import type { SignTemplates } from './types';

export const capricornTemplates: SignTemplates = {
  overall: {
    high: [
      { ko: '당신이 오랜 시간 묵묵히 준비해 온 일이 드디어 그 빛을 발하는 시기입니다. 토성의 에너지가 인내와 노력을 보상하는 방식으로, 지금 이 순간이 바로 당신을 위한 것임을 직감적으로 알 수 있을 것입니다. 자신을 온전히 믿고 앞으로 나아가세요—준비된 자에게는 반드시 기회가 찾아옵니다.', en: 'What you\'ve long and quietly prepared for is finally bearing fruit in ways you can feel clearly. Saturn\'s steady hand has been guiding your discipline, and now the world is ready to see your results. Believe in yourself completely—your preparation has made you more ready than you realize.', zh: '你长久以来默默准备的事情终于结出了果实，一切努力都没有白费。土星的力量正在为你的坚持给予回报，时机已经成熟。相信自己，迈出自信的步伐。', ja: '長い間準備してきたことがついに実を結ぶ時期が来ました。土星のエネルギーがあなたの努力に確かな報酬をもたらしています。自分を信じて、堂々と前に進んでください。', es: 'Lo que has preparado pacientemente por mucho tiempo finalmente da frutos visibles y tangibles. La energia de Saturno recompensa tu disciplina y constancia de manera concreta. Cree en ti plenamente y avanza con paso firme.' },
      { ko: '토성의 축복이 마침내 당신의 지난 노력에 보답하는 날이 왔습니다. 포기하고 싶었던 순간들을 견뎌낸 당신이기에, 지금 눈앞에 보이는 정상은 그 어느 때보다 가깝고도 실제적입니다. 멈추지 말고 마지막 한 발을 내딛으세요—정상의 풍경은 생각보다 훨씬 아름답습니다.', en: 'Saturn\'s blessing is now actively rewarding every bit of effort you\'ve poured into your goals. The summit you\'ve been climbing toward is no longer a distant dream but a visible reality just ahead. Don\'t stop now—the final steps to the top are the most rewarding of all.', zh: '土星的祝福终于回报了你所有的努力，顶峰近在眼前。你坚持走过的每一步都有了意义，胜利的曙光已经出现。不要停下脚步，继续向前冲。', ja: '土星の祝福がついにあなたの努力に報い、頂上が目の前に見えています。これまでの苦労が報われる瞬間が近づいています。最後の一歩を踏み出してください。', es: 'La bendicion de Saturno recompensa ahora cada esfuerzo que has puesto en tus metas durante tanto tiempo. La cima ya no es un sueno lejano, sino una realidad visible frente a ti. No te detengas—los ultimos pasos hasta la cima son los mas gratificantes.' },
      { ko: '말없이 꾸준히 쌓아온 신뢰가 오늘 비로소 눈부시게 빛을 발합니다. 당신이 얼마나 믿음직한 사람인지 주변이 이미 알고 있었고, 오늘 그 인정이 여러 방향에서 쏟아질 것입니다. 당당하게 받아들이세요—이 모든 것이 당신이 만들어낸 결과입니다.', en: 'The trust you\'ve quietly and steadily built over time shines brilliantly today for all to see. Your reliability has already been noticed by those around you, and now recognition pours in from multiple directions at once. Accept it with pride—every bit of it is the result of your own consistent effort.', zh: '你默默积累的信任今天终于闪闪发光，周围的认可接踵而至。你的可靠与踏实早已深入人心，今日终于得到了应有的回报。坦然接受这份肯定，这是你应得的。', ja: '黙々と積み上げてきた信頼が今日まばゆく光を放ちます。周囲はあなたがいかに信頼できる人物かをすでに知っており、今日その認められが様々な方向から寄せられます。誇りを持って受け取ってください。', es: 'La confianza que has construido callada y constantemente brilla hoy de manera deslumbrante. Tu fiabilidad ya ha sido notada por quienes te rodean, y ahora el reconocimiento llega desde multiples direcciones. Acéptalo con orgullo—todo es fruto de tu esfuerzo constante.' },
      { ko: '신중하게 세워놓은 당신의 계획들이 하나씩 현실로 전환되는 놀라운 과정이 진행 중입니다. 이 흐름은 우연이 아니라 당신이 반복적으로 쌓아온 규율과 준비의 결과입니다. 지금의 속도와 방향을 그대로 유지하세요—모멘텀은 멈추지 않는 자의 것입니다.', en: 'The plans you carefully crafted are converting into reality one by one in a way that feels almost effortless. This momentum is not luck—it is the direct result of the discipline and preparation you\'ve invested over time. Keep your current pace and direction; momentum belongs to those who never stop.', zh: '你精心制定的计划正在一一变为现实，这一切都是你努力的见证。这股势头来自你长期坚持的规律与准备，并非偶然。保持这个节奏和方向，动力属于永不停歇的人。', ja: 'あなたが丁寧に立てた計画が一つずつ現実になっています。このモメンタムはあなたが積み重ねてきた規律と準備の直接の結果です。今のペースと方向性を維持してください。', es: 'Los planes que cuidadosamente elaboraste se convierten en realidad uno a uno de manera casi fluida. Este impulso no es suerte—es el resultado directo de tu disciplina y preparacion acumulada. Mantén tu ritmo y direccion actuales; el momento pertenece a quienes nunca se detienen.' },
      { ko: '어떠한 상황에서도 흔들리지 않는 당신의 의지가 주변 사람들에게 깊은 감화를 줍니다. 이 강인함이야말로 리더십의 본질이며, 오늘은 그 자질이 누가 봐도 분명하게 드러나는 날입니다. 두려움 없이 앞장서세요—따르는 사람들이 반드시 생깁니다.', en: 'Your unwavering will in the face of any challenge deeply inspires those around you today. This inner strength is the very essence of true leadership, and today it shines in a way that is unmistakable to everyone. Step forward without fear—people will naturally follow your lead.', zh: '你在任何情况下都坚定不移的意志深深感化了周围的人。这种坚强正是领导力的本质，今天这一品质将清晰地展现在众人眼前。无所畏惧地带头前行，必有追随者。', ja: 'どんな状況でも揺るぎない意志が周囲を深く感化させます。この強さこそが真のリーダーシップの本質であり、今日はその資質が誰の目にも明らかに輝いています。恐れずに先頭に立ってください。', es: 'Tu voluntad inquebrantable ante cualquier desafio inspira profundamente a quienes te rodean. Esta fortaleza interior es la esencia del liderazgo verdadero, y hoy brilla de manera inconfundible para todos. Avanza sin miedo—las personas naturalmente seguiran tu ejemplo.' },
      { ko: '오랫동안 다져온 견고한 기반이 지금 당신에게 새로운 도약의 발판이 되고 있습니다. 이 탄탄한 토대가 있기에 어떠한 도전도 두려울 이유가 없으며, 지금이 바로 그 준비가 빛을 발할 순간입니다. 눈앞의 기회를 자신 있게 잡으세요—기반이 있는 자의 도약은 더 높이 뻗어나갑니다.', en: 'The solid foundation you\'ve built over years now becomes the perfect launchpad for a bold new leap. Because of this strong base, no challenge is too daunting and no opportunity too distant. Seize the moment with confidence—those who leap from solid ground always fly higher.', zh: '你长期夯实的坚实基础，如今成为了新飞跃的跳板。有了这个稳固的根基，任何挑战都无需畏惧，机会就在眼前。自信地抓住它——有根基的飞跃，能飞得更高更远。', ja: '長年築いてきた堅固な基盤が今まさに新たな飛躍の足がかりとなっています。この強固な土台があるから、どんな挑戦も怖くありません。自信を持って目の前のチャンスを掴んでください。', es: 'La base solida que has construido durante anos se convierte ahora en el trampolines perfecto para un nuevo salto audaz. Con este fundamento, ningun desafio es demasiado intimidante. Aprovecha el momento con confianza—quienes saltan desde tierra firme siempre vuelan mas alto.' },
      { ko: '길고도 길었던 인내의 계절이 마침내 끝나고, 이제 풍성한 보상의 계절이 당신을 향해 활짝 열리고 있습니다. 그 시간 동안 포기하지 않았던 당신의 선택이 옳았음을 오늘이 증명합니다. 두 팔 벌려 이 보상을 온전히 받아들이세요—이것은 당신이 마땅히 누릴 자격이 있는 것입니다.', en: 'The long, often grueling season of patience has finally ended, and now the abundant season of reward opens wide before you. Today validates every moment you chose not to give up during that difficult stretch. Open your arms wide and fully receive this reward—it is yours by right of everything you endured.', zh: '漫长而艰辛的忍耐季节终于结束，丰盛的回报季节正向你敞开大门。你坚持不放弃的选择在今天得到了验证。张开双臂，全然接受这份回报——这是你理所应当拥有的。', ja: '長く苦しかった忍耐の季節がついに終わり、豊かな報酬の季節が訪れました。あの時代に諦めなかったあなたの選択が正しかったと今日が証明しています。この報酬を両手で受け取ってください。', es: 'La larga y a menudo agotadora temporada de paciencia ha terminado finalmente, y ahora la abundante temporada de recompensa se abre ampliamente ante ti. Hoy valida cada momento en que elegiste no rendirte. Abre los brazos y recibe esta recompensa plenamente—te la has ganado.' },
      { ko: '남들이 타협을 선택할 때도 흔들리지 않고 지켜온 당신의 원칙이 오늘 옳았음이 명확히 증명됩니다. 도덕적 기준과 일관성이 결국 가장 강력한 자산임을 이 하루가 보여줍니다. 앞으로도 이 원칙을 더욱 굳건히 지켜나가세요—그 길이 당신을 더 높은 곳으로 이끌 것입니다.', en: 'The principles you steadfastly maintained, even when others chose compromise, are proven right today. This day shows that moral consistency and integrity are ultimately the most powerful assets anyone can hold. Strengthen your commitment to these principles going forward—they are the road to even greater heights.', zh: '当别人选择妥协时，你始终坚守的原则今天得到了清晰的验证。这一天证明了道德一致性和操守最终是最强大的资产。继续坚守这些原则，它们将引领你走向更高的地方。', ja: 'あなたが妥協せずに守り続けてきた原則が今日正しかったと証明されます。一貫性と誠実さこそが最も強力な資産だと今日が示しています。これからもその原則を大切に守ってください。', es: 'Los principios que mantuviste firmemente, incluso cuando otros eligieron ceder, se demuestran correctos hoy. Este dia muestra que la coherencia moral y la integridad son en ultima instancia los activos mas poderosos. Fortalece tu compromiso con estos principios—son el camino hacia mayores alturas.' },
      { ko: '목표를 향한 당신의 집중력이 오늘 최고조에 이르러, 어떤 상황도 당신의 시선을 흐트러뜨리지 못합니다. 이 탁월한 명료함 덕분에 중요한 결정을 내릴 때 최고의 판단을 발휘할 수 있습니다. 미루어 두었던 큰 결정이 있다면 오늘이 바로 그날입니다.', en: 'Your focus toward your goals peaks today, reaching a level of clarity where nothing can distract or derail you. This exceptional mental sharpness means your judgment for important decisions is at its very best right now. If there is a major decision you\'ve been postponing, today is the day to make it.', zh: '你对目标的专注力今天达到顶峰，清晰度无与伦比，没有任何事物能分散你的注意力。这种卓越的精神锐利意味着你对重要决策的判断力此刻处于最佳状态。若有一直推迟的重大决定，今天就是做决定的日子。', ja: '目標に向けた集中力が今日最高潮に達し、何もあなたの視線を乱せません。この卓越した明晰さのおかげで重要な決定を下す際に最高の判断を発揮できます。先延ばしにしていた大きな決断があれば今日が決断の日です。', es: 'Tu enfoque hacia tus metas alcanza hoy su punto maximo, con una claridad tal que nada puede distraerte. Esta nitidez mental excepcional significa que tu juicio para decisiones importantes esta en su mejor momento ahora mismo. Si hay una gran decision que has pospuesto, hoy es el dia de tomarla.' },
      { ko: '탁월한 실력과 한결같은 성실함이 오늘 당신 앞에 놓인 모든 장애물을 가볍게 넘어서게 합니다. 다른 사람들이 막힌다고 느끼는 곳에서 당신은 이미 해법을 품고 있습니다. 주저 없이 당당하게 전진하세요—실력 있는 자의 발걸음은 두려움을 모릅니다.', en: 'Your outstanding skill and unwavering diligence today allow you to overcome every obstacle placed in your path with remarkable ease. Where others feel blocked, you already carry the solution within you. Advance with complete confidence and no hesitation—those with true ability walk without fear.', zh: '你卓越的实力和持一如既往的勤勉，今天让你轻松跨越面前所有的障碍。在别人感到受阻的地方，你已经胸有成竹。毫不犹豫地自信前行——有真本事的人脚步无畏。', ja: '卓越した実力と揺るぎない誠実さが今日あなたの前の障害をすべて乗り越えさせます。他の人が行き詰まるところにあなたはすでに解決策を持っています。堂々と迷いなく前進してください。', es: 'Tu habilidad sobresaliente y tu diligencia inquebrantable te permiten hoy superar cada obstaculo con una facilidad notable. Donde otros se sienten bloqueados, tu ya llevas la solucion dentro. Avanza con plena confianza y sin dudas—quienes tienen verdadera habilidad caminan sin temor.' },
    ],
    medium: [
      { ko: '염소자리 특유의 차분함으로 오늘 일상을 관리한다면, 예상치 못한 돌발 상황도 무리 없이 넘길 수 있는 안정적인 하루가 될 것입니다. 큰 성과보다는 소소한 완수에서 오는 만족감이 내면의 균형을 유지하게 합니다. 오늘 하루를 꾸준함의 힘으로 채워가세요.', en: 'Managing your day with the calm, grounded energy typical of Capricorn will naturally create stability even when unexpected situations arise. The satisfaction that comes from small completions rather than grand achievements keeps you balanced today. Fill this day with the quiet power of consistency.', zh: '以摩羯座特有的沉着冷静管理今天的日常，即使出现突发情况也能从容应对，迎来平稳的一天。比起大成就，小事完成带来的满足感更能维持内心的平衡。用坚持的力量度过今天吧。', ja: '摩羯座特有の落ち着きで今日の日常を管理すれば、突発的な出来事も無理なく乗り越えられる安定した一日になります。大きな成果より小さな完遂から来る満足感が心の均衡を保ちます。', es: 'Gestionar tu dia con la calma y serenidad caracteristica de Capricornio creara estabilidad natural incluso cuando surjan imprevistos. La satisfaccion de pequenos logros, mas que grandes exitos, te mantiene equilibrado hoy. Llena este dia con el poder silencioso de la constancia.' },
      { ko: '오늘 상황이 생각보다 빠르게 전개되더라도, 급할수록 돌아가는 것이 가장 현명한 전략임을 기억하세요. 토성이 가르치는 가장 위대한 교훈은 "시간을 이기는 것은 시간밖에 없다"는 것입니다. 조급함을 내려놓고 한 걸음씩 정확하게 나아가는 염소자리의 지혜를 발휘하세요.', en: 'Even if today\'s situation moves faster than expected, remember that the wiser path is often the slower, more deliberate one. Saturn\'s greatest lesson is that only time can truly conquer time. Set aside urgency and exercise the Capricorn wisdom of moving one precise step at a time.', zh: '即使今天情况进展比预期快，也要记住，越急越需要走弯路才是最智慧的策略。土星最伟大的教导是，能战胜时间的只有时间本身。放下急躁，发挥摩羯座一步一个脚印的智慧。', ja: '今日の状況が予想より早く展開しても、急がば回れが最も賢明な戦略だと覚えておいてください。土星の最も偉大な教えは「時間を制するのは時間だけ」です。焦りを手放し、一歩一歩正確に進む摩羯座の知恵を発揮してください。', es: 'Aunque la situacion de hoy avance mas rapido de lo esperado, recuerda que el camino mas lento y deliberado suele ser el mas sabio. La mayor leccion de Saturno es que solo el tiempo puede conquistar verdaderamente el tiempo. Deja de lado la urgencia y avanza un paso preciso a la vez.' },
      { ko: '늘 더 높은 기준을 향해 달려가는 당신이지만, 오늘만큼은 작은 성취에도 진심으로 스스로를 칭찬하는 여유를 가져보세요. 자기 자신을 엄격하게 대하는 것만이 성장의 유일한 방법이 아니라는 것을 토성도 알고 있습니다. 오늘의 작은 승리를 충분히 음미하세요—그것이 내일의 큰 도약을 위한 연료가 됩니다.', en: 'You are always racing toward higher standards, but today allow yourself the space to genuinely praise even your smallest achievements. Saturn knows that relentless self-criticism is not the only path to growth—self-recognition is fuel too. Savor today\'s small victories fully; they are the energy source for tomorrow\'s bigger leaps.', zh: '你总是朝着更高的标准奔跑，但今天，请给自己留出空间，真诚地为小小的成就鼓掌。土星也知道，严格自我批评并非成长的唯一途径。充分品味今天的小胜利吧，它们是明天更大飞跃的燃料。', ja: 'いつも高い基準に向かって走り続けているあなたですが、今日だけは小さな成果にも心から自分を褒める余裕を持ってください。厳しい自己批判だけが成長の唯一の方法ではないと土星も知っています。今日の小さな勝利を十分に味わってください。', es: 'Siempre vas hacia estandares mas altos, pero hoy date el espacio para elogiarte genuinamente incluso por los logros mas pequenos. Saturno sabe que la autocritica constante no es el unico camino al crecimiento. Saborea plenamente las pequenas victorias de hoy—son el combustible para mayores saltos manana.' },
      { ko: '오늘은 앞으로의 큰 행동을 위해 계획을 꼼꼼하게 점검하고 빈틈을 보완할 최적의 시점입니다. 염소자리의 강점은 세부 사항에서 숨겨진 위험이나 기회를 먼저 발견하는 능력에 있습니다. 속도를 늦추고 빠뜨린 세부 사항을 살펴보세요—그 안에 다음 성공의 열쇠가 있습니다.', en: 'Today is the ideal time to carefully review your plans and fill in any gaps before the next major push forward. Capricorn\'s great strength lies in the ability to spot hidden risks or opportunities in the details before anyone else does. Slow down and examine what you\'ve overlooked—the key to your next success may be hiding there.', zh: '今天是在下一次大行动之前仔细检查计划、弥补不足的最佳时机。摩羯座的强项在于能比任何人都早发现细节中隐藏的风险或机会。放慢速度，审视你忽略的地方——下一次成功的钥匙可能就藏在那里。', ja: '今日は次の大きな行動のために計画を丁寧に点検し、漏れを補完する最適な時点です。摩羯座の強みは誰よりも先に細部の中に隠れたリスクやチャンスを見つける能力にあります。速度を落として見落とした細部を確認してください。', es: 'Hoy es el momento ideal para revisar cuidadosamente tus planes y llenar vacios antes del proximo gran avance. La gran fortaleza de Capricornio radica en detectar riesgos u oportunidades ocultos en los detalles antes que nadie. Reduce la velocidad y examina lo que has pasado por alto—la clave de tu proximo exito puede estar ahi.' },
      { ko: '화려하진 않더라도 평소의 루틴을 성실히 따르는 것이 오늘은 예상치 못한 좋은 결과로 이어질 수 있습니다. 루틴이야말로 염소자리가 세상과 신뢰를 쌓는 가장 조용하고 강력한 방법입니다. 지루하더라도 포기하지 말고 오늘도 그 루틴을 이어가세요.', en: 'Faithfully following your usual routine today, even if it feels unglamorous, can lead to unexpectedly good results that others simply don\'t see coming. Routine is the quiet yet powerful way Capricorn builds trust with the world. Keep going even if it feels tedious—persistence is your superpower.', zh: '今天忠实地遵循日常惯例，即使看起来平淡无奇，也可能带来意想不到的好结果。日常惯例正是摩羯座与世界建立信任的安静而强大的方式。即使感到枯燥，也继续坚持——持之以恒是你的超能力。', ja: '華やかではなくてもいつものルーティンを誠実に守れば今日は予想外の良い結果につながる可能性があります。ルーティンこそ摩羯座が世界と信頼を築く最も静かで強力な方法です。退屈でも続けてください。', es: 'Seguir fielmente tu rutina habitual hoy, aunque no parezca glamoroso, puede llevar a resultados inesperadamente buenos que otros simplemente no ven venir. La rutina es la forma silenciosa pero poderosa en que Capricornio construye confianza. Sigue aunque se sienta tedioso—la perseverancia es tu superpoder.' },
      { ko: '혼자 모든 것을 해내야 한다는 염소자리의 독립심이 오늘은 오히려 걸림돌이 될 수 있습니다. 주변 사람들과 적극적으로 협력하면 효율이 눈에 띄게 높아지는 날이기 때문입니다. 도움을 요청하는 것이 약함이 아닌 지혜임을 기억하고 팀의 힘을 활용하세요.', en: 'Capricorn\'s fierce independence—the drive to handle everything alone—can actually become a hindrance today. Actively cooperating with those around you will noticeably boost your efficiency in ways that solo effort simply cannot match. Remember that asking for help is wisdom, not weakness, and use the power of your team.', zh: '摩羯座独自处理一切的独立心在今天可能反而成为阻碍。与周围的人积极合作，效率会明显提升，这是单打独斗无法做到的。记住，寻求帮助是智慧而非软弱，好好利用团队的力量吧。', ja: '何でも一人でこなさなければならないという摩羯座の独立心が今日はむしろ足かせになる可能性があります。周りの人と積極的に協力すると効率が目に見えて高まる日だからです。助けを求めることが知恵であると覚えてチームの力を活用してください。', es: 'La feroz independencia de Capricornio—el impulso de manejar todo solo—puede convertirse en un obstaculo hoy. Cooperar activamente con quienes te rodean aumentara notablemente tu eficiencia de maneras que el esfuerzo solitario simplemente no puede igualar. Recuerda que pedir ayuda es sabiduria, no debilidad.' },
      { ko: '지금 있는 자리가 이상적이지 않더라도, 현재 위치에서 할 수 있는 최선에 온전히 집중하면 그것으로 충분합니다. 더 좋은 환경이나 조건을 기다리는 것보다 현재의 제약 안에서 최대치를 끌어내는 것이 진정한 염소자리의 방식입니다. 지금 여기서, 있는 힘껏 해보세요.', en: 'Even if your current position is not ideal, fully focusing on doing your best from exactly where you are is genuinely enough for today. Waiting for better conditions is less powerful than drawing the maximum out of current constraints—that is the true Capricorn way. Do your best right here, right now.', zh: '即使你目前的处境并不理想，全心专注于在现有位置做到最好，今天就已经足够了。等待更好的条件，不如在现有限制中挖掘最大潜力——这才是真正的摩羯座方式。就在此时此地，全力以赴吧。', ja: '今の立場が理想的でなくても、現在の位置でできる最善に完全に集中すれば今日はそれで十分です。より良い環境を待つより現在の制約の中で最大限を引き出すことが真の摩羯座のやり方です。今ここで精一杯やってみてください。', es: 'Aunque tu posicion actual no sea ideal, enfocarte plenamente en hacer lo mejor desde donde estas es genuinamente suficiente para hoy. Esperar mejores condiciones es menos poderoso que extraer el maximo de las restricciones actuales—ese es el verdadero camino de Capricornio.' },
      { ko: '오늘은 당신의 통제 욕구와 조급함을 의식적으로 내려놓아야 할 때입니다. 모든 것이 완벽한 타이밍에 맞춰 자연스럽게 풀릴 것이라는 믿음을 가져보세요. 염소자리가 종종 잊는 사실—"강을 거슬러 수영하지 않아도 강은 흐른다"—을 오늘 기억하세요.', en: 'Today is the day to consciously set aside your drive for control and your impatience. Trust that things will resolve naturally at exactly the right moment without forcing them. Remember what Capricorn sometimes forgets—the river flows whether you swim against it or not.', zh: '今天是有意识地放下控制欲和急躁的时候了。相信一切会在恰当的时机自然而然地解决，无需强求。记住摩羯座有时会忘记的那个道理——不管你是否逆流而游，河流依然向前流淌。', ja: '今日はコントロールしたいという欲求と焦りを意識的に手放すべき日です。すべてが完璧なタイミングで自然と解決するという信念を持ってみてください。摩羯座がしばしば忘れる事実を今日は思い出してください。', es: 'Hoy es el dia para dejar conscientemente a un lado tu impulso de control y tu impaciencia. Confia en que las cosas se resolveran naturalmente en el momento exacto sin forzarlas. Recuerda lo que Capricornio a veces olvida—el rio fluye tanto si nadas contra el como si no.' },
      { ko: '목표까지 아직 갈 길이 남아 있지만, 지금 당신이 걷고 있는 방향은 분명히 올바릅니다. 염소자리의 여정은 본래 짧지 않으며, 그 긴 여정을 묵묵히 걸어갈 수 있는 것이 바로 당신의 진정한 강점입니다. 지금의 속도와 방향 그대로 꾸준히 나아가세요.', en: 'There is still a journey ahead before you reach your goal, but the direction you are walking right now is clearly correct. The Capricorn path is never short by nature, and being able to walk that long road without wavering is precisely your greatest strength. Keep your current speed and direction—steady progress is victory.', zh: '距离目标还有一段路要走，但你现在所走的方向是清晰正确的。摩羯座的旅程本就不短，而能够默默走完这段长路，正是你真正的强项。保持现在的速度和方向，稳步前进——坚持即是胜利。', ja: '目標まではまだ道のりがありますが、今あなたが歩いている方向は明らかに正しいです。摩羯座の旅は本来短くなく、その長い旅をぶれずに歩めることがあなたの真の強みです。今の速度と方向そのままで着実に進んでください。', es: 'Todavia queda camino antes de alcanzar tu meta, pero la direccion que estas recorriendo ahora mismo es claramente correcta. El camino de Capricornio nunca es corto por naturaleza, y poder recorrer ese largo camino sin vacilar es precisamente tu mayor fortaleza. Mantén tu velocidad y direccion actuales.' },
      { ko: '지금은 새로운 변화를 추구하기보다 이미 잘 돌아가고 있는 것들을 견고히 유지하는 데 에너지를 쏟는 것이 훨씬 유리한 시기입니다. 잘 구축된 시스템을 지키는 것도 성과이며, 지금의 안정이 다음 도약의 든든한 토대가 됩니다. 오늘은 지켜내는 것이 목표입니다.', en: 'Right now it is far more advantageous to pour energy into maintaining what is already working well rather than seeking new changes. Protecting a well-built system is itself an achievement, and today\'s stability becomes the foundation for your next leap. Today, holding steady is the goal.', zh: '现在，与其追求新的变化，不如把精力集中在维护已经运转良好的事物上，这样更加有利。守护一个良好运转的系统本身就是一种成就，当下的稳定将成为下一次飞跃的坚实基础。今天，守住就是目标。', ja: '今は新しい変化を求めるよりすでにうまく機能しているものを堅固に維持することにエネルギーを注ぐのがずっと有利な時期です。うまく構築されたシステムを守ることも成果であり、今の安定が次の飛躍の土台になります。', es: 'Ahora es mucho mas ventajoso poner energia en mantener lo que ya funciona bien en lugar de buscar nuevos cambios. Proteger un sistema bien construido es en si mismo un logro, y la estabilidad de hoy se convierte en la base de tu proximo salto. Hoy, mantenerse firme es el objetivo.' },
    ],
    low: [
      { ko: '모든 것을 혼자 책임져야 한다는 의무감은 염소자리의 미덕이기도 하지만, 오늘은 그것이 당신을 심각하게 지치게 할 수 있습니다. 짐을 나누는 것은 약함이 아니라 지속 가능한 성장을 위한 현명한 선택입니다. 신뢰할 수 있는 사람에게 일부를 맡기세요—혼자 쓰러지는 것이 진짜 실패입니다.', en: 'The sense of duty to shoulder everything alone is one of Capricorn\'s virtues, but today it may seriously exhaust you. Sharing the burden is not weakness—it is the wise choice for sustainable growth that protects your long-term capacity. Delegate to someone you trust; collapsing alone is the real failure.', zh: '独自承担一切的责任感是摩羯座的美德，但今天这种感觉可能让你严重疲惫。分担重担不是软弱，而是为可持续成长做出的明智选择。把一部分交给信任的人吧——一个人倒下才是真正的失败。', ja: 'すべてを一人で責任を持たなければならないという義務感は摩羯座の美徳でもありますが、今日はそれがあなたを深刻に疲れさせる可能性があります。荷物を分かち合うことは弱さではなく持続可能な成長のための賢明な選択です。信頼できる人に任せてください。', es: 'El deber de cargar con todo solo es una virtud de Capricornio, pero hoy puede agotarte seriamente. Compartir la carga no es debilidad—es la eleccion sabia para un crecimiento sostenible que protege tu capacidad a largo plazo. Delega en alguien de confianza; desplomarse solo es el verdadero fracaso.' },
      { ko: '오늘은 완벽을 고집하는 습관이 오히려 당신에게 손실로 돌아올 수 있는 날입니다. 기회는 종종 "완벽하지 않은 모습으로 딱 한 번만" 찾아오기 때문입니다. 80%의 완성도로 과감하게 움직이는 유연함이 오늘은 100%보다 훨씬 강력한 선택이 됩니다.', en: 'Today your habit of insisting on perfection could actually turn into a loss for you. Opportunities often come just once, and never in their perfect form. Moving boldly with 80% readiness and flexible thinking is a far more powerful choice today than waiting for 100%.', zh: '今天，坚持完美的习惯可能反而给你带来损失。机会往往只有一次，而且从不以完美的形式出现。以80%的准备灵活行动，今天比等待100%完美强大得多。', ja: '今日は完璧にこだわる習慣がむしろあなたへの損失として返ってくる可能性がある日です。機会はしばしば「完璧ではない姿で一度だけ」訪れるからです。80%の完成度で大胆に動く柔軟さが今日は100%より強力な選択です。', es: 'Hoy tu habito de insistir en la perfeccion podria convertirse en una perdida para ti. Las oportunidades a menudo llegan solo una vez, y nunca en su forma perfecta. Moverte con audacia con un 80% de preparacion y pensamiento flexible es hoy una eleccion mucho mas poderosa que esperar el 100%.' },
      { ko: '최고의 기준을 향해 달려가는 것이 당신의 본능이지만, 오늘은 그 엄격함이 스스로를 상처 입힐 수 있습니다. 쉬는 것은 나태함이 아니라, 더 오래 더 멀리 가기 위한 전략적 선택입니다. 지금 멈추는 용기가 내일의 더 큰 전진을 만들어냅니다.', en: 'Running toward the highest standards is your instinct, but today that strictness may wound rather than motivate you. Resting is not laziness—it is a strategic choice to go further and longer. The courage to pause now creates the energy for greater progress tomorrow.', zh: '追求最高标准是你的本能，但今天这种严苛可能反而会伤害你自己。休息不是懈怠，而是为了走得更久更远的战略选择。现在停下的勇气，将创造明天更大的前进动力。', ja: '最高の基準に向かって走ることがあなたの本能ですが、今日はその厳しさが自分を傷つける可能性があります。休むことは怠慢ではなく、より長くより遠くまで行くための戦略的選択です。今止まる勇気が明日のより大きな前進を生み出します。', es: 'Correr hacia los mas altos estandares es tu instinto, pero hoy esa estrictez puede herirte en lugar de motivarte. Descansar no es pereza—es una eleccion estrategica para ir mas lejos y durante mas tiempo. El valor de pausar ahora crea la energia para un mayor progreso manana.' },
      { ko: '모든 것을 혼자 통제하려는 욕구는 염소자리가 가장 자주 짊어지는 무게입니다. 오늘은 그 마음을 의식적으로 내려놓고, 주변 사람들에게 솔직하게 도움을 요청해 보세요. 도움을 받는다는 것은 통제력을 잃는 것이 아니라, 더 넓은 가능성으로 향하는 문을 여는 것입니다.', en: 'The urge to control everything alone is the weight Capricorn most often carries. Today, consciously set that feeling aside and reach out honestly to people around you for help. Receiving help does not mean losing control—it means opening a door to wider possibilities than you can access alone.', zh: '独自掌控一切的欲望是摩羯座最常背负的重量。今天，有意识地放下这种想法，坦诚地向周围的人寻求帮助。接受帮助不是失去控制，而是打开通向更广可能性的大门。', ja: 'すべてを一人でコントロールしようとする欲求は摩羯座が最もよく背負う重みです。今日はその気持ちを意識的に手放し、周りの人に素直に助けを求めてみてください。助けを受けることはコントロールを失うことではなく、より広い可能性への扉を開くことです。', es: 'El impulso de controlar todo solo es el peso que Capricornio carga con mayor frecuencia. Hoy, deja ese sentimiento conscientemente a un lado y acude honestamente a las personas a tu alrededor para pedir ayuda. Recibir ayuda no significa perder el control—significa abrir una puerta a posibilidades mas amplias.' },
      { ko: '현실적인 사고가 강점인 염소자리이지만, 오늘은 그 현실주의가 비관주의로 기울어질 위험이 있습니다. 암울한 생각은 당신의 실제 능력보다 상황을 더 나쁘게 보이게 하고 최선의 판단을 가로막습니다. 의식적으로 한 가지 긍정적 측면에 시선을 고정하면, 출구가 보이기 시작할 것입니다.', en: 'Realistic thinking is Capricorn\'s great strength, but today that realism risks tipping into pessimism. Dark thoughts make situations appear worse than they actually are and block your best judgment from emerging. Deliberately fix your gaze on one positive angle—and the exit will begin to reveal itself.', zh: '现实思维是摩羯座的强项，但今天这种现实主义有倒向悲观主义的危险。阴暗的想法让情况看起来比实际更糟，并阻碍你做出最佳判断。有意识地把目光锁定在一个积极的方面——出口就会开始显现。', ja: '現実的な思考が強みの摩羯座ですが、今日はその現実主義が悲観主義に傾くリスクがあります。暗い考えは実際の能力より状況を悪く見せ、最善の判断を妨げます。意識的に一つのポジティブな側面に視線を固定すれば出口が見え始めるでしょう。', es: 'El pensamiento realista es la gran fortaleza de Capricornio, pero hoy ese realismo corre el riesgo de inclinarse hacia el pesimismo. Los pensamientos oscuros hacen que las situaciones parezcan peores de lo que son y bloquean tu mejor juicio. Fija deliberadamente tu mirada en un angulo positivo—y la salida comenzara a revelarse.' },
      { ko: '오늘 당신의 고집이 불필요한 갈등을 낳고 중요한 관계에 금을 낼 수 있습니다. 당신의 방식이 틀린 것이 아닐 수 있지만, 타인의 관점도 동등하게 타당할 수 있다는 열린 마음이 지금 필요합니다. 한 발 물러서서 경청하면, 오히려 더 좋은 해법이 보일 것입니다.', en: 'Today your stubbornness may generate unnecessary conflict and crack important relationships. Your approach may not be wrong, but right now you need an open mind that recognizes others\' perspectives as equally valid. Step back and listen—an even better solution may become visible from there.', zh: '今天你的固执可能引发不必要的冲突，并在重要关系中留下裂痕。你的方式也许没错，但此刻你需要一颗开放的心，认识到他人的观点同样有道理。退一步，认真倾听——更好的解决方案可能就此显现。', ja: '今日あなたの頑固さが不必要な葛藤を生み、重要な関係にひびを入れる可能性があります。あなたのやり方が間違っていないかもしれませんが、他人の観点も同様に妥当だという開かれた心が今必要です。一歩引いて耳を傾ければより良い解決策が見えてくるでしょう。', es: 'Hoy tu terquedad puede generar conflictos innecesarios y agrietar relaciones importantes. Tu enfoque puede no estar equivocado, pero ahora necesitas una mente abierta que reconozca las perspectivas de otros como igualmente validas. Da un paso atras y escucha—una solucion incluso mejor puede volverse visible desde ahi.' },
      { ko: '오늘은 평소보다 체력 소모가 훨씬 큰 하루가 될 것입니다. 이럴 때일수록 무리하게 밀어붙이기보다 에너지를 전략적으로 보존하는 것이 현명한 염소자리의 선택입니다. 지금 멈추는 것은 약함이 아니라, 내일을 위한 최선의 투자입니다.', en: 'Today will demand significantly more physical and mental energy than usual. In moments like this, the wise Capricorn choice is to strategically conserve energy rather than push through recklessly. Stopping now is not weakness—it is the best investment you can make for tomorrow.', zh: '今天的体力消耗将远超平时。正是在这样的时刻，明智的摩羯座选择战略性地保存能量，而不是莽撞地硬撑。现在停下来不是软弱，而是为明天做的最好投资。', ja: '今日は平均以上の体力消耗が大きい日になるでしょう。このような時こそ無理に押し進めるより戦略的にエネルギーを温存することが賢明な摩羯座の選択です。今止まることは弱さではなく明日への最善の投資です。', es: 'Hoy demandara significativamente mas energia fisica y mental de lo habitual. En momentos como este, la sabiduria de Capricornio es conservar estrategicamente la energia en lugar de empujar de manera imprudente. Detenerse ahora no es debilidad—es la mejor inversion que puedes hacer para manana.' },
      { ko: '오늘 일이 예상과 다르게 흘러가더라도 좌절하지 마세요. 토성의 시간표는 당신이 원하는 것보다 느릴 수 있지만, 결코 틀리지 않습니다. 이 인내의 시간이 당신을 단단하게 만들고 있으며, 당신의 때는 반드시 오게 되어 있습니다.', en: 'Even if things unfold differently than planned today, don\'t allow disappointment to take hold. Saturn\'s timeline may be slower than you wish, but it is never wrong. This season of patience is forging your strength, and your time is absolutely coming—it cannot be stopped.', zh: '即使今天事情不按计划发展，也不要灰心丧气。土星的时间表可能比你希望的更慢，但它永远不会出错。这段忍耐的时光正在锤炼你的意志，你的时机必定会来，无法阻挡。', ja: '今日物事が予想と異なって進んでも失望しないでください。土星のタイムラインはあなたが望むより遅いかもしれませんが、決して間違っていません。この忍耐の時間があなたを強くしており、あなたの時は必ず来ます。', es: 'Aunque las cosas se desarrollen diferente a lo planeado hoy, no dejes que la decepcion te domine. El cronograma de Saturno puede ser mas lento de lo que deseas, pero nunca esta equivocado. Esta temporada de paciencia forja tu fortaleza, y tu momento esta absolutamente llegando—no puede detenerse.' },
      { ko: '감정을 내색하지 않는 것이 강인함이라 여기는 염소자리이지만, 오늘은 억눌린 감정이 오히려 더 큰 짐이 되어 당신을 힘들게 합니다. 신뢰하는 한 사람에게 솔직하게 마음을 열어보세요—그 단 한 번의 고백이 당신의 어깨를 몇 배나 가볍게 만들 것입니다.', en: 'Capricorn often considers not showing emotions a sign of strength, but today suppressed feelings have become a heavier burden than they need to be. Open your heart honestly to one trusted person—that single act of vulnerability will lighten your shoulders many times over.', zh: '摩羯座往往认为不表露情绪是一种坚强，但今天被压抑的感情反而成了更大的负担，让你更加痛苦。向一个信任的人诚实地敞开心扉吧——这一次真诚的袒露将让你肩上的重担减轻数倍。', ja: '感情を出さないことが強さだと考える摩羯座ですが、今日は抑圧された感情がむしろより大きな負担になってあなたを苦しめます。信頼できる一人の人に素直に心を開いてみてください。その一度の告白があなたの肩を何倍も軽くするでしょう。', es: 'Capricornio a menudo considera no mostrar emociones una senal de fortaleza, pero hoy los sentimientos suprimidos se han convertido en una carga mas pesada de lo necesario. Abre tu corazon honestamente a una persona de confianza—ese unico acto de vulnerabilidad aligerara tus hombros muchas veces.' },
      { ko: '결과만을 바라보며 달려오다 보면 과정의 가치를 잊기 쉬운데, 오늘은 바로 그 함정에 빠지지 않아야 할 날입니다. 성과에 대한 조급함을 의식적으로 내려놓고, 지금 이 과정에서 당신이 무엇을 배우고 있는지에 의미를 두어 보세요. 여정 자체가 목적지보다 당신을 더 크게 성장시킵니다.', en: 'Constantly chasing results makes it easy to lose sight of the value of the process, and today is the day to avoid falling into that trap. Consciously set aside impatience for outcomes and find meaning in what you are learning right now through this journey. The journey itself grows you more than any destination could.', zh: '只顾奔向结果很容易忘记过程的价值，今天正是不能陷入这个陷阱的日子。有意识地放下对成果的急切，在这段旅程中，找到你正在学习什么的意义。旅途本身比任何目的地都更能让你成长。', ja: '結果だけを見て走り続けると過程の価値を忘れやすく、今日はまさにその罠に落ちてはいけない日です。成果への焦りを意識的に手放し、今この過程で何を学んでいるかに意味を見出してみてください。旅そのものがどんな目的地よりあなたをより大きく成長させます。', es: 'Perseguir constantemente resultados hace facil perder de vista el valor del proceso, y hoy es el dia para evitar caer en esa trampa. Deja conscientemente a un lado la impaciencia por los resultados y encuentra significado en lo que estas aprendiendo ahora mismo en este viaje. El viaje en si te hace crecer mas que cualquier destino.' },
    ],
  },
  love: {
    high: [
      { ko: '오늘은 당신의 진지하고 솔직한 마음이 말 한마디 한마디를 통해 상대에게 깊이 전달되는 특별한 날입니다. 염소자리의 꾸밈없는 진심은 화려한 말보다 훨씬 강한 힘을 가지고 있으며, 오늘은 그것이 완벽하게 통하는 날입니다. 준비했던 고백이 있다면 지금이 바로 그 순간입니다.', en: 'Today is a special day when your serious, honest feelings reach the other person deeply through every word you speak. Capricorn\'s unadorned sincerity carries far more power than flowery speech, and today it resonates perfectly. If there is a confession you have been preparing, right now is the moment.', zh: '今天是你真诚而认真的心情，通过每一句话深深传达给对方的特别日子。摩羯座朴实无华的真心，比华丽的言辞拥有更强的力量，今天这一点恰好完美奏效。如果有一直想表白的话，现在就是那个时刻。', ja: '今日はあなたの真剣で素直な気持ちが言葉の一つ一つを通して相手に深く伝わる特別な日です。摩羯座の飾らない真心は華やかな言葉よりずっと強い力を持っており、今日はそれが完璧に通じる日です。準備していた告白があれば今がその瞬間です。', es: 'Hoy es un dia especial en que tus sentimientos serios y honestos llegan profundamente al otro a traves de cada palabra que pronuncias. La sinceridad sin adornos de Capricornio tiene mucho mas poder que los discursos floridos, y hoy resuena perfectamente. Si hay una confesion que has estado preparando, este es el momento.' },
      { ko: '함께 쌓아온 시간과 경험이 두 사람의 관계를 한 단계 더 깊고 단단한 차원으로 끌어올리는 시기입니다. 이 성숙한 사랑의 깊이는 처음의 설렘보다 훨씬 더 아름답습니다. 미래에 대한 구체적인 계획을 함께 세워보세요—공동의 목표가 관계를 더욱 견고하게 만듭니다.', en: 'The time and experiences you\'ve built together are now lifting your relationship to a deeper, more solid level. The depth of this mature love is far more beautiful than the initial excitement ever was. Make concrete plans for the future together—shared goals make the relationship even more unbreakable.', zh: '你们共同积累的时光和经历，正将这段关系提升到更深、更坚实的层次。这种成熟爱情的深度，远比最初的心动更加美丽。一起制定具体的未来计划吧——共同的目标让关系更加牢不可破。', ja: '共に積み上げてきた時間と経験が二人の関係をさらに深く固い次元に引き上げる時期です。この成熟した愛の深さは最初のときめきよりずっと美しいです。具体的な未来の計画を一緒に立ててみてください。', es: 'El tiempo y las experiencias que han construido juntos ahora elevan su relacion a un nivel mas profundo y solido. La profundidad de este amor maduro es mucho mas bella que la emocion inicial. Hagan planes concretos para el futuro juntos—las metas compartidas hacen la relacion aun mas inquebrantable.' },
      { ko: '말보다 행동으로 사랑을 표현하는 염소자리의 방식이 오늘 파트너에게 가장 깊은 감동을 줍니다. 당신이 묵묵히 해온 작은 헌신들이 상대의 마음속에 얼마나 크게 자리 잡고 있는지 오늘 확인할 수 있을 것입니다. 오늘도 그 사랑을 행동으로, 구체적으로 표현해 보세요.', en: 'Capricorn\'s way of expressing love through actions rather than words moves your partner most deeply today. You will be able to see today just how large a place your quiet, consistent devotions have taken in their heart. Express that love again today—concretely, through action.', zh: '摩羯座用行动而非语言表达爱意的方式，今天给伴侣带来了最深的感动。今天你将能看到，你默默付出的小小奉献在对方心中占据了多么重要的位置。今天也用行动、具体地表达你的爱吧。', ja: '言葉より行動で愛を表現する摩羯座のやり方が今日パートナーに最も深い感動を与えます。あなたが黙々とやってきた小さな献身が相手の心にどれほど大きく根付いているか今日確認できるでしょう。今日もその愛を行動で具体的に表現してみてください。', es: 'La forma de Capricornio de expresar amor a traves de acciones en vez de palabras conmueve mas profundamente a tu pareja hoy. Podras ver hoy cuanto espacio han tomado tus devotas y silenciosas dedicaciones en el corazon de tu pareja. Expresa ese amor nuevamente hoy—de manera concreta, mediante acciones.' },
      { ko: '설렘보다 안도감, 화려함보다 신뢰로 빛나는 당신의 사랑이 오늘 가장 아름다운 빛을 발합니다. 진정한 사랑의 완숙한 아름다움은 바로 이 안정감 속에 있으며, 그것을 당신과 파트너 모두 오늘 충분히 느낄 것입니다. 이 소중한 사랑에 진심으로 감사함을 표현해 보세요.', en: 'Your love, which shines through reassurance rather than excitement and through trust rather than glamour, radiates its most beautiful light today. The mature beauty of true love lives precisely in this sense of stability, and both you and your partner will feel it fully today. Express genuine gratitude for this precious love.', zh: '你的爱情，以安心而非心动、以信任而非华丽闪耀，今天绽放出最美的光芒。真爱成熟的美丽恰恰存在于这种稳定感之中，你和你的伴侣今天都将充分感受到这一点。真诚地为这份珍贵的爱表达感谢吧。', ja: 'ときめきよりも安心感、華やかさよりも信頼で輝くあなたの愛が今日最も美しい光を放ちます。真の愛の成熟した美しさはまさにこの安定感の中にあり、あなたもパートナーも今日それを十分に感じるでしょう。この大切な愛への感謝を表現してみてください。', es: 'Tu amor, que brilla a traves de la tranquilidad en lugar de la emocion y de la confianza en lugar del glamour, irradia su luz mas hermosa hoy. La belleza madura del amor verdadero vive precisamente en este sentido de estabilidad. Expresa genuina gratitud por este precioso amor.' },
      { ko: '솔로인 당신에게, 오늘은 가치관과 삶의 방향이 비슷한 특별한 누군가와의 의미 있는 만남이 기다리고 있습니다. 염소자리는 단순히 끌리는 것보다 서로의 가치를 이해하고 존중할 수 있는 관계를 원하기 때문에, 이 만남은 그 어느 때보다 특별하게 느껴질 것입니다. 마음을 열고 그 연결을 받아들이세요.', en: 'If you are single, today a meaningful encounter with someone who shares your values and life direction is waiting for you. Because Capricorn seeks relationships built on mutual understanding and respect rather than simple attraction, this meeting will feel more special than any before. Open your heart and embrace the connection.', zh: '单身的你，今天有一个与你价值观和人生方向相近的特别的人的有意义的相遇在等着你。摩羯座渴望的不只是简单的吸引，而是能够相互理解和尊重彼此价值观的关系，因此这次相遇将比以往任何时候都更加特别。打开心扉，接纳这份连结吧。', ja: 'シングルのあなたに今日は価値観と人生の方向が似た特別な誰かとの意味ある出会いが待っています。摩羯座は単なる引き合いよりお互いの価値を理解し尊重できる関係を望むため、この出会いはこれまでになく特別に感じられるでしょう。心を開いてその繋がりを受け入れてください。', es: 'Si eres soltero/a, hoy te espera un encuentro significativo con alguien que comparte tus valores y direccion de vida. Porque Capricornio busca relaciones construidas en comprension y respeto mutuos mas que simple atraccion, este encuentro se sentira mas especial que cualquier otro. Abre tu corazon y abraza la conexion.' },
      { ko: '두 사람이 함께 목표를 세우고 그것을 향해 나란히 걸어가는 과정 자체가 관계의 깊이를 더욱 단단하게 만들어 갑니다. 염소자리의 사랑은 단순한 감정이 아닌 공동의 성장과 성취 위에 피어납니다. 오늘 파트너와 함께 이루고 싶은 것에 대해 진지하게 이야기를 나눠보세요.', en: 'The very process of setting goals together and walking toward them side by side deepens the foundation of your relationship in lasting ways. Capricorn\'s love flourishes not just on feelings but on shared growth and achievement. Have a serious conversation with your partner today about what you want to build together.', zh: '两人一起设立目标并肩前行的过程本身，正在以持久的方式加深关系的根基。摩羯座的爱不仅建立在感情上，更是在共同的成长与成就中绽放。今天和伴侣认真谈谈你们想共同实现的目标吧。', ja: '二人で目標を立て並んで歩む過程そのものが関係の深さをより強固に作り上げていきます。摩羯座の愛は単なる感情ではなく共同の成長と達成の上に咲きます。今日パートナーと一緒に成し遂げたいことについて真剣に話し合ってみてください。', es: 'El proceso mismo de establecer metas juntos y caminar hacia ellas uno al lado del otro profundiza los cimientos de vuestra relacion de maneras duraderas. El amor de Capricornio florece no solo en los sentimientos sino en el crecimiento y logro compartidos. Ten una conversacion seria hoy con tu pareja sobre lo que quieren construir juntos.' },
      { ko: '어떤 감동적인 말보다도, 어렵고 힘든 순간에 그 곁을 묵묵히 지켜주는 당신의 존재 자체가 상대에게는 가장 위대한 사랑 고백이 됩니다. 오늘은 그 단순하고 진실된 동행이 파트너의 마음에 깊이 새겨지는 날입니다. 오늘도 그냥 곁에 있어주세요—그것만으로 충분합니다.', en: 'More than any moving words, your presence quietly standing beside them through difficult moments is the greatest confession of love your partner could ever receive. Today that simple, true companionship is deeply engraved in your partner\'s heart. Simply be there today—that alone is enough.', zh: '比任何感人的言语都更有力量的，是你在艰难时刻默默守护在旁的存在，这对对方而言是最伟大的爱情告白。今天，这份简单而真诚的陪伴将深深铭刻在伴侣心中。今天，只是陪在身旁就够了——仅此而已。', ja: 'どんな感動的な言葉よりも、困難な瞬間に黙ってそばで守り続けるあなたの存在自体が相手にとって最も偉大な愛の告白となります。今日はその単純で真実の同行がパートナーの心に深く刻まれる日です。今日もただそばにいてください。', es: 'Mas que cualquier palabra conmovedora, tu presencia silenciosamente a su lado durante los momentos dificiles es la mayor confesion de amor que tu pareja podria recibir. Hoy esa simple y verdadera compania queda profundamente grabada en el corazon de tu pareja. Simplemente estate ahi hoy—solo eso es suficiente.' },
      { ko: '안정을 추구하는 염소자리이지만, 오래된 관계에 신선한 활력을 불어넣을 수 있는 에너지가 오늘 찾아옵니다. 드라마틱한 변화가 아닌 작은 시도—익숙하지 않은 장소, 새로운 화제, 뜻밖의 제스처—가 관계에 생동감을 되살려줄 것입니다. 오늘 하나의 작은 변화를 선물해 보세요.', en: 'Although Capricorn naturally seeks stability, today brings the energy to infuse fresh vitality into a long-standing relationship. It doesn\'t take dramatic change—a small attempt like an unfamiliar place, a new topic, or an unexpected gesture will revive the spark. Gift one small change today.', zh: '摩羯座天生追求稳定，但今天带来了为长久关系注入新鲜活力的能量。不需要戏剧性的改变——换个陌生的地方、聊个新话题、来个意外的小举动，就能重燃关系的生气。今天，送出一个小小的改变吧。', ja: '安定を求める摩羯座ですが、今日は長い関係に新鮮な活力を吹き込めるエネルギーが訪れます。劇的な変化ではなく、馴染みのない場所、新しい話題、意外なジェスチャーといった小さな試みが関係に生き生きとした感覚を取り戻させるでしょう。', es: 'Aunque Capricornio busca naturalmente la estabilidad, hoy trae la energia para infundir nueva vitalidad en una relacion de larga data. No hace falta un cambio dramatico—un pequeno intento como un lugar poco familiar, un nuevo tema o un gesto inesperado revivira la chispa. Regala un pequeno cambio hoy.' },
      { ko: '오늘은 서로의 성장과 꿈을 진심으로 지지하는 두 사람의 파트너십이 가장 밝게 빛나는 날입니다. 경쟁하지 않고 서로의 날개를 달아주는 관계야말로 염소자리가 꿈꾸는 이상적인 사랑의 형태입니다. 오늘 파트너의 성공을 진심으로 축하하고 응원해 주세요.', en: 'Today is the day your partnership—one where you genuinely support each other\'s growth and dreams—shines at its brightest. A relationship that gives each other wings rather than competing is the ideal form of love Capricorn has always dreamed of. Celebrate and cheer your partner\'s success wholeheartedly today.', zh: '今天是你们这对真心支持彼此成长与梦想的伴侣关系最为闪耀的日子。不是相互竞争，而是为彼此插上翅膀——这正是摩羯座心目中理想爱情的形态。今天，真诚地为伴侣的成功喝彩和加油吧。', ja: '今日はお互いの成長と夢を心から支え合う二人のパートナーシップが最も明るく輝く日です。競い合わずにお互いに翼を授ける関係こそ摩羯座が夢見る理想の愛の形です。今日パートナーの成功を心から祝って応援してください。', es: 'Hoy es el dia en que vuestra alianza—una en la que se apoyan genuinamente en el crecimiento y suenos del otro—brilla en su punto mas luminoso. Una relacion que da alas al otro en lugar de competir es la forma ideal de amor que Capricornio siempre ha sonado. Celebra y anima el exito de tu pareja de todo corazon hoy.' },
      { ko: '오늘 당신의 책임감 있고 신뢰할 수 있는 태도가 상대의 마음속에 세상 어떤 것으로도 흔들리지 않는 깊은 신뢰를 심어줍니다. 화려한 로맨스가 아닌 이 흔들리지 않는 신뢰야말로 장기적으로 사랑을 지탱하는 가장 강한 기둥입니다. 오늘도 약속을 지키고 일관된 모습을 보여주세요.', en: 'Today your responsible and trustworthy attitude plants in the other person\'s heart a deep trust that nothing in the world can shake. This unshakeable trust—not flashy romance—is the strongest pillar that sustains love for the long term. Keep your promises and show consistency today as well.', zh: '今天，你负责任、值得信赖的态度，在对方心中种下了世上任何事物都无法撼动的深厚信任。这种不可动摇的信任，而非华丽的浪漫，才是长期维系爱情最坚实的支柱。今天也要信守承诺，展现一贯的风格。', ja: '今日あなたの責任感があり信頼できる態度が相手の心に世界のどんなものでも揺るがせない深い信頼を植え付けます。華やかなロマンスではなくこの揺るぎない信頼こそが長期的に愛を支える最も強い柱です。今日も約束を守り一貫した姿を見せてください。', es: 'Hoy tu actitud responsable y digna de confianza planta en el corazon del otro una confianza profunda que nada en el mundo puede sacudir. Esta confianza inquebrantable—no el romance llamativo—es el pilar mas fuerte que sostiene el amor a largo plazo. Cumple tus promesas y muestra coherencia hoy tambien.' },
    ],
    medium: [
      { ko: '큰 사건보다 일상의 작은 신뢰가 관계의 토대를 이루는 법입니다. 지금은 화려한 것보다 서로에 대한 믿음을 차분히 다지는 시간이 필요하며, 그 시작은 작은 약속 하나를 지키는 것에서 비롯됩니다. 오늘 어떤 작은 약속을 지킬 수 있을지 생각해 보세요.', en: 'Small daily trust builds the foundation of a relationship far more than dramatic gestures do. Right now you need time to quietly strengthen mutual belief in each other, and it all starts with keeping one small promise. Think today about what small commitment you can follow through on.', zh: '日常的小信任比戏剧性的举动更能奠定关系的基础。现在需要静下心来巩固彼此的信任，而这一切的起点，是信守一个小小的承诺。今天想想你能履行哪个小承诺吧。', ja: '大きな出来事より日常の小さな信頼が関係の土台を作るものです。今はきらびやかなことよりお互いへの信頼を静かに固める時間が必要であり、その始まりは小さな約束を一つ守ることからです。今日どんな小さな約束を守れるか考えてみてください。', es: 'La pequena confianza diaria construye los cimientos de una relacion mucho mas que los grandes gestos. Ahora necesitas tiempo para fortalecer silenciosamente la confianza mutua, y todo comienza con cumplir una pequena promesa. Piensa hoy en que pequeno compromiso puedes cumplir.' },
      { ko: '거창한 이벤트보다 일상의 작은 배려 하나가 두 사람 사이의 온도를 훨씬 따뜻하게 만들 수 있습니다. 오늘 아침 커피 한 잔을 건네는 그 정성이면 충분하며, 그 순간이 상대에게는 긴 하루를 버티게 하는 힘이 됩니다. 오늘 작은 배려 하나를 실천해 보세요.', en: 'One small daily gesture of care warms the relationship far more than a grand event could. A cup of coffee handed over with thought this morning is genuinely enough, and that single moment gives your partner the strength to get through a long day. Practice one small act of care today.', zh: '比起盛大的活动，日常中一个小小的体贴举动能让两人之间的温度暖和得多。今天早上递上一杯用心泡的咖啡就已足够，那个瞬间将成为对方撑过漫长一天的力量。今天就实践一个小小的体贴吧。', ja: '大きなイベントより日常の小さな配慮一つが二人の間の温度をずっと温かくできます。今日の朝コーヒー一杯を渡す気遣いで十分であり、その瞬間が相手にとって長い一日を乗り越える力になります。今日小さな配慮一つを実践してみてください。', es: 'Un pequeno gesto diario de cuidado calienta la relacion mucho mas que un gran evento. Una taza de cafe entregada con consideracion esta manana es genuinamente suficiente, y ese unico momento le da a tu pareja la fuerza para superar un dia largo. Practica un pequeno acto de cuidado hoy.' },
      { ko: '감정을 말로 표현하는 것이 쉽지 않은 염소자리이지만, 오늘만큼은 어색하더라도 진심 한마디를 시도해 보세요. 유창한 말솜씨보다 짧더라도 진심에서 나온 한마디가 상대의 하루를 따뜻하게 바꾸는 힘을 가집니다. 용기를 내어 그 말 한마디를 건네보세요.', en: 'Expressing emotions in words is not easy for Capricorn, but today try at least one heartfelt sentence even if it feels awkward. A short word that comes from genuine feeling has the power to transform your partner\'s whole day into something warmer—far more than a polished speech would. Gather your courage and say it.', zh: '对摩羯座来说，用语言表达情感并不容易，但今天，哪怕感觉别扭，也试着说出一句真心话吧。比流利的表达更有力量的，是哪怕短短一句从内心深处说出的话，它能让对方的一天变得温暖。鼓起勇气，说出那句话吧。', ja: '感情を言葉で表現することが得意でない摩羯座ですが、今日だけは不慣れでも真心のこもった一言を試みてみてください。流暢な言葉より短くても真心から出た一言が相手の一日を温かく変える力を持ちます。勇気を出してその一言を伝えてみてください。', es: 'Expresar emociones con palabras no es facil para Capricornio, pero hoy intenta al menos una frase sincera aunque se sienta torpe. Una palabra corta que viene de un sentimiento genuino tiene el poder de transformar todo el dia de tu pareja en algo mas calido—mucho mas que un discurso elaborado. Reune tu valor y dila.' },
      { ko: '낭만적인 대화뿐 아니라 함께 살아갈 현실적인 계획을 나누는 것이 염소자리식 사랑의 진전입니다. 오늘은 여행, 재정, 미래 거주지 등 구체적인 주제에 대해 연인과 솔직하게 이야기해 보세요. 그 대화가 두 사람의 관계를 한 단계 더 단단한 현실 위에 올려놓을 것입니다.', en: 'Sharing realistic plans for living together, not just romantic conversations, is how Capricorn love advances. Today talk openly with your partner about concrete topics like travel, finances, or where you want to live in the future. That conversation will place your relationship on a firmer, more real foundation.', zh: '不只是浪漫的对话，共同分享现实生活的计划，才是摩羯座式爱情的进展方式。今天，坦诚地和恋人聊聊旅行、财务或未来居住地等具体话题吧。这次对话将让你们的关系建立在更坚实的现实基础之上。', ja: 'ロマンチックな会話だけでなく、一緒に暮らしていく現実的な計画を分かち合うことが摩羯座式の愛の進展です。今日は旅行、財政、将来の居住地など具体的なテーマについて恋人と率直に話してみてください。', es: 'Compartir planes realistas para vivir juntos, no solo conversaciones romanticas, es como el amor de Capricornio avanza. Habla abiertamente con tu pareja hoy sobre temas concretos como viajes, finanzas o donde quieren vivir en el futuro. Esa conversacion colocara vuestra relacion sobre una base mas firme y real.' },
      { ko: '극적인 변화나 화려한 이벤트가 아닌, 매일의 꾸준한 관심과 배려가 사랑을 오래도록 키우는 진짜 비결임을 오늘 다시 한번 확인하게 됩니다. 염소자리는 이 진리를 누구보다 잘 압니다. 오늘도 그 꾸준한 사랑을 작은 행동 하나로 표현해 보세요.', en: 'Today you are reminded once again that the real secret to growing love for a long time is not dramatic changes or flashy events, but steady daily attention and care. Capricorn understands this truth better than anyone. Express that consistent love through one small action again today.', zh: '今天你再次意识到，让爱情长久滋养的真正秘诀，不是戏剧性的变化或华丽的活动，而是每天持续的关注与体贴。摩羯座比任何人都更懂得这个真理。今天也用一个小小的行动来表达这份持久的爱吧。', ja: '劇的な変化や派手なイベントではなく、毎日の着実な関心と配慮が愛を長く育てる真の秘訣であることを今日改めて確認することになります。摩羯座はこの真実を誰よりもよく知っています。今日もその継続的な愛を小さな行動一つで表現してみてください。', es: 'Hoy te recuerdas una vez mas que el verdadero secreto para cultivar el amor durante mucho tiempo no son los cambios dramaticos ni los eventos llamativos, sino la atencion y el cuidado constantes del dia a dia. Capricornio entiende esta verdad mejor que nadie. Expresa ese amor consistente con una pequena accion hoy.' },
      { ko: '자신의 속도로 목표를 향해 달리는 것이 익숙한 염소자리이지만, 지금은 상대의 다른 속도를 존중하고 맞춰주는 인내심이 관계에 가장 필요한 덕목입니다. 속도의 차이가 문제가 아니라, 그 차이를 어떻게 이해하느냐가 진짜 사랑의 척도입니다. 오늘은 파트너의 박자를 조용히 들어보세요.', en: 'Capricorn is used to rushing toward goals at their own pace, but right now patience to respect and match your partner\'s different tempo is the most needed virtue in your relationship. The difference in pace is not the problem—how you understand that difference is the real measure of love. Quietly listen to your partner\'s rhythm today.', zh: '摩羯座习惯按自己的节奏冲向目标，但此刻，尊重并配合对方不同节奏的耐心，才是关系中最需要的品质。节奏的差异不是问题所在，如何理解这种差异，才是真正衡量爱的尺度。今天，静静地聆听伴侣的节拍吧。', ja: '自分のペースで目標に向かって走ることが得意な摩羯座ですが、今は相手の異なる速度を尊重して合わせる忍耐心が関係に最も必要な美徳です。速度の違いが問題ではなく、その違いをどう理解するかが真の愛の尺度です。今日はパートナーのリズムを静かに聴いてみてください。', es: 'Capricornio esta acostumbrado a correr hacia las metas a su propio ritmo, pero ahora la paciencia para respetar y adaptarse al diferente tempo de tu pareja es la virtud mas necesaria en tu relacion. La diferencia de ritmo no es el problema—como entiendes esa diferencia es la verdadera medida del amor.' },
      { ko: '오늘 당신의 과묵함이 상대에게 냉담함이나 무관심으로 오해받을 수 있습니다. 긴 설명이 필요하지 않으니, 짧은 문자 한 통이나 따뜻한 눈빛 하나라도 작은 표현을 시도해 보세요. 그 최소한의 연결이 오늘의 오해를 막고 관계의 온기를 유지하는 데 충분합니다.', en: 'Today your quietness may be misread as coldness or indifference by your partner. You don\'t need a long explanation—try a short text or a warm glance as a small gesture of connection. That minimal expression is enough to prevent today\'s misunderstanding and preserve the warmth in your relationship.', zh: '今天，你的沉默可能被对方误解为冷漠或不关心。不需要长篇大论，发一条简短的信息或投去一个温暖的眼神，做出小小的联结表示就好。这最小限度的表达，已足以避免今天的误解，维持关系的温度。', ja: '今日あなたの過黙な態度が相手に冷淡さや無関心と誤解される可能性があります。長い説明は不要なので、短いメッセージ一通や温かい眼差し一つでも小さな表現を試みてみてください。その最低限の繋がりが今日の誤解を防ぎ関係の温かさを保つのに十分です。', es: 'Hoy tu silencio podria ser malinterpretado como frialdad o indiferencia por tu pareja. No necesitas una larga explicacion—intenta un mensaje corto o una mirada calida como pequeno gesto de conexion. Esa expresion minima es suficiente para prevenir el malentendido de hoy y preservar el calor en tu relacion.' },
      { ko: '개인의 공간과 자유를 존중하면서도 두 사람의 유대감을 따뜻하게 유지하는 균형이 지금 관계에 가장 필요한 것입니다. 독립과 연결, 이 두 가지를 동시에 아름답게 지킬 수 있는 것이 성숙한 사랑의 증거입니다. 오늘 그 균형 잡힌 거리감을 의식적으로 실천해 보세요.', en: 'The balance of respecting personal space and freedom while warmly maintaining your bond is what your relationship needs most right now. Being able to beautifully honor both independence and connection at once is the mark of a mature love. Consciously practice that balanced distance today.', zh: '尊重个人空间与自由，同时温暖地维系两人纽带的平衡，正是当下关系最需要的。能够同时优雅地守护独立与连结，这是成熟爱情的证明。今天，有意识地实践这种平衡的距离感吧。', ja: '個人の空間と自由を尊重しながらも二人の絆を温かく維持するバランスが今関係に最も必要なものです。独立と繋がりこの二つを同時に美しく守れることが成熟した愛の証です。今日そのバランスのとれた距離感を意識的に実践してみてください。', es: 'El equilibrio de respetar el espacio y la libertad personal mientras se mantiene calidamente el vinculo es lo que mas necesita vuestra relacion ahora mismo. Poder honrar bellamente tanto la independencia como la conexion al mismo tiempo es la marca de un amor maduro. Practica conscientemente esa distancia equilibrada hoy.' },
      { ko: '특별한 날의 데이트도 물론 소중하지만, 오늘은 함께 마트를 가거나 저녁을 함께 만들어 먹는 평범한 일상을 나누는 시간이 훨씬 더 깊은 의미와 친밀감을 만들어 냅니다. 평범함 속에 진짜 사랑이 있으며, 염소자리는 그 진실을 가장 잘 알고 있습니다. 오늘의 평범한 순간을 소중히 여기세요.', en: 'Special date nights are wonderful, but today sharing an ordinary moment together—going to the market or cooking dinner—creates far deeper meaning and intimacy than any planned event could. Real love lives in the ordinary, and Capricorn knows this truth best of all. Treasure today\'s simple, everyday moments.', zh: '特别的约会当然珍贵，但今天，一起去超市或共同做顿晚饭的平凡日常，能创造出比任何精心策划的活动都更深刻的意义与亲密感。真实的爱藏在平凡之中，摩羯座最懂得这个真理。珍惜今天那些平凡的瞬间吧。', ja: '特別なデートも大切ですが、今日は一緒にスーパーに行ったり夕食を作ったりする平凡な日常を分かち合う時間がずっと深い意味と親密感を生み出します。平凡の中に本当の愛があり、摩羯座はその真実を最もよく知っています。今日の平凡な瞬間を大切にしてください。', es: 'Las citas especiales son maravillosas, pero hoy compartir un momento ordinario juntos—ir al mercado o cocinar la cena—crea un significado e intimidad mucho mas profundos que cualquier evento planificado. El amor real vive en lo ordinario, y Capricornio conoce esta verdad mejor que nadie. Atesora los simples momentos cotidianos de hoy.' },
      { ko: '드라마틱한 사건 없이 조용히 흘러가는 이 시기가 오히려 관계의 기반을 가장 탄탄하게 다지는 소중한 시간입니다. 겉으로는 평범해 보여도, 지금 쌓아가는 신뢰와 이해의 층이 미래 관계의 가장 강한 뿌리가 됩니다. 이 조용한 과정의 가치를 알아보는 지혜를 가지세요.', en: 'This quiet period with no dramatic events is actually the most valuable time for solidly building your relationship\'s foundation. Even if it looks ordinary on the surface, the layers of trust and understanding you are building now become the strongest root of your future relationship. Have the wisdom to recognize the value of this quiet process.', zh: '没有戏剧性事件、静静流淌的这段时期，其实是最踏实地奠定关系基础的宝贵时光。即使表面看起来平淡，你们现在积累的信任与理解的层次，将成为未来关系最强壮的根基。拥有看见这段宁静过程价值的智慧吧。', ja: 'ドラマチックな出来事なく静かに流れるこの時期がむしろ関係の基盤を最も堅固に固める大切な時間です。表面は平凡に見えても今積み重ねている信頼と理解の層が未来の関係の最も強い根になります。この静かなプロセスの価値を見抜く知恵を持ってください。', es: 'Este periodo tranquilo sin eventos dramaticos es en realidad el tiempo mas valioso para construir solidamente la base de tu relacion. Aunque parezca ordinario en la superficie, las capas de confianza y comprension que construyes ahora se convierten en la raiz mas fuerte de vuestra relacion futura. Ten la sabiduria de reconocer el valor de este proceso silencioso.' },
    ],
    low: [
      { ko: '스스로에게 높은 기준을 요구하는 것은 미덕이지만, 그 동일한 기준을 상대에게도 무의식적으로 적용하고 있지 않은지 오늘 조용히 돌아보세요. 사람은 각자 다른 방식으로 성장하며, 사랑은 그 차이를 판단이 아닌 이해로 대하는 것입니다. 오늘 상대의 있는 그대로를 받아들여 보세요.', en: 'Holding yourself to high standards is a virtue, but today quietly reflect on whether you have been unconsciously applying those same standards to your partner. People grow in different ways, and love means meeting those differences with understanding rather than judgment. Try accepting your partner exactly as they are today.', zh: '对自己高标准要求是美德，但今天请静下心来反思，你是否无意中把同样的标准也套用在了对方身上。人各有其成长方式，而爱，是用理解而非评判去面对那些差异。今天，试着接受伴侣本来的样子吧。', ja: '自分に高い基準を求めることは美徳ですが、同じ基準を相手にも無意識に適用していないか今日静かに振り返ってみてください。人はそれぞれ異なる方法で成長し、愛はその違いを判断でなく理解で対処することです。今日相手のあるがままを受け入れてみてください。', es: 'Mantenerte con altos estandares es una virtud, pero hoy reflexiona quietamente sobre si has estado aplicando inconscientemente esos mismos estandares a tu pareja. Las personas crecen de maneras diferentes, y el amor significa encontrar esas diferencias con comprension en lugar de juicio. Intenta aceptar a tu pareja exactamente como es hoy.' },
      { ko: '목표를 향한 열정이 대단한 당신이지만, 어느새 그 열정이 연인에게 가야 할 시간과 관심을 잠식하고 있을 수 있습니다. 일의 성공이 삶 전체의 행복을 보장하지 않는다는 것을 기억하세요. 오늘 하루, 연인에게 의도적으로 시간과 주의를 할당해 보세요.', en: 'Your passion for your goals is remarkable, but it may have gradually encroached on the time and attention that should go to your partner. Remember that success at work does not guarantee happiness in all areas of life. Today, intentionally allocate time and attention to your partner.', zh: '你对目标的热情令人钦佩，但这份热情或许已经不知不觉地侵占了本该属于恋人的时间和关注。请记住，工作上的成功并不能保证生活全面的幸福。今天，有意识地把时间和注意力分配给恋人吧。', ja: '目標への情熱が素晴らしいあなたですが、いつの間にかその情熱が恋人への時間と関心を侵食しているかもしれません。仕事の成功が人生全体の幸福を保証しないことを覚えておいてください。今日は恋人に意識的に時間と注意を割いてみてください。', es: 'Tu pasion por tus metas es notable, pero puede que haya ido invadiendo gradualmente el tiempo y la atencion que deberian ir a tu pareja. Recuerda que el exito en el trabajo no garantiza la felicidad en todas las areas de la vida. Hoy, asigna intencionalmente tiempo y atencion a tu pareja.' },
      { ko: '모든 것을 통제하고 싶은 염소자리의 성향이 사랑에서는 소유욕으로 나타날 수 있습니다. 오늘 그 마음을 의식적으로 경계하세요. 진정한 사랑은 상대를 붙잡는 것이 아니라, 상대가 자유롭게 당신 곁에 머물고 싶도록 만드는 것입니다. 통제를 내려놓을 때 사랑이 진짜로 깊어집니다.', en: 'Capricorn\'s desire to control everything can manifest as possessiveness in love. Today, be consciously aware of this tendency. True love is not about holding someone in place—it is about making them want to freely stay by your side. Love deepens for real only when you release the need to control.', zh: '摩羯座想要掌控一切的倾向，在爱情中可能表现为占有欲。今天，请有意识地警惕这种心态。真正的爱不是把对方留住，而是让对方发自内心地想要留在你身边。只有放下控制，爱才能真正深化。', ja: 'すべてをコントロールしたい摩羯座の性向が愛では所有欲として現れる可能性があります。今日その気持ちを意識的に警戒してください。真の愛は相手を縛り付けることではなく、相手が自由にあなたのそばにいたいと思わせることです。コントロールを手放す時に愛が本当に深まります。', es: 'El deseo de Capricornio de controlar todo puede manifestarse como posesividad en el amor. Hoy, se conscientemente consciente de esta tendencia. El amor verdadero no se trata de retener a alguien—se trata de hacer que quieran quedarse libremente a tu lado. El amor se profundiza de verdad solo cuando sueltas la necesidad de controlar.' },
      { ko: '감정을 감추고 혼자 삭이는 것이 당신의 오랜 습관이지만, 그 습관이 쌓이면서 두 사람 사이에 눈에 보이지 않는 높은 벽이 생겨나고 있습니다. 오늘 아주 조금이라도 솔직해지는 시도를 해보세요. 그 작은 틈새가 상대와의 진짜 연결이 시작되는 문입니다.', en: 'Hiding your feelings and processing them alone has been your long-standing habit, but as it accumulates it is building an invisible wall between you. Try being just a little more honest today. That small opening is the door where genuine connection with your partner begins.', zh: '压抑感情、独自消化是你由来已久的习惯，但这种习惯的积累正在你们之间筑起一道隐形的高墙。今天，试着哪怕只是稍微坦诚一点点。那道小小的裂缝，正是与对方真正连结开始的大门。', ja: '感情を隠して一人で消化することがあなたの長年の習慣ですが、その習慣が積み重なって二人の間に見えない高い壁が生まれています。今日ほんの少しでも正直になる試みをしてみてください。その小さな隙間が相手との本当の繋がりが始まる扉です。', es: 'Ocultar tus sentimientos y procesarlos solo ha sido tu habito de larga data, pero al acumularse esta construyendo una pared invisible entre ustedes. Intenta ser solo un poco mas honesto hoy. Esa pequena apertura es la puerta donde comienza la conexion genuina con tu pareja.' },
      { ko: '과거에 받은 상처가 지금 이 관계에 그림자처럼 따라다니며 두 사람의 현재를 흐리게 하고 있습니다. 그 상처는 분명 실재했지만, 오늘의 파트너는 그 상처를 준 사람이 아닙니다. 과거의 무게를 내려놓는 용기가 현재와 미래의 사랑을 지키는 가장 강한 행동입니다.', en: 'Wounds from the past are following this relationship like a shadow, clouding what exists between you now. Those wounds were real, but today\'s partner is not the one who caused them. The courage to release the weight of the past is the strongest act you can take to protect the love of your present and future.', zh: '过去受到的伤害像影子一样跟随着这段关系，让你们的现在变得模糊不清。那些伤痛确实存在，但今天的伴侣并不是造成那些伤痛的人。放下过去重量的勇气，是守护现在与未来之爱最有力的行动。', ja: '過去に受けた傷が今の関係に影のようについてまわり、二人の現在を曇らせています。その傷は確かに実在しましたが、今日のパートナーはその傷を与えた人ではありません。過去の重みを手放す勇気が現在と未来の愛を守る最も強い行動です。', es: 'Las heridas del pasado siguen a esta relacion como una sombra, nublando lo que existe entre ustedes ahora. Esas heridas fueron reales, pero la pareja de hoy no es quien las causo. El valor de soltar el peso del pasado es el acto mas fuerte que puedes tomar para proteger el amor de tu presente y futuro.' },
      { ko: '높은 기준을 가진 당신의 비판적인 시선이 오늘 상대를 움츠러들게 하고 관계에 냉기를 불러올 수 있습니다. 비판 대신 먼저 칭찬 한마디를 건네보세요. 사람은 칭찬받을 때 더 잘 자라며, 그 온기가 결국 당신이 원하는 변화도 자연스럽게 이끌어 냅니다.', en: 'Today your critical gaze—born of high standards—may cause your partner to shrink and bring a chill to the relationship. Offer praise first instead of criticism. People grow better when praised, and that warmth will naturally lead to the very changes you want more effectively than any critique would.', zh: '你那来自高标准的批判目光，今天可能让对方退缩，给关系带来一丝寒意。试着先说一句赞美的话，而不是批评。人在被赞美时成长得更好，那份温暖最终也会自然而然地引发你希望看到的改变，远比批评更有效。', ja: '高い基準から来るあなたの批判的な視線が今日相手を萎縮させ関係に冷気をもたらす可能性があります。批判より先に褒め言葉を一言贈ってみてください。人は褒められる時よりよく成長し、その温かさが結局あなたが望む変化も自然に導き出します。', es: 'Hoy tu mirada critica—nacida de altos estandares—puede hacer que tu pareja se encoja y traer un frio a la relacion. Ofrece elogios primero en vez de criticas. Las personas crecen mejor cuando se les elogia, y esa calidez conducira naturalmente a los mismos cambios que deseas de manera mas efectiva que cualquier critica.' },
      { ko: '사랑을 일처럼 효율적으로 관리하려는 경향이 오늘 관계의 온기를 식히고 있습니다. 사랑에서 가장 중요한 것은 결과나 효율이 아니라 감성적 교류와 공명임을 기억하세요. 오늘은 계획을 잠시 내려놓고 상대의 이야기를 온전히 들어주는 시간을 가져보세요.', en: 'The tendency to manage love as efficiently as you would manage work is cooling the warmth of your relationship today. Remember that what matters most in love is not results or efficiency but emotional exchange and resonance. Put down your plans for a while today and give your partner the gift of being fully heard.', zh: '像管理工作一样高效地处理爱情的倾向，今天正在让关系的温度降低。请记住，在爱情中最重要的不是结果或效率，而是感性的交流与共鸣。今天，暂时放下计划，给自己和伴侣一段彼此倾听的时光吧。', ja: '愛を仕事のように効率的に管理しようとする傾向が今日関係の温かさを冷ましています。愛で最も重要なのは結果や効率ではなく感性的な交流と共鳴であることを覚えておいてください。今日は計画をしばらく脇に置いて相手の話を完全に聴く時間を持ってみてください。', es: 'La tendencia a gestionar el amor con tanta eficiencia como el trabajo esta enfriando la calidez de tu relacion hoy. Recuerda que lo mas importante en el amor no son los resultados ni la eficiencia sino el intercambio emocional y la resonancia. Deja tus planes por un rato hoy y dale a tu pareja el regalo de ser plenamente escuchado.' },
      { ko: '자신의 기준과 논리로만 관계를 판단하다 보면 상대가 보이지 않게 됩니다. 두 사람이 함께 만들어가는 관계는 혼자의 판단이 아닌 열린 대화로 풀어나가야 합니다. 오늘 판단 대신 질문으로 대화를 시작해 보세요—상대의 진짜 마음이 들릴 것입니다.', en: 'Judging the relationship only through your own standards and logic causes you to stop seeing your partner. A relationship built by two people must be worked out through open dialogue, not one person\'s verdict alone. Start a conversation today with a question instead of a judgment—you will hear your partner\'s real heart.', zh: '只用自己的标准和逻辑来判断关系，会让你看不见对方的存在。两个人共同构建的关系，需要通过开放的对话来解决，而非一人的定论。今天，试着用提问而非评判来开启对话——你将听到伴侣真实的心声。', ja: '自分の基準と論理だけで関係を判断すると相手が見えなくなります。二人で一緒に作る関係は一人の判断ではなくオープンな対話で解決していく必要があります。今日判断の代わりに質問で会話を始めてみてください。相手の本当の気持ちが聞こえるでしょう。', es: 'Juzgar la relacion solo a traves de tus propios estandares y logica hace que dejes de ver a tu pareja. Una relacion construida por dos personas debe resolverse a traves del dialogo abierto, no del veredicto de una sola persona. Comienza una conversacion hoy con una pregunta en lugar de un juicio—escucharas el corazon real de tu pareja.' },
      { ko: '완벽한 관계란 존재하지 않으며, 그것을 찾아 헤매는 동안 오히려 지금 곁에 있는 소중한 사람을 잃을 수도 있습니다. 삐뚤고 불완전한 부분들이야말로 이 관계가 살아있고 진짜임을 증명하는 것들입니다. 오늘은 그 불완전함 속에서 오직 이 관계만이 가진 아름다움을 찾아보세요.', en: 'A perfect relationship does not exist, and while searching for one you may lose the precious person right beside you. The imperfect, crooked parts are precisely what prove this relationship is alive and real. Today, find the beauty that only this relationship possesses within all its imperfection.', zh: '完美的关系并不存在，而在追寻完美的过程中，你可能反而会失去身边珍贵的人。那些弯曲不完美的部分，恰恰证明了这段关系是真实而鲜活的。今天，在所有的不完美之中，去寻找只有这段关系才拥有的美丽吧。', ja: '完璧な関係は存在せず、それを探し続ける間に今そばにいる大切な人を失うかもしれません。ゆがんで不完全な部分こそがこの関係が生きていて本物であることを証明するものです。今日はその不完全さの中にあるこの関係だけが持つ美しさを見つけてみてください。', es: 'Una relacion perfecta no existe, y mientras la buscas puedes perder a la persona preciosa que esta justo a tu lado. Las partes imperfectas y torcidas son precisamente las que prueban que esta relacion esta viva y es real. Hoy, encuentra la belleza que solo esta relacion posee dentro de toda su imperfeccion.' },
      { ko: '상대의 자유롭고 예측 불가능한 면이 때로는 당신의 통제 욕구를 자극할 수 있습니다. 하지만 그 자유를 진심으로 존중할 때, 오히려 두 사람의 관계는 역설적으로 더 단단하고 깊어집니다. 자유 속에서도 선택받는 사람이 되는 것—그것이 진정한 사랑의 힘입니다.', en: 'Your partner\'s free and unpredictable side can sometimes trigger your desire to control. But when you genuinely respect that freedom, paradoxically the relationship becomes stronger and deeper. Being the one chosen even in freedom—that is the true power of love.', zh: '伴侣自由而难以预测的一面，有时会激发你的控制欲。但当你真正尊重那份自由时，两人的关系反而会在矛盾中变得更加坚实而深厚。即使在自由中也被选择——这才是真正爱情的力量。', ja: '相手の自由で予測できない面が時にあなたのコントロールしたい欲求を刺激するかもしれません。しかしその自由を心から尊重する時、逆説的に二人の関係はより強固で深くなります。自由の中でも選ばれる人になること—それが真の愛の力です。', es: 'El lado libre e impredecible de tu pareja a veces puede desencadenar tu deseo de controlar. Pero cuando genuinamente respetas esa libertad, paradojicamente la relacion se vuelve mas fuerte y profunda. Ser el elegido incluso en la libertad—ese es el verdadero poder del amor.' },
    ],
  },
  career: {
    high: [
      { ko: '끈기 있게 추진해 온 장기 프로젝트에서 마침내 눈에 보이는 성과가 나타나기 시작하는 시기입니다. 이 결과는 당신의 체계적인 접근 방식과 포기하지 않는 인내가 만들어낸 것이며, 주변 사람들도 이제 그 가치를 분명히 인식할 것입니다. 자신 있게 성과를 제시하고 다음 단계를 제안하세요.', en: 'Visible results are finally beginning to emerge from the long-term project you have persisted with so patiently. These results are the product of your systematic approach and unwavering endurance, and those around you will now clearly recognize their value. Present the results with confidence and propose the next step.', zh: '你持之以恒推进的长期项目终于开始出现肉眼可见的成果。这些成果是你系统化的方法和不屈不挠的坚持所创造的，周围的人现在也将清楚地认识到其价值。自信地展示成果，并提出下一步计划吧。', ja: '粘り強く推進してきた長期プロジェクトでついに目に見える成果が現れ始める時期です。この結果はあなたの体系的なアプローチとあきらめない忍耐が生み出したものであり、周囲の人もその価値を明確に認識するでしょう。自信を持って成果を提示し次のステップを提案してください。', es: 'Resultados visibles finalmente comienzan a emerger del proyecto a largo plazo con el que has perseverado tan pacientemente. Estos resultados son el producto de tu enfoque sistematico y resistencia inquebrantable, y quienes te rodean ahora reconoceran claramente su valor. Presenta los resultados con confianza y propone el siguiente paso.' },
      { ko: '오늘 상사나 윗사람으로부터 특별한 인정과 신뢰의 신호가 올 수 있으며, 그것이 머지않아 실질적인 승진이나 더 큰 책임으로 이어질 수 있습니다. 이 기회를 자연스럽게 활용하되, 지나치게 기대치를 드러내거나 서두르지 마세요. 당신의 성실함이 스스로 말하게 하세요.', en: 'Today a special signal of recognition and trust may come from your superiors, and it could soon translate into a concrete promotion or greater responsibility. Naturally leverage this opportunity without revealing excessive expectations or rushing. Let your diligence speak for itself.', zh: '今天，上司或上级可能会传来特别的认可与信任信号，这很快可能转化为实际的晋升或更大的责任。自然地把握这个机会，但不要过度流露期待或急于求成。让你的勤勉自己说话。', ja: '今日上司や目上の人から特別な認められと信頼のサインが来る可能性があり、それがまもなく実際の昇進やより大きな責任につながる可能性があります。この機会を自然に活用しつつ、過度な期待を見せたり急いだりしないでください。あなたの誠実さに自分で語らせてください。', es: 'Hoy puede llegar una senal especial de reconocimiento y confianza de tus superiores, y podria pronto traducirse en un ascenso concreto o mayor responsabilidad. Aprovecha naturalmente esta oportunidad sin revelar expectativas excesivas ni apresurarte. Deja que tu diligencia hable por si misma.' },
      { ko: '당신이 구축한 체계적인 업무 방식이 오늘 팀 전체의 성과를 눈에 띄게 끌어올리는 데 결정적인 역할을 합니다. 당신의 방법론이 팀의 표준이 되어가고 있으며, 이 영향력이 당신의 직업적 가치를 한층 높여줍니다. 당신의 방식을 적극적으로 팀과 공유하세요.', en: 'The systematic work approach you have built plays a decisive role in noticeably elevating the entire team\'s performance today. Your methodology is becoming the team\'s standard, and this influence raises your professional value significantly. Actively share your approach with the team.', zh: '你所建立的系统化工作方式，今天在明显提升整个团队绩效方面发挥了决定性作用。你的方法论正在成为团队的标准，这种影响力进一步提升了你的职业价值。主动与团队分享你的方式吧。', ja: 'あなたが構築した体系的な業務方式が今日チーム全体の成果を目に見えて引き上げる上で決定的な役割を果たします。あなたの方法論がチームの標準となりつつあり、この影響力があなたの職業的な価値を一層高めます。積極的にあなたの方式をチームと共有してください。', es: 'El enfoque sistematico de trabajo que has construido juega hoy un papel decisivo para elevar notablemente el rendimiento de todo el equipo. Tu metodologia se esta convirtiendo en el estandar del equipo, y esta influencia aumenta significativamente tu valor profesional. Comparte activamente tu enfoque con el equipo.' },
      { ko: '지금까지 쌓아온 경험과 역량이 당신을 새로운 차원의 책임을 맡기에 충분하게 준비시켜 놓았습니다. 기회가 문을 두드릴 때 머뭇거림은 적이 됩니다—자신이 준비되었음을 알고 당당히 손을 들어보세요. 다음 레벨은 기다리는 자가 아닌 나서는 자의 것입니다.', en: 'The experience and capabilities you have accumulated have fully prepared you for a new level of responsibility. Hesitation becomes your enemy when opportunity knocks—know that you are ready and raise your hand with confidence. The next level belongs not to those who wait but to those who step forward.', zh: '迄今为止积累的经验与能力，已将你充分准备好承担新层次的责任。当机会敲门时，犹豫便是你的敌人——知道自己已经准备好，自信地举起手来吧。下一个台阶，属于挺身而出的人，而非等待观望的人。', ja: 'これまで積み重ねてきた経験と能力があなたを新たなレベルの責任を引き受けるのに十分に準備させています。機会がドアを叩く時の躊躇は敵になります。自分が準備できていることを知り自信を持って手を挙げてみてください。次のレベルは待つ人ではなく踏み出す人のものです。', es: 'La experiencia y las capacidades que has acumulado te han preparado completamente para un nuevo nivel de responsabilidad. La duda se convierte en tu enemiga cuando llama la oportunidad—sabe que estas listo/a y levanta la mano con confianza. El siguiente nivel pertenece no a quienes esperan sino a quienes dan un paso al frente.' },
      { ko: '당신의 깊은 전문성과 풍부한 경험이 오늘 가장 밝게 빛나며, 당신이 내놓는 의견이 중요한 의사결정의 핵심 방향에 반영됩니다. 이 영향력을 의식적으로 활용하고, 오늘의 발언과 제안을 신중하게 준비하세요. 당신의 말이 오늘 조직의 방향을 바꿀 수 있습니다.', en: 'Your deep expertise and rich experience shine most brightly today, and the opinions you put forward will be reflected in the core direction of key decisions. Consciously leverage this influence and prepare your statements and proposals carefully. Your words today have the power to change your organization\'s direction.', zh: '你深厚的专业性和丰富的经验今天最为闪耀，你提出的意见将被纳入重要决策的核心方向。有意识地发挥这种影响力，认真准备今天的发言和提案。你今天的话语有改变组织方向的力量。', ja: 'あなたの深い専門性と豊富な経験が今日最も輝き、あなたが出す意見が重要な意思決定の核心的な方向に反映されます。この影響力を意識的に活用し、今日の発言と提案を慎重に準備してください。あなたの言葉が今日組織の方向を変えることができます。', es: 'Tu profunda experiencia y rica trayectoria brillan mas hoy, y las opiniones que presentas se reflejaran en la direccion central de las decisiones clave. Aprovecha conscientemente esta influencia y prepara cuidadosamente tus declaraciones y propuestas. Tus palabras hoy tienen el poder de cambiar la direccion de tu organizacion.' },
      { ko: '화려한 자기 PR 없이 묵묵히 실력을 쌓아온 당신의 방식이 어느새 돈으로 살 수 없는 귀한 신뢰의 네트워크를 만들어 주었습니다. 진짜 기회는 항상 이런 진실된 연결에서 옵니다. 오늘 그 소중한 인맥들에게 먼저 연락을 취하거나 감사를 표현해 보세요.', en: 'Your quiet way of building skills without flashy self-promotion has built a precious network of trust that money cannot buy. Real opportunities always come from these genuine connections. Today, reach out to those valuable connections first, or express your gratitude to them.', zh: '你不靠华丽的自我宣传、默默积累实力的方式，不知不觉间为你建立起了金钱买不到的珍贵信任人脉。真正的机会总是从这样真诚的连结中到来。今天，主动联系那些宝贵的人脉，或者向他们表达感谢吧。', ja: '華やかな自己PRなく黙々と実力を積み上げてきたあなたのやり方がいつの間にかお金では買えない貴重な信頼のネットワークを作ってくれました。本当のチャンスは常にこのような真実の繋がりから来ます。今日その大切な人脈に先に連絡を取ったり感謝を表現してみてください。', es: 'Tu manera silenciosa de construir habilidades sin autopromocion llamativa ha creado una red preciosa de confianza que el dinero no puede comprar. Las oportunidades reales siempre vienen de estas conexiones genuinas. Hoy, contacta primero a esas conexiones valiosas o expresa tu gratitud hacia ellas.' },
      { ko: '오늘 리더십을 발휘할 절호의 기회가 찾아옵니다. 염소자리의 리더십은 권위가 아닌 실력과 성실함으로 사람들을 이끄는 것임을 기억하고, 팀이 올바른 방향으로 나아갈 수 있도록 먼저 앞장서세요. 이 도전이 당신의 커리어 경로를 새롭게 정의할 것입니다.', en: 'Today the perfect opportunity to show leadership arrives. Remember that Capricorn\'s leadership is about guiding people through skill and diligence rather than authority, and take the lead so that the team can move in the right direction. This challenge will newly define your career path.', zh: '今天，发挥领导力的绝佳机会来临。记住，摩羯座的领导力是以实力和勤勉引导他人，而非权威，率先为团队指引正确的方向吧。这个挑战将重新定义你的职业道路。', ja: '今日リーダーシップを発揮する絶好の機会が訪れます。摩羯座のリーダーシップは権威ではなく実力と誠実さで人々を率いることだと覚えておき、チームが正しい方向に進めるよう先に先頭に立ってください。このチャレンジがあなたのキャリアの道を新たに定義するでしょう。', es: 'Hoy llega la oportunidad perfecta para mostrar liderazgo. Recuerda que el liderazgo de Capricornio consiste en guiar a las personas a traves de la habilidad y la diligencia en lugar de la autoridad, y encabeza para que el equipo pueda avanzar en la direccion correcta. Este desafio redefinira tu trayectoria profesional.' },
      { ko: '다른 사람들이 압도되어 포기하는 복잡한 문제를 침착하게 분해하고 해결하는 당신의 능력이 오늘 주변의 진심 어린 감탄을 자아냅니다. 이 역량이야말로 당신이 조직에서 가장 없어서는 안 되는 존재로 만드는 핵심입니다. 오늘도 그 강점을 아낌없이 발휘하세요.', en: 'Today your ability to calmly break down and solve complex problems that overwhelm and defeat others draws sincere admiration from those around you. This capability is precisely the core of what makes you the most indispensable person in your organization. Give that strength everything you have today.', zh: '今天，你能够沉着冷静地分解并解决那些令他人望而却步的复杂问题，这种能力引来周围人真诚的赞叹。这种能力正是让你成为组织中最不可或缺的人的核心所在。今天也毫不吝啬地发挥你的这一优势吧。', ja: '他の人が圧倒されてあきらめる複雑な問題を冷静に分解して解決するあなたの能力が今日周囲の心からの感嘆を引き出します。この能力こそがあなたを組織で最も欠かせない存在にする核心です。今日もその強みを惜しみなく発揮してください。', es: 'Hoy tu capacidad para descomponer calmadamente y resolver problemas complejos que abruman y derratan a otros genera admiracion sincera de quienes te rodean. Esta capacidad es precisamente el nucleo de lo que te hace la persona mas indispensable en tu organizacion. Da a esa fortaleza todo lo que tienes hoy.' },
      { ko: '지금까지의 모든 경험과 역량이 오늘 당신에게 커리어의 다음 단계로 나아갈 완전한 준비가 되었음을 말해줍니다. 이 확신이 들 때 주저하지 않는 것이 염소자리가 정상에 서는 방법입니다. 지금 바로 움직이세요—다음 장은 당신이 써야 합니다.', en: 'Everything you have experienced and developed until now tells you today that you are completely ready to advance to the next stage of your career. Not hesitating when this certainty arrives is exactly how Capricorn reaches the summit. Move right now—the next chapter is yours to write.', zh: '迄今为止所有的经验与能力，今天都在告诉你：你已完全准备好迈向职业生涯的下一阶段。当这种确信到来时不犹豫，正是摩羯座登顶的方式。现在就行动——下一个篇章需要你来书写。', ja: 'これまでのすべての経験と能力が今日あなたにキャリアの次のステージに進む完全な準備ができていると告げています。この確信が来た時に躊躇しないことが摩羯座が頂上に立つ方法です。今すぐ動いてください。次の章はあなたが書かなければなりません。', es: 'Todo lo que has experimentado y desarrollado hasta ahora te dice hoy que estas completamente listo/a para avanzar al siguiente nivel de tu carrera. No dudar cuando llega esta certeza es exactamente como Capricornio alcanza la cima. Actua ahora mismo—el proximo capitulo es tuyo para escribir.' },
      { ko: '오늘 당신의 한결같은 성실함이 조직에서 그 어떤 기술이나 자산보다 더 귀한 핵심 자원으로 인식되고 있습니다. 화려하지 않아도 신뢰할 수 있는 사람이 결국 가장 오래, 가장 높이 올라간다는 것을 오늘이 증명합니다. 이 성실함에 진정한 자부심을 가지세요.', en: 'Today your consistent diligence is recognized in your organization as a more precious core asset than any skill or technology. Today proves that the person who is trustworthy even without being flashy is ultimately the one who rises the highest and lasts the longest. Take genuine pride in this diligence.', zh: '今天，你一如既往的勤勉被组织视为比任何技术或资产都更珍贵的核心资源。今天证明了：即使不那么耀眼，但值得信赖的人，最终走得最久、站得最高。为这份勤勉感到真正的自豪吧。', ja: '今日あなたの一貫した誠実さが組織でいかなる技術や資産よりも貴重な核心的な資源として認識されています。華やかでなくても信頼できる人が結局最も長く最も高く上がることを今日が証明します。この誠実さに真の誇りを持ってください。', es: 'Hoy tu diligencia consistente es reconocida en tu organizacion como un activo central mas precioso que cualquier habilidad o tecnologia. Hoy demuestra que la persona que es confiable incluso sin ser llamativa es en ultima instancia la que sube mas alto y dura mas tiempo. Siente verdadero orgullo por esta diligencia.' },
    ],
    medium: [
      { ko: '특별한 이벤트나 눈에 띄는 성과 없이도, 맡은 업무를 하루하루 꾸준히 처리하는 것만으로 자연스럽게 좋은 평가와 신뢰가 쌓입니다. 이 꾸준함이야말로 염소자리가 가진 가장 강력한 무기입니다. 오늘도 그 방식 그대로 성실하게 임해보세요.', en: 'Even without special events or standout achievements, simply handling your assigned tasks steadily day by day naturally accumulates good evaluations and trust. This consistency is Capricorn\'s most powerful weapon. Approach today with the same diligent method—it will pay off.', zh: '即使没有特别的事件或亮眼的成果，仅凭日复一日踏实处理分内工作，就能自然积累好的评价与信任。这种持之以恒，正是摩羯座最强大的武器。今天也以同样的方式认真对待吧。', ja: '特別なイベントや目立つ成果がなくても、担当業務を日々着実に処理するだけで自然と良い評価と信頼が積み重なります。この一貫性こそが摩羯座が持つ最も強力な武器です。今日もその方法のまま誠実に取り組んでみてください。', es: 'Incluso sin eventos especiales o logros destacados, simplemente manejar tus tareas asignadas de manera constante dia a dia acumula naturalmente buenas evaluaciones y confianza. Esta consistencia es el arma mas poderosa de Capricornio. Afronta hoy con el mismo metodo diligente—dara sus frutos.' },
      { ko: '거대한 목표 앞에서 막막함을 느끼기 쉬운 시기이지만, 작은 목표를 하나씩 달성해 나가다 보면 어느새 큰 그림의 윤곽이 선명해지고 있음을 발견하게 됩니다. 지금 당신이 걷고 있는 이 작은 걸음들이 결국 가장 먼 곳까지 데려다 줄 것입니다. 오늘의 작은 완수에 집중하세요.', en: 'It is easy to feel overwhelmed before a huge goal right now, but as you achieve small targets one by one you will find that the outline of the big picture is becoming clearer. These small steps you are taking will ultimately carry you the furthest. Focus on today\'s small completion.', zh: '在巨大目标面前容易感到迷茫，但一个个达成小目标后，你会发现大蓝图的轮廓正在变得清晰。你现在走的这些小步伐，终将带你走到最远的地方。专注于今天的小小完成吧。', ja: '大きな目標の前で途方に暮れやすい時期ですが、小さな目標を一つずつ達成していくと大きな絵の輪郭が鮮明になっていくことに気づきます。今あなたが歩んでいる小さな一歩が結局最も遠くまで連れて行ってくれるでしょう。今日の小さな完遂に集中してください。', es: 'Es facil sentirse abrumado ante una meta enorme ahora mismo, pero al lograr pequenos objetivos uno a uno descubriras que el contorno del panorama general se va volviendo mas claro. Estos pequenos pasos que estas dando te llevaran en ultima instancia mas lejos. Enfocate en la pequena realizacion de hoy.' },
      { ko: '외부의 혼돈을 정리하면 내면의 명료함도 함께 따라오는 법입니다. 오늘은 업무 환경을 체계적으로 정리하고 효율을 높이기에 최적의 날이며, 그 시작은 책상 정리처럼 가장 작고 구체적인 것에서 비롯됩니다. 정돈된 공간이 정돈된 사고를 만들어냅니다.', en: 'Organizing external chaos brings internal clarity in its wake. Today is the perfect day to systematically organize your workspace and boost efficiency, and it all starts with the smallest, most concrete action—tidying your desk. An organized space creates an organized mind.', zh: '整理外在的混乱，内心的清明也会随之而来。今天是系统整理工作环境、提升效率的最佳时机，而这一切从最小、最具体的事情开始——整理桌面。整洁的空间创造整洁的思维。', ja: '外部の混乱を整理すると内面の明晰さも一緒についてきます。今日は業務環境を体系的に整理し効率を高めるのに最適な日であり、その始まりは机の整理のような最も小さく具体的なことからです。整頓された空間が整頓された思考を作り出します。', es: 'Organizar el caos externo trae claridad interna en su estela. Hoy es el dia perfecto para organizar sistematicamente tu espacio de trabajo y aumentar la eficiencia, y todo comienza con la accion mas pequena y concreta—ordenar tu escritorio. Un espacio organizado crea una mente organizada.' },
      { ko: '오늘의 성과는 혼자의 역량이 아닌 동료들과의 안정적이고 신뢰에 기반한 협업에서 비롯됩니다. 신뢰는 하루아침에 만들어지지 않지만, 오늘 당신이 보여주는 성실한 협력 하나가 그 기반을 한 층 더 쌓아 올립니다. 팀워크를 의식적으로 강화하세요.', en: 'Today\'s achievement comes not from individual capability alone but from stable, trust-based collaboration with your colleagues. Trust is not built overnight, but one sincere act of cooperation you show today adds another layer to that foundation. Consciously strengthen teamwork.', zh: '今天的成果，不只来自个人能力，而是来自与同事稳定、基于信任的合作。信任不是一夜之间建立的，但你今天展现出的真诚协作，将为那个基础再添一层。有意识地强化团队合作吧。', ja: '今日の成果は一人の能力ではなく同僚との安定した信頼に基づいた協業から生まれます。信頼は一夜にして作られませんが、今日あなたが見せる誠実な協力一つがその基盤をさらに一層積み上げます。チームワークを意識的に強化してください。', es: 'El logro de hoy proviene no solo de la capacidad individual sino de la colaboracion estable y basada en la confianza con tus colegas. La confianza no se construye de la noche a la manana, pero un acto sincero de cooperacion que muestras hoy agrega otra capa a esa base. Fortalece conscientemente el trabajo en equipo.' },
      { ko: '현재에 안주하지 않고 새로운 기술과 지식을 꾸준히 흡수하는 것이 염소자리가 경쟁에서 앞서 나가는 방법입니다. 오늘 자기 계발의 기회를 놓치지 마세요. 지금 투자하는 배움이 6개월 후 당신의 가치를 크게 높여줄 것입니다.', en: 'Continuously absorbing new skills and knowledge without becoming complacent is how Capricorn stays ahead in competition. Don\'t miss today\'s self-development opportunities. The learning you invest in now will greatly raise your value six months from now.', zh: '不安于现状、持续吸收新技能和知识，是摩羯座在竞争中保持领先的方式。今天不要错过自我提升的机会。你现在投入的学习，将在六个月后大大提升你的价值。', ja: '現状に満足せず新しい技術や知識を着実に吸収することが摩羯座が競争で先を行く方法です。今日自己啓発の機会を逃さないでください。今投資する学びが6ヶ月後にあなたの価値を大きく高めてくれるでしょう。', es: 'Absorber continuamente nuevas habilidades y conocimientos sin volverse complaciente es como Capricornio se mantiene adelante en la competencia. No pierdas las oportunidades de desarrollo personal de hoy. El aprendizaje en el que inviertes ahora elevara enormemente tu valor en seis meses.' },
      { ko: '치밀한 계획이 강점인 염소자리이지만, 모든 계획은 현실 앞에서 수정이 필요한 법입니다. 오늘 계획대로 진행되지 않는 부분이 생기더라도 고집하지 말고 유연하게 방향을 수정해 보세요. 최종 목표가 같다면, 경로는 얼마든지 바뀔 수 있습니다.', en: 'Meticulous planning is Capricorn\'s strength, but every plan needs adjustment when it meets reality. Even if parts don\'t go according to plan today, don\'t persist stubbornly—adjust the direction with flexibility. As long as the final goal is the same, the route can change as many times as needed.', zh: '周密的计划是摩羯座的强项，但任何计划在现实面前都需要调整。即使今天有些部分不按计划进行，也不要固执己见——灵活地调整方向吧。只要最终目标不变，路线可以随时更改。', ja: '綿密な計画が強みの摩羯座ですが、すべての計画は現実の前で修正が必要なものです。今日計画通りに進まない部分が生じても固執せず柔軟に方向を修正してみてください。最終目標が同じなら経路はいくらでも変えることができます。', es: 'La planificacion meticulosa es la fortaleza de Capricornio, pero cada plan necesita ajuste cuando se encuentra con la realidad. Aunque hoy haya partes que no salgan segun lo planeado, no insistas obstinadamente—ajusta la direccion con flexibilidad. Mientras el objetivo final sea el mismo, la ruta puede cambiar tantas veces como sea necesario.' },
      { ko: '화려한 성과나 빠른 결과보다, 지금은 탄탄한 기본기를 다지는 것이 장기적으로 훨씬 더 중요한 투자가 됩니다. 기초가 흔들리면 상부 구조도 무너지지만, 기초가 견고하면 어떤 위기도 버텨낼 수 있습니다. 오늘은 기본에 집중하는 것이 가장 현명한 선택입니다.', en: 'More than flashy results or quick outcomes, solidifying a strong foundation right now is a far more important long-term investment. When the foundation shakes, the superstructure collapses too—but a solid foundation can withstand any crisis. Focusing on the basics today is the wisest choice.', zh: '比起耀眼的成果或快速的结果，眼下夯实基本功才是长期来看更重要的投资。基础动摇，上层建筑也会随之崩塌；但基础牢固，任何危机都能挺过去。今天，专注于基本才是最明智的选择。', ja: '華やかな成果や早い結果より今は堅実な基本を固めることが長期的にずっと重要な投資です。基礎が揺れると上部構造も崩れますが、基礎が堅固なら如何なる危機も耐えられます。今日は基本に集中することが最も賢明な選択です。', es: 'Mas que resultados llamativos o rapidos, consolidar una base solida ahora mismo es una inversion a largo plazo mucho mas importante. Cuando los cimientos se tambalean, la superestructura tambien colapsa—pero una base solida puede resistir cualquier crisis. Enfocarte en los fundamentos hoy es la eleccion mas sabia.' },
      { ko: '쉬지 않고 달리는 것이 생산성을 높인다고 생각하기 쉽지만, 오늘은 업무 중 의식적으로 짧은 휴식을 취하는 것이 오히려 집중력과 효율을 더 높여줍니다. 번아웃은 오지 않을 것처럼 느껴지다가 갑자기 찾아옵니다. 작은 쉼이 큰 붕괴를 막습니다.', en: 'It is easy to think that running without rest increases productivity, but today consciously taking short breaks during work actually boosts your focus and efficiency more. Burnout feels like it will never come until it suddenly does. Small rests prevent large collapses.', zh: '不休息地奔跑看似能提高效率，但今天有意识地在工作中短暂休息，反而能提升专注力与效率。职业倦怠往往让人觉得不会到来，却突然就降临了。小小的休息能防止大崩溃。', ja: '休まずに走ることが生産性を高めると思いがちですが、今日は業務中に意識的に短い休憩を取ることがかえって集中力と効率をより高めます。バーンアウトは来ないと感じながら突然訪れます。小さな休みが大きな崩壊を防ぎます。', es: 'Es facil pensar que correr sin descanso aumenta la productividad, pero hoy tomar descansos cortos conscientemente durante el trabajo en realidad mejora tu enfoque y eficiencia. El agotamiento se siente como si nunca llegara hasta que de repente lo hace. Los pequenos descansos previenen grandes colapsos.' },
      { ko: '당장 눈앞의 결과에 집착하기보다, 오늘 6개월 후의 당신이 어떤 모습이기를 원하는지를 먼저 그려보고 그것을 위한 씨앗을 오늘 심는 자세가 필요합니다. 미래를 내다보는 이 전략적 사고가 바로 염소자리가 다른 별자리보다 더 멀리, 더 높이 가는 이유입니다.', en: 'Rather than fixating on immediate results, today you need the mindset of first picturing what you want to look like six months from now and planting the seeds for that future today. This forward-looking strategic thinking is exactly why Capricorn goes further and higher than other signs.', zh: '与其执着于眼前的结果，今天需要的是先描绘六个月后你希望成为什么样的人，并在今天种下为此而努力的种子的姿态。这种前瞻性的战略思维，正是摩羯座比其他星座走得更远、更高的原因。', ja: '目先の結果に執着するより、今日6ヶ月後の自分がどんな姿でいたいかをまず描き、そのための種を今日まく姿勢が必要です。未来を見据えるこの戦略的思考こそ摩羯座が他の星座より遠くより高く行く理由です。', es: 'Mas que fijarte en los resultados inmediatos, hoy necesitas la mentalidad de primero imaginar como quieres verte en seis meses y plantar las semillas para ese futuro hoy. Este pensamiento estrategico con vision de futuro es exactamente por que Capricornio va mas lejos y mas alto que otros signos.' },
      { ko: '자신을 드러내지 않고 조용히 맡은 바를 성실히 수행할 때, 누군가는 반드시 보고 있고 눈에 보이지 않는 곳에서 기회가 조용히 쌓여갑니다. 조명받지 않아도 꾸준히 하는 것이 염소자리의 방식이며, 그 방식이 결국 가장 큰 열매를 맺습니다. 오늘도 조용히, 하지만 탁월하게.', en: 'When you quietly and faithfully fulfill your duties without putting yourself in the spotlight, someone will always notice and opportunities are quietly accumulating in unseen places. Doing it consistently without recognition is the Capricorn way, and that way ultimately bears the greatest fruit. Quietly today, but with excellence.', zh: '不显山露水地默默履行职责时，总有人在注意，机会也在看不见的地方悄悄积累。不受关注也持续坚持，这是摩羯座的方式，而这种方式最终会结出最丰盛的果实。今天，依然安静，但要卓越。', ja: '自分を前に出さず静かに任された仕事を誠実に遂行する時、誰かは必ず見ており見えないところで機会が静かに積み重なります。注目されなくても続けることが摩羯座のやり方であり、そのやり方が結局最も大きな実を結びます。今日も静かに、しかし卓越して。', es: 'Cuando cumples tus deberes silenciosamente y fielmente sin ponerte en el centro de atencion, alguien siempre lo nota y las oportunidades se acumulan silenciosamente en lugares invisibles. Hacerlo consistentemente sin reconocimiento es la forma de Capricornio, y esa forma en ultima instancia da los mejores frutos. Silenciosamente hoy, pero con excelencia.' },
    ],
    low: [
      { ko: '모든 것을 수용하고 최선을 다하려는 염소자리의 의지가 오늘 업무 과부하로 이어질 수 있습니다. 진정한 프로는 할 수 있는 것과 없는 것을 명확히 구분하고 필요할 때는 거절할 줄 압니다. 오늘 "아니오"라고 말하는 것이 당신의 장기적 성과를 지키는 가장 현명한 결정입니다.', en: 'Capricorn\'s determination to accept everything and give your best may lead to work overload today. A true professional knows how to clearly distinguish what can and cannot be done, and knows how to say no when necessary. Saying no today is the wisest decision to protect your long-term performance.', zh: '摩羯座接受一切、全力以赴的意志，今天可能导致工作过载。真正的专业人士知道如何清晰区分能做和不能做的事，也懂得在必要时说"不"。今天说"不"，是保护你长期绩效的最明智的决定。', ja: 'すべてを受け入れ最善を尽くそうとする摩羯座の意志が今日業務過負荷につながる可能性があります。真のプロはできることとできないことを明確に区別し、必要な時には断ることを知っています。今日「ノー」と言うことがあなたの長期的な成果を守る最も賢明な決断です。', es: 'La determinacion de Capricornio de aceptar todo y dar lo mejor puede llevar hoy a la sobrecarga de trabajo. Un verdadero profesional sabe como distinguir claramente lo que puede y no puede hacerse, y sabe decir que no cuando es necesario. Decir no hoy es la decision mas sabia para proteger tu rendimiento a largo plazo.' },
      { ko: '모든 것을 직접 해야만 직성이 풀리는 염소자리이지만, 오늘은 동료에게 업무를 위임하는 연습이 반드시 필요한 날입니다. 위임은 통제를 포기하는 것이 아니라 팀의 힘을 극대화하는 리더십의 핵심 기술입니다. 오늘 한 가지라도 믿고 맡겨보세요.', en: 'Capricorn typically needs to do everything personally to feel satisfied, but today practicing delegation to colleagues is absolutely necessary. Delegation is not giving up control—it is the core leadership skill of maximizing your team\'s power. Try trusting and handing over at least one thing today.', zh: '摩羯座通常需要亲力亲为才能安心，但今天绝对有必要练习将工作委派给同事。委派不是放弃控制，而是最大化团队力量的核心领导技能。今天，试着信任并交出至少一件事吧。', ja: 'すべてを自分でやらないと気が済まない摩羯座ですが、今日は同僚に業務を委任する練習が絶対に必要な日です。委任はコントロールを手放すことではなく、チームの力を最大化するリーダーシップの核心スキルです。今日一つでも信じて任せてみてください。', es: 'Capricornio tipicamente necesita hacer todo personalmente para sentirse satisfecho, pero hoy practicar la delegacion a colegas es absolutamente necesario. La delegacion no es ceder el control—es la habilidad de liderazgo central para maximizar el poder de tu equipo. Intenta confiar y delegar al menos una cosa hoy.' },
      { ko: '100점을 향한 완벽주의가 오늘 마감일을 위협하고 있습니다. 아무리 완벽한 결과물도 제때 제출되지 않으면 가치를 잃습니다. 오늘만큼은 "완성이 완벽보다 낫다"는 원칙으로 80점짜리를 완성하고 제출하는 용기를 가져보세요.', en: 'Your perfectionism aimed at 100 points is threatening your deadline today. Even the most perfect result loses value if it is not submitted on time. Just for today, have the courage to complete and submit an 80-point result with the principle that done is better than perfect.', zh: '追求满分的完美主义今天正在威胁你的截止日期。再完美的成果，如果不能按时提交，就会失去价值。今天，以"完成胜于完美"的原则，鼓起勇气完成并提交一个80分的成果吧。', ja: '100点を目指す完璧主義が今日締め切りを脅かしています。どんなに完璧な結果物も時間通りに提出されなければ価値を失います。今日だけは「完成は完璧より優れている」という原則で80点のものを完成させ提出する勇気を持ってみてください。', es: 'Tu perfeccionismo apuntando a 100 puntos esta amenazando tu fecha limite hoy. Incluso el resultado mas perfecto pierde valor si no se entrega a tiempo. Solo por hoy, ten el valor de completar y entregar un resultado de 80 puntos con el principio de que hecho es mejor que perfecto.' },
      { ko: '혼자 묵묵히 해내는 것을 미덕으로 여기는 당신이지만, 오늘 상사와의 소통이 부족하면 예상치 못한 오해와 불신이 생길 수 있습니다. 중간 보고는 약함이 아닌 신뢰 구축의 도구입니다. 오늘 간단한 진행 상황 보고 하나가 불필요한 갈등을 예방합니다.', en: 'You value silently getting things done on your own, but today a lack of communication with your boss may create unexpected misunderstandings and distrust. A progress report is not a sign of weakness—it is a tool for building trust. One simple update today prevents unnecessary conflict.', zh: '你视默默独自完成为美德，但今天与上司沟通不足可能引发意想不到的误解和不信任。中期汇报不是软弱的表现，而是建立信任的工具。今天一次简单的进度汇报，能预防不必要的冲突。', ja: '一人で黙々とやり遂げることを美徳とするあなたですが、今日上司とのコミュニケーションが不足すると予想外の誤解や不信が生じる可能性があります。中間報告は弱さではなく信頼構築のツールです。今日簡単な進行状況報告一つが不必要な葛藤を防ぎます。', es: 'Valoras hacer las cosas en silencio por tu cuenta, pero hoy una falta de comunicacion con tu jefe puede crear malentendidos y desconfianza inesperados. Un reporte de progreso no es una senal de debilidad—es una herramienta para construir confianza. Una actualizacion simple hoy previene conflictos innecesarios.' },
      { ko: '익숙한 방식에 대한 고집이 강한 염소자리이지만, 빠르게 변화하는 환경에 적응하지 못하면 결국 뒤처질 수 있습니다. 새로운 방법이나 기술을 위협이 아닌 성장의 기회로 바라보는 열린 마음이 오늘 필요합니다. 변화를 수용하는 유연함이 당신의 강점을 더욱 날카롭게 만들어 줍니다.', en: 'Capricorn\'s attachment to familiar methods is strong, but failing to adapt to a rapidly changing environment will ultimately leave you behind. Today you need an open mind that sees new methods and technologies not as threats but as opportunities for growth. The flexibility to embrace change sharpens your existing strengths even further.', zh: '摩羯座对熟悉方式的坚持很强，但无法适应快速变化的环境，最终会落后。今天你需要一颗开放的心，将新方法和技术视为成长的机会，而非威胁。接受变化的灵活性，会让你的优势更加锋利。', ja: 'なじみのある方法へのこだわりが強い摩羯座ですが、急速に変化する環境に適応できなければ結局遅れをとる可能性があります。新しい方法や技術を脅威ではなく成長の機会と見る開かれた心が今日必要です。変化を受け入れる柔軟さがあなたの強みをさらに鋭くします。', es: 'El apego de Capricornio a los metodos familiares es fuerte, pero no adaptarse a un entorno que cambia rapidamente en ultima instancia te dejara atras. Hoy necesitas una mente abierta que vea los nuevos metodos y tecnologias no como amenazas sino como oportunidades de crecimiento. La flexibilidad para abrazar el cambio agudiza aun mas tus fortalezas existentes.' },
      { ko: '오늘 직장 내 정치적 상황이 당신을 끌어들이려 할 수 있습니다. 이 소용돌이에 휘말리지 말고 냉정하게 거리를 두세요. 단기적인 정치 게임보다 실력과 성과에 집중하는 것이 장기적으로 훨씬 유리하며, 이것이 바로 염소자리가 결국 가장 높이 올라가는 이유입니다.', en: 'Today\'s office political situation may try to pull you in. Keep a cool distance and don\'t get swept up in the swirl. Focusing on skill and results rather than short-term political games is far more advantageous in the long run—and this is precisely why Capricorn ultimately rises the highest.', zh: '今天，职场的政治局面可能会试图将你卷入其中。保持冷静的距离，不要被这股漩涡吞没。比起短期的政治游戏，专注于实力和成果长期来看更加有利——这正是摩羯座最终能爬得最高的原因。', ja: '今日職場の政治的状況があなたを引き込もうとするかもしれません。この渦に巻き込まれず冷静に距離を置いてください。短期的な政治ゲームより実力と成果に集中することが長期的にずっと有利であり、これこそ摩羯座が結局最も高く上がる理由です。', es: 'La situacion politica de la oficina de hoy puede intentar arrastrarte. Mantén una distancia fria y no te dejes llevar por el torbellino. Enfocarte en las habilidades y los resultados en lugar de los juegos politicos a corto plazo es mucho mas ventajoso a largo plazo—y esto es precisamente por que Capricornio en ultima instancia sube mas alto.' },
      { ko: '성공을 향한 야망이 강한 염소자리이지만, 오늘 그 경쟁 의식이 지나쳐 동료와의 소중한 관계를 해칠 위험이 있습니다. 혼자 올라가는 것보다 함께 올라가는 것이 더 멀리, 더 오래 간다는 것을 기억하세요. 협력은 경쟁을 포기하는 것이 아니라 더 큰 승리를 향한 전략입니다.', en: 'Capricorn\'s ambition for success is strong, but today there is a risk that excessive competitiveness will damage precious relationships with colleagues. Remember that going up together goes further and lasts longer than climbing alone. Cooperation is not giving up on winning—it is a strategy toward a bigger victory.', zh: '摩羯座对成功的野心很强，但今天过度的竞争意识有损害与同事珍贵关系的风险。记住，携手前进比单独攀登走得更远、更持久。合作不是放弃竞争，而是迈向更大胜利的战略。', ja: '成功への野望が強い摩羯座ですが、今日その競争意識が行き過ぎて同僚との大切な関係を損なう危険があります。一人で上がるよりも一緒に上がることがより遠くより長く続くことを覚えておいてください。協力は競争を諦めることではなく、より大きな勝利への戦略です。', es: 'La ambicion de Capricornio por el exito es fuerte, pero hoy hay un riesgo de que la competitividad excesiva danie relaciones preciosas con colegas. Recuerda que subir juntos va mas lejos y dura mas tiempo que escalar solo. La cooperacion no es renunciar a ganar—es una estrategia hacia una victoria mayor.' },
      { ko: '빠른 성과를 원하는 조급함이 오늘 당신의 냉철한 판단력을 흐리게 만들고 있습니다. 급하게 내린 결정은 나중에 더 큰 대가를 치르는 법입니다. 한 발 물러서서 더 넓은 시야로 상황을 바라보면, 지금 보이지 않던 더 나은 선택지가 반드시 보일 것입니다.', en: 'Your impatience for quick results is clouding your usually sharp judgment today. Rushed decisions often cost far more later. Step back and look at the situation from a wider view—a better option that is currently invisible to you will definitely become visible from there.', zh: '急于求成的心态正在让你平日里冷静的判断力变得模糊。仓促的决定往往日后要付出更大代价。退一步，从更宏观的视角看看情况——那个你目前看不到的更好选项，一定会从那里显现出来。', ja: '早い成果を望む焦りが今日あなたの鋭い判断力を曇らせています。急いで下した決定は後でより大きな代価を払うことになります。一歩引いてより広い視野で状況を見れば、今は見えていないより良い選択肢が必ず見えてくるでしょう。', es: 'Tu impaciencia por resultados rapidos esta nublando tu habitualmente agudo juicio hoy. Las decisiones precipitadas a menudo cuestan mucho mas despues. Da un paso atras y mira la situacion desde una vista mas amplia—una mejor opcion que actualmente es invisible para ti definitivamente se volvera visible desde ahi.' },
      { ko: '강한 리더십을 발휘하려는 의지가 때로는 권위적인 태도로 나타나 팀의 사기와 창의성을 떨어뜨릴 수 있습니다. 오늘은 지시하기 전에 먼저 경청하는 자세를 취해보세요. 팀원의 목소리를 진심으로 듣는 리더가 결국 가장 강한 팀을 만들어 냅니다.', en: 'The will to exert strong leadership can sometimes come across as authoritarian, lowering the team\'s morale and creativity. Today, before giving directives, take the posture of listening first. A leader who genuinely hears their team members\' voices ultimately builds the strongest team.', zh: '展现强势领导力的意志，有时会以权威姿态出现，降低团队的士气和创造力。今天，在下达指令之前，先采取倾听的姿态吧。真诚倾听团队成员声音的领导者，最终能打造出最强大的团队。', ja: '強いリーダーシップを発揮しようとする意志が時には権威的な態度として現れ、チームの士気と創造性を下げる可能性があります。今日は指示する前にまず傾聴する姿勢を取ってみてください。チームメンバーの声を心から聴くリーダーが結局最も強いチームを作り出します。', es: 'La voluntad de ejercer un liderazgo fuerte a veces puede percibirse como autoritaria, bajando la moral y la creatividad del equipo. Hoy, antes de dar directivas, adopta la postura de escuchar primero. Un lider que genuinamente escucha las voces de los miembros de su equipo en ultima instancia construye el equipo mas fuerte.' },
      { ko: '일에서 자신의 가치를 찾는 경향이 강한 염소자리이지만, 오늘 업무 외의 시간에 자신을 돌보는 것을 소홀히 하면 곧 더 큰 피로와 공허함이 찾아올 수 있습니다. 일은 삶의 중요한 부분이지만 전부는 아닙니다. 오늘 퇴근 후, 자신을 위한 시간을 의식적으로 만들어보세요.', en: 'Capricorn strongly tends to find self-worth in work, but neglecting to care for yourself outside of work today will soon bring greater fatigue and emptiness. Work is an important part of life but not all of it. After finishing work today, consciously create time just for yourself.', zh: '摩羯座有从工作中寻找自我价值的强烈倾向，但今天忽视在工作之外照顾自己，很快就会带来更大的疲惫与空虚。工作是生活的重要部分，但不是全部。今天下班后，有意识地为自己创造一段属于自己的时间吧。', ja: '仕事に自分の価値を見出す傾向が強い摩羯座ですが、今日業務外の時間に自分を労わることを怠るとすぐにより大きな疲れと空虚感が訪れる可能性があります。仕事は人生の重要な部分ですがすべてではありません。今日退勤後、自分のための時間を意識的に作ってみてください。', es: 'Capricornio tiende fuertemente a encontrar su valor en el trabajo, pero descuidar el autocuidado fuera del trabajo hoy pronto traera mayor fatiga y vacio. El trabajo es una parte importante de la vida pero no lo es todo. Despues de terminar el trabajo hoy, crea conscientemente tiempo solo para ti.' },
    ],
  },
  health: {
    high: [
      { ko: '규칙적인 생활 습관을 꾸준히 유지해 온 당신의 노력이 오늘 몸 전체에서 느껴지는 가벼움과 활력으로 보답받고 있습니다. 이 좋은 컨디션은 우연이 아니라 당신이 쌓아온 자기 관리의 결실입니다. 이 흐름을 이어가는 것에 집중하고 새로운 건강 목표를 설정해 보세요.', en: 'The effort you have consistently put into maintaining a regular lifestyle is being rewarded today through a lightness and vitality felt throughout your whole body. This great condition is not coincidence—it is the fruit of the self-care you have built up. Focus on continuing this momentum and set a new health goal.', zh: '你坚持保持规律生活习惯的努力，今天以全身感受到的轻盈与活力给予了回报。这种良好的状态不是偶然，而是你长期自我管理的成果。专注于延续这股势头，并为自己设定一个新的健康目标吧。', ja: '規則的な生活習慣を着実に維持してきたあなたの努力が今日体全体で感じられる軽さと活力で報われています。この良いコンディションは偶然ではなく、あなたが積み上げてきた自己管理の成果です。この流れを続けることに集中し新しい健康目標を設定してみてください。', es: 'El esfuerzo que has puesto consistentemente en mantener un estilo de vida regular se recompensa hoy a traves de una ligereza y vitalidad sentida en todo tu cuerpo. Esta excelente condicion no es coincidencia—es el fruto del autocuidado que has acumulado. Enfocate en continuar este impulso y establece una nueva meta de salud.' },
      { ko: '오늘은 등산이나 트레킹처럼 인내와 지구력을 요하는 운동에서 다른 어느 때보다 큰 활력과 성취감을 얻을 수 있습니다. 염소자리의 에너지는 단거리 스프린트보다 장거리 마라톤에서 더 빛납니다. 오늘 야외로 나가 몸을 움직이면 정신적 명료함까지 동시에 얻게 됩니다.', en: 'Today you can gain greater vitality and a deeper sense of achievement from endurance-requiring exercises like hiking or trekking than at any other time. Capricorn\'s energy shines more brightly in a long-distance marathon than a short-distance sprint. Get outside and move your body today—you will gain mental clarity as well.', zh: '今天，从登山或徒步旅行等需要耐力和毅力的运动中，你能获得比任何时候都更大的活力与成就感。摩羯座的能量在长距离马拉松中比短距离冲刺更加闪耀。今天走出户外活动身体，你同时也将获得精神上的清明。', ja: '今日は登山やトレッキングのように忍耐と持久力を要する運動で、これまでのどの時よりも大きな活力と達成感を得られます。摩羯座のエネルギーは短距離スプリントよりも長距離マラソンでより輝きます。今日外に出て体を動かせば精神的な明晰さまで同時に得られます。', es: 'Hoy puedes obtener mayor vitalidad y un sentido mas profundo de logro de ejercicios que requieren resistencia como senderismo o trekking que en cualquier otro momento. La energia de Capricornio brilla mas en un maraton de larga distancia que en un sprint corto. Sal afuera y mueve tu cuerpo hoy—obtendras claridad mental tambien.' },
      { ko: '염소자리가 주관하는 뼈와 관절 건강이 지금 안정적인 상태에 있습니다. 이 건강한 기반 위에서 체력을 더욱 비축하고 근력을 강화하기 좋은 최적의 시기입니다. 꾸준한 스트레칭과 적절한 근력 운동을 추가하면 이 좋은 상태를 더 오래 유지할 수 있습니다.', en: 'The bones and joints governed by Capricorn are in stable condition right now. This is an ideal time to build up even more stamina and strengthen muscles on this healthy foundation. Adding consistent stretching and appropriate strength training will help maintain this good state for longer.', zh: '摩羯座所主管的骨骼和关节健康目前处于稳定状态。这是在这个健康基础上进一步储备体力、强化肌肉的最佳时机。加入持续的拉伸和适当的力量训练，能让这种良好状态保持更长时间。', ja: '摩羯座が管轄する骨と関節の健康が今安定した状態にあります。この健康な基盤の上でさらに体力を蓄え筋力を強化するのに最適な時期です。継続的なストレッチと適切な筋力運動を加えればこの良い状態をより長く維持できます。', es: 'Los huesos y articulaciones que gobierna Capricornio estan en condicion estable ahora mismo. Este es el momento ideal para acumular aun mas resistencia y fortalecer musculos sobre esta base saludable. Agregar estiramientos consistentes y entrenamiento de fuerza apropiado ayudara a mantener este buen estado por mas tiempo.' },
      { ko: '포기하지 않고 꾸준히 유지해 온 건강 습관들이 오늘 당신의 면역력 향상과 전반적인 건강 지수 상승으로 이어지고 있습니다. 건강은 결코 하루아침에 만들어지지 않으며, 당신이 매일 작게 실천한 것들이 지금 이 결과를 만들었습니다. 이 긍정적인 루프를 더욱 강화하세요.', en: 'The health habits you have kept without giving up are today leading to improved immunity and a rise in your overall health indicators. Good health is never built overnight—it is what you practiced in small ways every day that created these results. Reinforce this positive loop even more.', zh: '你坚持不懈保持的健康习惯，今天正在为你带来免疫力提升和整体健康指数上升。健康从来不是一朝一夕建立的——是你每天坚持的小实践造就了现在的结果。进一步强化这个积极的循环吧。', ja: 'あきらめずに着実に維持してきた健康習慣が今日あなたの免疫力向上と全体的な健康指数の上昇につながっています。健康は決して一夜にして作られず、毎日小さく実践してきたことが今この結果を作り出しました。このポジティブなループをさらに強化してください。', es: 'Los habitos de salud que has mantenido sin rendirte hoy estan llevando a una mejor inmunidad y un aumento en tus indicadores generales de salud. La buena salud nunca se construye de la noche a la manana—es lo que practicaste de maneras pequenas cada dia lo que creo estos resultados. Refuerza aun mas este ciclo positivo.' },
      { ko: '오늘은 몸과 마음이 특별히 잘 조화를 이루어 내면 에너지가 넘치는 날입니다. 이 조화의 날을 그냥 지나치기 아깝습니다. 새로운 운동 루틴을 시작하거나 오랫동안 도전해 보고 싶었던 신체 활동을 시작하기에 이보다 좋은 날은 없습니다. 지금 시작하세요.', en: 'Today mind and body are in exceptionally good harmony, and inner energy is overflowing. It would be a waste to let this harmonious day pass by. There is no better day to start a new exercise routine or begin a physical activity you have wanted to try for a long time. Start now.', zh: '今天身心处于特别和谐的状态，内在能量充沛。让这个和谐的日子就这样流逝太可惜了。没有比今天更好的日子来开始新的运动习惯，或尝试那项你长久以来一直想挑战的身体活动。现在就开始吧。', ja: '今日は心身が特に良く調和し内なるエネルギーが溢れる日です。この調和の日をただ過ごすのはもったいないです。新しい運動ルーティンを始めたり、長い間挑戦してみたかった身体活動を始めるにはこれ以上良い日はありません。今始めてください。', es: 'Hoy mente y cuerpo estan en una armonia excepcionalmente buena, y la energia interior desborda. Seria una lastima dejar pasar este dia armonioso. No hay mejor dia para comenzar una nueva rutina de ejercicio o iniciar una actividad fisica que has querido probar por mucho tiempo. Empieza ahora.' },
      { ko: '적절히 절제된 식단을 유지하는 당신의 노력이 오늘 최상의 컨디션으로 보답받고 있습니다. 이 자기 관리 능력이야말로 염소자리만이 가진 진정한 강점 중 하나이며, 충분히 자랑스러워할 자격이 있습니다. 오늘의 좋은 컨디션을 바탕으로 더욱 도전적인 목표에 나서보세요.', en: 'Your effort to maintain a properly disciplined diet is being rewarded today with optimal condition. This capacity for self-management is one of the true strengths unique to Capricorn, and you have every right to be proud of it. Use today\'s excellent condition as the basis to take on more challenging goals.', zh: '你保持适度节制饮食的努力，今天以最佳状态给予了回报。这种自我管理的能力，正是摩羯座独有的真正强项之一，你完全有资格为此感到自豪。以今天的良好状态为基础，去挑战更有难度的目标吧。', ja: '適切に節制された食事を維持するあなたの努力が今日最高のコンディションで報われています。この自己管理能力こそ摩羯座だけが持つ真の強みの一つであり、十分に誇れる資格があります。今日の良いコンディションを基盤にしてより挑戦的な目標に挑んでみてください。', es: 'Tu esfuerzo por mantener una dieta apropiadamente disciplinada se recompensa hoy con una condicion optima. Esta capacidad de autogestion es una de las fortalezas verdaderas unicas de Capricornio, y tienes todo el derecho de estar orgulloso/a de ella. Usa la excelente condicion de hoy como base para asumir metas mas desafiantes.' },
      { ko: '내면의 정신적 안정감이 신체적 건강까지 끌어올리는 아름다운 선순환이 지금 당신의 삶 안에서 돌아가고 있습니다. 몸과 마음은 결코 분리되어 있지 않으며, 오늘은 그 연결이 가장 선명하게 느껴지는 날입니다. 이 선순환이 더욱 강해지도록 명상이나 자연과의 접촉을 더해보세요.', en: 'A beautiful virtuous cycle in which mental stability elevates even physical health is running inside your life right now. Body and mind are never separate, and today is the day you feel that connection most clearly. Add meditation or contact with nature to make this virtuous cycle even stronger.', zh: '内心精神稳定带动身体健康提升的美好良性循环，正在你的生活中运转。身心从未分离，今天正是你最清晰地感受到这种连结的日子。加入冥想或与自然的接触，让这个良性循环变得更强吧。', ja: '内面の精神的な安定感が身体的な健康まで引き上げる美しい好循環が今あなたの人生の中で回っています。体と心は決して切り離されておらず、今日はその繋がりが最も鮮明に感じられる日です。この好循環がさらに強くなるよう瞑想や自然との接触を加えてみてください。', es: 'Un hermoso ciclo virtuoso en el que la estabilidad mental eleva incluso la salud fisica esta corriendo dentro de tu vida ahora mismo. Cuerpo y mente nunca estan separados, y hoy es el dia en que sientes esa conexion mas claramente. Agrega meditacion o contacto con la naturaleza para hacer este ciclo virtuoso aun mas fuerte.' },
      { ko: '오랫동안 당신을 괴롭혀 온 건강 고민이 오늘 해결의 실마리를 찾을 수 있는 날입니다. 혼자 해결하려 했다면 오늘은 전문가 상담을 통해 더 명확한 방향을 얻어보세요. 건강에 관해서는 자존심보다 지혜로운 도움 요청이 더 중요한 용기입니다.', en: 'A health concern that has troubled you for a long time may find a clue to resolution today. If you have been trying to solve it alone, today is the day to gain clearer direction through professional consultation. When it comes to health, seeking wise help is more important courage than pride.', zh: '长久困扰你的健康问题，今天可能找到解决的线索。如果你一直独自尝试解决，今天就通过专业咨询获得更明确的方向吧。在健康问题上，寻求明智的帮助比自尊更需要勇气，也更重要。', ja: '長い間あなたを悩ませてきた健康の悩みが今日解決の糸口を見つけられる日です。一人で解決しようとしていたなら、今日は専門家への相談を通じてより明確な方向性を得てみてください。健康に関しては自尊心より賢明な助けを求めることがより重要な勇気です。', es: 'Un problema de salud que te ha preocupado durante mucho tiempo puede encontrar una pista de solucion hoy. Si has estado tratando de resolverlo solo, hoy es el dia de obtener una direccion mas clara a traves de consulta profesional. Cuando se trata de salud, buscar ayuda sabia es un valor mas importante que el orgullo.' },
      { ko: '오늘 체력과 정신력이 모두 최고조에 달해 무엇이든 도전할 수 있는 황금 상태입니다. 이런 날은 흔하지 않으며, 오랫동안 미루어 두었던 도전적인 목표를 향해 첫 발걸음을 내딛기에 완벽한 순간입니다. 두려움 없이 나서세요—당신의 몸과 마음이 오늘은 당신의 편입니다.', en: 'Today both your stamina and mental strength peak, placing you in a golden state where you can take on anything. Days like this are rare, and it is the perfect moment to take the first step toward a challenging goal you have long postponed. Step forward without fear—your body and mind are on your side today.', zh: '今天体力和精神力都达到最高峰，你处于一种可以挑战任何事情的黄金状态。这样的日子并不多见，正是迈出向长久以来搁置的挑战性目标踏出第一步的完美时机。无所畏惧地迈出去——你的身心今天都站在你这边。', ja: '今日体力と精神力の両方が最高潮に達し、何でも挑戦できるゴールデンな状態です。こんな日は珍しく、長い間先送りにしていた挑戦的な目標に向けて最初の一歩を踏み出すのに完璧な瞬間です。恐れずに踏み出してください。あなたの体と心が今日はあなたの味方です。', es: 'Hoy tanto tu resistencia como tu fuerza mental alcanzan su punto maximo, colocandote en un estado dorado donde puedes enfrentar cualquier cosa. Dias como este son raros, y es el momento perfecto para dar el primer paso hacia una meta desafiante que has postergado por mucho tiempo. Da el paso sin miedo—tu cuerpo y mente estan de tu lado hoy.' },
      { ko: '오늘 자연 속에서 시간을 보내면 몸과 마음 모두에서 다른 어떤 방법으로도 얻기 힘든 깊고 근본적인 회복이 이루어집니다. 흙의 별자리인 염소자리는 대지와 연결될 때 가장 강해집니다. 짧은 시간이라도 야외에 나가 자연의 에너지를 온몸으로 받아들이세요.', en: 'Spending time in nature today brings both body and mind a deep, fundamental recovery difficult to obtain through any other means. Capricorn, an earth sign, becomes strongest when connected to the ground. Even for a short time, go outdoors and receive nature\'s energy with your whole body.', zh: '今天在大自然中度过时光，身心都能获得其他任何方式都难以达到的深层、根本性的恢复。作为土象星座的摩羯座，与大地连结时最为强大。哪怕只是短暂的时间，也走到户外，用全身接受自然的能量吧。', ja: '今日自然の中で時間を過ごすと心身の両方で他のどんな方法でも得難い深く根本的な回復が得られます。大地の星座である摩羯座は大地と繋がる時が最も強くなります。短い時間でも屋外に出て自然のエネルギーを全身で受け取ってください。', es: 'Pasar tiempo en la naturaleza hoy trae tanto al cuerpo como a la mente una recuperacion profunda y fundamental dificil de obtener por cualquier otro medio. Capricornio, un signo de tierra, se vuelve mas fuerte cuando esta conectado a la tierra. Aunque sea por poco tiempo, sal afuera y recibe la energia de la naturaleza con todo tu cuerpo.' },
    ],
    medium: [
      { ko: '오늘은 과도한 운동 대신 무리하지 않는 범위에서 꾸준히 몸을 움직이는 것이 현명합니다. 매일 걷는 것만으로도 심혈관 건강, 스트레스 해소, 관절 유연성에 놀라운 효과를 가져다줍니다. 완벽한 운동보다 지속 가능한 일상 활동이 장기적으로 훨씬 큰 건강 효과를 줍니다.', en: 'Today it is wise to keep moving steadily within comfortable limits rather than excessive exercise. Just walking every day brings remarkable benefits for cardiovascular health, stress relief, and joint flexibility. Sustainable daily activity gives far greater long-term health benefits than any single perfect workout.', zh: '今天，明智的做法是在不勉强的范围内持续活动身体，而非过度运动。每天只是散步，就能为心血管健康、压力释放和关节灵活性带来显著效果。持续的日常活动比任何单次完美的锻炼都能带来更大的长期健康收益。', ja: '今日は過度な運動の代わりに無理しない範囲で着実に体を動かすことが賢明です。毎日歩くだけでも心血管の健康、ストレス解消、関節の柔軟性に驚くほどの効果をもたらします。完璧な運動より持続可能な日常活動が長期的にずっと大きな健康効果を与えます。', es: 'Hoy es sabio seguir moviendote firmemente dentro de limites comodos en lugar de ejercicio excesivo. Solo caminar cada dia trae beneficios notables para la salud cardiovascular, el alivio del estres y la flexibilidad articular. La actividad diaria sostenible da beneficios de salud a largo plazo mucho mayores que cualquier entrenamiento perfecto unico.' },
      { ko: '오늘은 의식적으로 자세를 바르게 유지하고 규칙적으로 스트레칭을 챙기세요. 염소자리가 주관하는 허리와 무릎은 잘못된 자세와 과부하에 특히 취약하므로 오늘 각별히 신경 써야 합니다. 2시간마다 잠깐 일어나 몸을 풀어주는 것만으로도 큰 차이가 생깁니다.', en: 'Today consciously maintain good posture and stretch regularly. The back and knees governed by Capricorn are especially vulnerable to poor posture and overload, so pay particular attention today. Just standing up and loosening your body every two hours makes a big difference.', zh: '今天有意识地保持正确姿势，并定期做好拉伸。摩羯座所主管的腰部和膝盖对不良姿势和过度负荷特别敏感，今天需要格外注意。每两小时起身活动一下筋骨，就能带来很大的改变。', ja: '今日は意識的に正しい姿勢を保ちこまめにストレッチをしてください。摩羯座が管轄する腰と膝は悪い姿勢と過負荷に特に弱いので今日は格別に注意が必要です。2時間ごとに少し立ち上がって体をほぐすだけでも大きな違いが生まれます。', es: 'Hoy mantén conscientemente buena postura y estira regularmente. La espalda y las rodillas que gobierna Capricornio son especialmente vulnerables a la mala postura y la sobrecarga, asi que presta especial atencion hoy. Solo levantarte y aflojar tu cuerpo cada dos horas marca una gran diferencia.' },
      { ko: '오늘 영양이 잘 균형 잡힌 식사가 당신의 안정적인 컨디션을 유지하는 가장 중요한 열쇠입니다. 건강한 식단은 에너지를 공급할 뿐 아니라 집중력과 기분도 안정시켜 줍니다. 화려하지 않아도 되니, 오늘 끼니를 거르지 말고 영양소를 고루 갖춘 간단한 식사를 챙겨 드세요.', en: 'Today nutritionally balanced meals are the most important key to maintaining your stable condition. A healthy diet not only supplies energy but also stabilizes concentration and mood. It doesn\'t need to be elaborate—just make sure not to skip meals today and have simple, well-rounded nutritious food.', zh: '今天，营养均衡的饮食是维持你稳定状态最重要的关键。健康的饮食不仅供给能量，还能稳定专注力和情绪。不需要精心准备——今天不要跳过任何一餐，吃一顿营养均衡的简单饮食就好。', ja: '今日は栄養バランスの取れた食事があなたの安定したコンディションを維持する最も重要な鍵です。健康的な食事はエネルギーを供給するだけでなく集中力と気分も安定させます。華やかでなくていいので、今日食事を抜かずに栄養素をまんべんなく含む簡単な食事を摂ってください。', es: 'Hoy las comidas nutricionalmente equilibradas son la clave mas importante para mantener tu condicion estable. Una dieta saludable no solo suministra energia sino que tambien estabiliza la concentracion y el estado de animo. No necesita ser elaborada—solo asegurate de no saltarte comidas hoy y tener alimentos nutritivos simples y equilibrados.' },
      { ko: '수면 패턴을 일정하게 유지하는 것이 다음 날의 집중력, 기분, 효율 모두를 결정합니다. 오늘 밤 정해진 시간에 잠자리에 들고 스마트폰을 멀리하는 작은 실천이 내일의 당신에게 줄 수 있는 최고의 선물입니다. 수면을 전략적으로 관리하는 것이 성과자의 비밀입니다.', en: 'Keeping a consistent sleep pattern determines your next day\'s focus, mood, and efficiency altogether. Going to bed at a fixed time tonight and putting your smartphone away is the best gift you can give your tomorrow self. Strategically managing sleep is the secret of high performers.', zh: '保持规律的睡眠模式，决定了第二天的专注力、心情和效率。今晚在固定时间就寝，把手机放到一边，这是你能给明天的自己的最好礼物。战略性地管理睡眠，是高绩效者的秘密。', ja: '睡眠パターンを一定に保つことが翌日の集中力、気分、効率すべてを決定します。今夜定められた時間に就寝しスマートフォンを遠ざける小さな実践が明日の自分に与えられる最高の贈り物です。睡眠を戦略的に管理することが成果を上げる人の秘密です。', es: 'Mantener un patron de sueno consistente determina el enfoque, el estado de animo y la eficiencia del dia siguiente en conjunto. Acostarte a una hora fija esta noche y alejar tu smartphone es el mejor regalo que puedes darle a tu yo de manana. Gestionar el sueno estrategicamente es el secreto de los de alto rendimiento.' },
      { ko: '오늘은 피부 관리에 더욱 신경 쓸 좋은 시기입니다. 특히 보습을 철저히 하고 자외선 차단을 챙기세요. 피부 건강은 내면의 수분 섭취와 수면의 질과도 직결되므로, 물을 충분히 마시는 것도 잊지 마세요. 외면을 돌보는 것이 내면의 자기 존중과 연결됩니다.', en: 'Today is a good time to pay extra attention to skincare. Moisturize thoroughly and make sure to apply sun protection. Skin health is also directly connected to internal hydration and sleep quality, so don\'t forget to drink enough water. Taking care of your outer self connects to inner self-respect.', zh: '今天是更加注重皮肤护理的好时机。特别要做好保湿，注意防晒。皮肤健康与体内水分摄取和睡眠质量直接相关，所以不要忘记充分补水。照顾外在的自己，与内在的自我尊重息息相关。', ja: '今日は特にスキンケアに気を配ると良い時期です。保湿を徹底し日焼け止めも忘れずに。肌の健康は体内の水分摂取と睡眠の質とも直結するので、水を十分に飲むことも忘れないでください。外見を気遣うことが内面の自己尊重に繋がります。', es: 'Hoy es un buen momento para prestar atencion extra al cuidado de la piel. Hidrata a fondo y asegurate de aplicar proteccion solar. La salud de la piel tambien esta directamente conectada con la hidratacion interna y la calidad del sueno, asi que no olvides beber suficiente agua. Cuidar tu exterior se conecta con el autorrespeto interior.' },
      { ko: '오늘 카페인 섭취를 줄이고 대신 따뜻한 차를 마셔보세요. 카페인에 의존하는 집중력 대신 자연스러운 내면 에너지를 활성화하는 방향으로 전환하면 더 안정적이고 지속적인 집중 상태를 유지할 수 있습니다. 녹차, 생강차, 루이보스 등을 시도해 보세요.', en: 'Today try reducing caffeine intake and drinking warm tea instead. Shifting away from caffeine-dependent focus toward activating your natural inner energy allows you to maintain a more stable and sustained concentration. Try green tea, ginger tea, or rooibos.', zh: '今天试着减少咖啡因摄入，改喝温热的茶。从依赖咖啡因的专注力，转向激活自然内在能量的方向，能让你维持更稳定、更持续的专注状态。可以尝试绿茶、姜茶或路易波士茶。', ja: '今日はカフェインの摂取を減らして代わりに温かいお茶を飲んでみてください。カフェインに依存した集中力から自然な内なるエネルギーを活性化する方向に転換すれば、より安定した持続的な集中状態を維持できます。緑茶、生姜茶、ルイボスなどを試してみてください。', es: 'Hoy intenta reducir la ingesta de cafeina y beber te caliente en su lugar. Cambiar de una concentracion dependiente de la cafeina hacia activar tu energia interior natural te permite mantener un estado de concentracion mas estable y sostenido. Prueba te verde, te de jengibre o rooibos.' },
      { ko: '치과 정기 검진을 계속 미루어 왔다면 오늘이 바로 예약을 잡을 적기입니다. 구강 건강은 전신 건강과 연결되어 있으며, 작은 문제를 조기에 발견하면 훨씬 적은 비용과 시간으로 해결할 수 있습니다. 염소자리의 현명한 예방 정신을 발휘해보세요.', en: 'If you have been putting off dental checkups, today is the right time to make an appointment. Oral health is connected to whole-body health, and catching small problems early can solve them at far less cost and time. Exercise Capricorn\'s wise spirit of prevention.', zh: '如果你一直推迟牙科定期检查，今天正是预约的好时机。口腔健康与全身健康息息相关，早期发现小问题可以以更少的费用和时间解决。发挥摩羯座明智的预防精神吧。', ja: '歯科の定期検診をずっと先延ばしにしているなら今日がちょうど予約を取る適切な時です。口腔の健康は全身の健康と繋がっており、小さな問題を早期に発見すればずっと少ないコストと時間で解決できます。摩羯座の賢明な予防精神を発揮してみてください。', es: 'Si has estado posponiendo los chequeos dentales, hoy es el momento adecuado para hacer una cita. La salud oral esta conectada con la salud de todo el cuerpo, y detectar problemas pequenos temprano puede resolverlos a un costo y tiempo mucho menor. Ejerce el sabio espiritu de prevencion de Capricornio.' },
      { ko: '대단한 결심이나 복잡한 계획 없이도 일상 속 아주 작은 건강 루틴 하나가 시간이 지남에 따라 놀라운 차이를 만들어냅니다. 엘리베이터 대신 계단 오르기 같은 단순한 선택부터 시작하세요. 염소자리는 작게 시작하지만 멈추지 않는 자이며, 그것이 결국 가장 강한 방식입니다.', en: 'Without any grand resolution or complex plan, one very small daily health routine makes a remarkable difference over time. Start with simple choices like taking the stairs instead of the elevator. Capricorn is someone who starts small but never stops, and that is ultimately the strongest approach.', zh: '不需要宏大的决心或复杂的计划，日常中一个极小的健康习惯，随着时间积累会带来惊人的改变。从走楼梯代替坐电梯这样简单的选择开始吧。摩羯座是那个从小处着手却永不停歇的人，这最终是最强大的方式。', ja: '大きな決意や複雑な計画なしでも日常の非常に小さな健康ルーティン一つが時間とともに驚くほどの違いを生み出します。エレベーターの代わりに階段を使うような単純な選択から始めてください。摩羯座は小さく始めるが止まらない者であり、それが結局最も強い方法です。', es: 'Sin ninguna gran resolucion ni plan complejo, una rutina de salud muy pequena del dia a dia hace una diferencia notable con el tiempo. Comienza con elecciones simples como subir escaleras en lugar del ascensor. Capricornio es alguien que comienza pequeno pero nunca se detiene, y ese es en ultima instancia el enfoque mas fuerte.' },
      { ko: '오늘 몸이 보내는 스트레스 신호를 결코 무시하지 마세요. 특히 목과 어깨의 긴장이 누적되면 두통이나 더 심각한 근골격계 문제로 이어질 수 있습니다. 지금 잠깐 멈추고 목을 천천히 돌리며 어깨를 풀어주세요. 당신의 몸은 언제나 먼저 경고를 보냅니다.', en: 'Today, never ignore the stress signals your body sends. Particularly, accumulating tension in the neck and shoulders can lead to headaches or more serious musculoskeletal issues. Pause right now and slowly roll your neck and release your shoulders. Your body always sends warnings first.', zh: '今天，绝对不要忽视身体发出的压力信号。尤其是颈部和肩部的紧张积累，可能导致头痛或更严重的肌肉骨骼问题。现在暂停一下，慢慢转动脖子，放松肩膀。你的身体总是会提前发出警告。', ja: '今日体が送るストレスのサインを決して無視しないでください。特に首と肩の緊張が蓄積すると頭痛やより深刻な筋骨格系の問題につながる可能性があります。今すぐ少し止まって首をゆっくり回し肩をほぐしてください。あなたの体は常に先に警告を発します。', es: 'Hoy nunca ignores las senales de estres que tu cuerpo envia. Particularmente, acumular tension en el cuello y los hombros puede llevar a dolores de cabeza o problemas musculoesqueleticos mas serios. Haz una pausa ahora mismo y gira lentamente el cuello y suelta los hombros. Tu cuerpo siempre envia advertencias primero.' },
      { ko: '화려한 식단 변화 없이도 규칙적인 식사 시간을 지키는 것만으로 소화 기능이 눈에 띄게 개선되고 에너지 흐름이 안정됩니다. 몸은 패턴을 좋아하고 예측 가능한 리듬 속에서 가장 잘 기능합니다. 오늘부터 식사 시간을 정하고 그것을 지키는 작은 습관을 만들어보세요.', en: 'Without any elaborate diet change, just keeping regular meal times visibly improves digestion and stabilizes energy flow. The body loves patterns and functions best within predictable rhythms. Starting today, set meal times and build the small habit of keeping them.', zh: '不需要华丽的饮食改变，仅仅保持规律的用餐时间，就能明显改善消化功能，稳定能量流动。身体喜欢规律，在可预测的节奏中运作最佳。从今天开始，制定用餐时间，养成坚持遵守的小习惯吧。', ja: '派手な食事の変化なしでも規則的な食事時間を守るだけで消化機能が目に見えて改善されエネルギーの流れが安定します。体はパターンを好み予測可能なリズムの中で最もうまく機能します。今日から食事時間を定めてそれを守る小さな習慣を作ってみてください。', es: 'Sin ningun cambio elaborado de dieta, solo mantener horarios regulares de comida mejora visiblemente la digestion y estabiliza el flujo de energia. El cuerpo ama los patrones y funciona mejor dentro de ritmos predecibles. A partir de hoy, establece horarios de comida y construye el pequeno habito de mantenerlos.' },
    ],
    low: [
      { ko: '당신의 몸 안에 과로가 조용히 누적되고 있으며, 이 경고를 무시하면 나중에 훨씬 더 큰 대가를 치르게 됩니다. 지금 잠깐 쉬는 것은 나약함이 아니라 장기전을 준비하는 현명한 전략입니다. 오늘 의무적으로 한 가지 완전한 휴식 시간을 만들어 보세요.', en: 'Overwork is quietly accumulating in your body, and ignoring this warning will cost you a far greater price later. Taking a short rest right now is not weakness—it is a wise strategy for preparing for the long game. Deliberately create one full rest period today.', zh: '你体内的过劳正在悄悄积累，忽视这个警告，日后将付出更大的代价。现在稍作休息不是软弱，而是为长期战做准备的明智策略。今天务必为自己创造一段完整的休息时间。', ja: 'あなたの体の中に過労が静かに蓄積しており、この警告を無視するとあとでずっと大きな代価を払うことになります。今少し休むことは弱さではなく長期戦を準備する賢明な戦略です。今日義務的に一つの完全な休憩時間を作ってみてください。', es: 'El exceso de trabajo se acumula silenciosamente en tu cuerpo, e ignorar esta advertencia te costara un precio mucho mayor despues. Descansar un poco ahora no es debilidad—es una estrategia sabia para prepararse para el juego largo. Crea deliberadamente un periodo de descanso completo hoy.' },
      { ko: '오늘 염소자리가 다스리는 무릎과 관절에 예상치 못한 무리가 갈 수 있습니다. 격한 운동은 오늘만큼은 삼가고 스트레칭이나 가벼운 걷기로 대체하세요. 무리하면 회복에 더 긴 시간이 필요하며, 지금 잠깐 쉬는 것이 장기적 건강을 지키는 최선의 선택입니다.', en: 'Today unexpected strain may come to the knees and joints governed by Capricorn. Just for today, avoid intense exercise and replace it with stretching or light walking. Pushing through will require a longer recovery time, and a brief rest right now is the best choice to protect your long-term health.', zh: '今天，摩羯座所主管的膝盖和关节可能承受意想不到的压力。今天就避免激烈运动，改以拉伸或轻度步行代替。强撑只会需要更长的恢复时间，现在短暂休息是守护长期健康的最佳选择。', ja: '今日摩羯座が管轄する膝や関節に予想外の負担がかかる可能性があります。激しい運動は今日だけは控えてストレッチや軽い歩きに切り替えてください。無理すると回復に長い時間が必要になり、今少し休むことが長期的な健康を守る最善の選択です。', es: 'Hoy puede venir una tension inesperada a las rodillas y articulaciones gobernadas por Capricornio. Solo por hoy, evita el ejercicio intenso y reemplazalo con estiramientos o caminata ligera. Forzar requerira un tiempo de recuperacion mas largo, y un breve descanso ahora mismo es la mejor eleccion para proteger tu salud a largo plazo.' },
      { ko: '오늘 쌓인 스트레스가 피부 트러블로 나타날 수 있습니다. 피부 문제는 신호입니다—외부 케어보다 먼저 내면의 안정을 찾는 것이 진짜 해결책입니다. 짧은 명상, 깊은 호흡, 또는 좋아하는 음악 듣기처럼 당신만의 내면 안정 루틴을 오늘 실천해보세요.', en: 'Accumulated stress today may manifest as skin troubles. Skin issues are signals—finding inner calm before external skincare is the real solution. Practice your own inner-calming routine today, whether it is short meditation, deep breathing, or listening to music you love.', zh: '今天积累的压力可能以皮肤问题的形式出现。皮肤问题是信号——在外部护理之前先找到内心的平静，才是真正的解决之道。今天实践你自己的内心安定例程，无论是短暂的冥想、深呼吸，还是聆听你喜欢的音乐。', ja: '今日蓄積されたストレスが肌トラブルとして現れる可能性があります。肌の問題はサインです。外部ケアより先に内面の安定を見つけることが本当の解決策です。短い瞑想、深呼吸、または好きな音楽を聴くなどあなただけの内面安定ルーティンを今日実践してみてください。', es: 'El estres acumulado hoy puede manifestarse como problemas de piel. Los problemas de piel son senales—encontrar la calma interior antes del cuidado externo de la piel es la solucion real. Practica tu propia rutina calmante interior hoy, ya sea meditacion corta, respiracion profunda o escuchar musica que amas.' },
      { ko: '업무에 집중하다 보면 식사를 거르는 것이 생산성이라 착각하기 쉽지만, 그것은 오히려 이후의 집중력과 에너지를 무너뜨립니다. 오늘 식사를 거르고 있지는 않은지 스스로 점검해보세요. 제때 먹는 것이 가장 간단하고 효과적인 자기 관리입니다.', en: 'It is easy to mistake skipping meals for productivity when focusing on work, but it actually destroys subsequent concentration and energy. Check today whether you are skipping meals. Eating on time is the simplest and most effective form of self-care.', zh: '专注工作时很容易把不吃饭误认为是高效率，但这实际上会破坏之后的专注力和能量。今天检查一下自己是否跳过了用餐。按时吃饭，是最简单也最有效的自我管理。', ja: '仕事に集中するあまり食事を抜くことを生産性だと錯覚しやすいですが、それはむしろその後の集中力とエネルギーを崩します。今日食事を抜いていないか自分で点検してみてください。時間通りに食べることが最もシンプルで効果的な自己管理です。', es: 'Es facil confundir saltarse comidas con productividad cuando te enfocas en el trabajo, pero en realidad destruye la concentracion y energia subsiguientes. Comprueba hoy si estas saltandote comidas. Comer a tiempo es la forma mas simple y efectiva de autocuidado.' },
      { ko: '오늘 수면 부족의 누적이 당신의 판단력과 체력 모두를 눈에 띄게 떨어뜨리고 있습니다. 밤 늦게까지 일하는 것이 성실함처럼 보여도, 충분히 자지 않은 뇌는 결코 최상의 성과를 낼 수 없습니다. 오늘 밤만큼은 반드시 7시간 이상의 수면을 확보하세요.', en: 'The accumulation of sleep deprivation is visibly lowering both your judgment and stamina today. Working late may look like diligence, but a brain that hasn\'t slept enough can never produce its best results. At least tonight, make sure to secure 7 or more hours of sleep.', zh: '睡眠不足的积累，今天正在明显降低你的判断力和体力。深夜加班看似勤勉，但睡眠不足的大脑永远无法发挥最佳水平。至少今晚，务必保证7小时以上的睡眠。', ja: '今日睡眠不足の蓄積があなたの判断力と体力の両方を目に見えて下げています。夜遅くまで働くことが誠実さに見えても、十分に寝ていない脳は決して最高の成果を出せません。今夜だけでも必ず7時間以上の睡眠を確保してください。', es: 'La acumulacion de falta de sueno esta bajando visiblemente tanto tu juicio como tu resistencia hoy. Trabajar hasta tarde puede parecer diligencia, pero un cerebro que no ha dormido suficiente nunca puede producir sus mejores resultados. Al menos esta noche, asegurate de dormir 7 o mas horas.' },
      { ko: '오늘 허리 통증이나 자세 불량에 각별히 주의해야 합니다. 지금 당신의 데스크 환경을 점검하고 모니터 높이, 의자 높이, 등받이 지지대를 조정해보세요. 장시간 같은 자세로 앉아있는 것이 만성 통증의 가장 큰 원인이며, 작은 환경 변화가 큰 차이를 만듭니다.', en: 'Today you must pay particular attention to back pain or poor posture. Check your desk setup right now and adjust your monitor height, chair height, and back support. Sitting in the same position for long periods is the biggest cause of chronic pain, and small environmental changes make a big difference.', zh: '今天需要格外注意腰痛和不良姿势。现在检查一下你的桌面环境，调整显示器高度、椅子高度和背部支撑。长时间保持同一姿势是慢性疼痛的最大原因，小小的环境改变能带来巨大差异。', ja: '今日は腰痛や姿勢不良に特別に注意が必要です。今すぐデスク環境を点検してモニターの高さ、椅子の高さ、背もたれのサポートを調整してみてください。長時間同じ姿勢で座ることが慢性痛の最大の原因であり、小さな環境変化が大きな違いを生みます。', es: 'Hoy debes prestar especial atencion al dolor de espalda o la mala postura. Revisa tu configuracion de escritorio ahora mismo y ajusta la altura del monitor, la altura de la silla y el soporte de la espalda. Sentarse en la misma posicion durante largos periodos es la mayor causa de dolor cronico, y pequenos cambios ambientales hacen una gran diferencia.' },
      { ko: '오랫동안 억눌러 온 감정이 오늘 신체 증상으로 나타날 수 있습니다. 몸과 마음은 연결되어 있으며, 마음의 짐을 풀어놓지 않으면 몸이 대신 그것을 짊어집니다. 오늘 일기 쓰기, 운동, 신뢰하는 사람과의 대화처럼 감정을 안전하게 표현할 방법을 찾아보세요.', en: 'Emotions long suppressed may manifest as physical symptoms today. Body and mind are connected, and when emotional burdens are not released, the body carries them instead. Today find a safe way to express emotions, whether through journaling, exercise, or conversation with someone you trust.', zh: '长期压抑的情绪今天可能以身体症状的形式出现。身心是相连的，情绪的重担若不得释放，身体便会代为承担。今天寻找一种安全表达情绪的方式，无论是写日记、运动，还是与信任的人交谈。', ja: '長い間抑え込んできた感情が今日身体症状として現れる可能性があります。体と心は繋がっており、心の荷物を下ろさなければ体が代わりにそれを担います。今日は日記を書く、運動する、信頼できる人との会話など感情を安全に表現する方法を探してみてください。', es: 'Las emociones suprimidas por mucho tiempo pueden manifestarse como sintomas fisicos hoy. Cuerpo y mente estan conectados, y cuando las cargas emocionales no se liberan, el cuerpo las carga en su lugar. Hoy encuentra una forma segura de expresar emociones, ya sea escribiendo un diario, haciendo ejercicio o conversando con alguien de confianza.' },
      { ko: '미루어 왔던 건강 검진을 더 이상 미루지 마세요. 염소자리의 현실적인 사고방식으로 보면, 예방 비용은 치료 비용의 몇 분의 일에 불과하며 조기 발견이 삶의 질을 완전히 다르게 만들 수 있습니다. 오늘 바로 검진 예약을 잡아보세요—그것이 가장 현명한 자기 투자입니다.', en: 'No longer postpone the health checkup you have been putting off. With Capricorn\'s realistic thinking, prevention costs just a fraction of treatment costs, and early detection can make a completely different quality of life possible. Make the appointment today—it is the wisest self-investment you can make.', zh: '不要再推迟你一直搁置的健康检查了。以摩羯座现实的思维方式来看，预防的费用仅是治疗费用的几分之一，而早期发现可以使生活质量大相径庭。今天就预约检查吧——这是你能做的最明智的自我投资。', ja: '先延ばしにしてきた健康診断をこれ以上先延ばしにしないでください。摩羯座の現実的な思考方法で見ると、予防コストは治療コストのほんの一部であり早期発見が人生の質を完全に変えることができます。今日すぐ検診の予約を入れてみてください。', es: 'Ya no pospongas mas el chequeo medico que has estado aplazando. Con el pensamiento realista de Capricornio, los costos de prevencion son solo una fraccion de los costos de tratamiento, y la deteccion temprana puede hacer posible una calidad de vida completamente diferente. Haz la cita hoy—es la inversion propia mas sabia que puedes hacer.' },
      { ko: '오늘 치아와 잇몸 건강에 적신호가 올 수 있으니 각별히 주의하세요. 스트레스가 이갈이나 잇몸 질환으로 이어지는 경우가 많으므로, 오늘 구강 위생을 평소보다 더 철저히 관리하고 필요하다면 치과 상담을 예약하세요. 작은 징후를 초기에 잡는 것이 현명한 염소자리의 선택입니다.', en: 'Warning signs may come for teeth and gum health today, so pay particular attention. Stress often leads to teeth grinding or gum disease, so manage your oral hygiene more thoroughly than usual today, and book a dental consultation if necessary. Catching small signs early is the wise Capricorn choice.', zh: '今天牙齿和牙龈健康可能亮起红灯，请格外注意。压力常常导致磨牙或牙龈疾病，因此今天要比平时更彻底地管理口腔卫生，必要时预约牙科咨询。早期发现小征兆，是明智的摩羯座的选择。', ja: '今日は歯と歯茎の健康に警告サインが出る可能性があるので特別に注意してください。ストレスが歯ぎしりや歯茎の疾患につながることが多いため、今日は口腔衛生を普段より徹底して管理し必要であれば歯科相談を予約してください。小さなサインを早期に捉えることが賢明な摩羯座の選択です。', es: 'Hoy pueden llegar senales de alerta para la salud dental, asi que presta especial atencion. El estres a menudo conduce al rechinar de dientes o enfermedad de las encias, asi que gestiona tu higiene oral mas a fondo de lo habitual hoy, y reserva una consulta dental si es necesario. Captar senales pequenas temprano es la sabia eleccion de Capricornio.' },
      { ko: '강철 같은 의지력이 염소자리의 자랑이지만, 오늘은 그 의지력만으로 버티는 데 명확한 한계가 보입니다. 쉬는 것은 포기가 아니라 더 강하게 다시 일어서기 위한 전략입니다. 오늘 몸과 마음이 요청하는 회복의 시간을 스스로에게 허락해주세요.', en: 'Iron willpower is Capricorn\'s pride, but today you can clearly see the limits of enduring on willpower alone. Resting is not giving up—it is a strategy for rising again even stronger. Today, give yourself permission to take the recovery time your body and mind are asking for.', zh: '钢铁意志是摩羯座的骄傲，但今天，仅凭意志力坚持的明确极限已经显现。休息不是放弃，而是为了更强大地重新站起来的战略。今天，允许自己享有身心所需求的恢复时间吧。', ja: '鋼鉄のような意志力が摩羯座の誇りですが、今日はその意志力だけで耐えることの明確な限界が見えています。休むことはあきらめではなく、より強くまた立ち上がるための戦略です。今日体と心が求めている回復の時間を自分に許してあげてください。', es: 'La voluntad de hierro es el orgullo de Capricornio, pero hoy puedes ver claramente los limites de aguantar solo con fuerza de voluntad. Descansar no es rendirse—es una estrategia para levantarse aun mas fuerte. Hoy, date permiso para tomar el tiempo de recuperacion que tu cuerpo y mente estan pidiendo.' },
    ],
  },
  money: {
    high: [
      { ko: '인내심을 갖고 꾸준히 유지해 온 절약과 투자의 결실이 드디어 눈에 보이기 시작하는 시기가 왔습니다. 복리의 마법이 당신의 통장에서 실제로 펼쳐지고 있으며, 이 흐름은 앞으로 더욱 가속화될 것입니다. 지금 이 방향을 더욱 강화하고 새로운 투자 목표를 설정해 보세요.', en: 'The time has finally come when the fruits of the saving and investment you have patiently and consistently maintained are starting to become visible. The magic of compound interest is literally unfolding in your account, and this momentum will accelerate even more going forward. Strengthen this direction further and set a new investment goal now.', zh: '你耐心且持续保持的节约与投资的成果，终于开始变得肉眼可见了。复利的魔力正在你的账户中真实展开，这股势头今后将进一步加速。现在进一步强化这个方向，并设定新的投资目标吧。', ja: '忍耐強く着実に維持してきた節約と投資の成果がついに目に見え始める時期が来ました。複利の魔法があなたの口座で実際に展開されており、この流れはこれからさらに加速するでしょう。今この方向をさらに強化し新しい投資目標を設定してみてください。', es: 'Finalmente ha llegado el momento en que los frutos del ahorro e inversion que has mantenido pacientemente y de manera constante comienzan a hacerse visibles. La magia del interes compuesto se esta desplegando literalmente en tu cuenta, y este impulso se acelerara aun mas en adelante. Fortalece aun mas esta direccion y establece una nueva meta de inversion ahora.' },
      { ko: '오늘 당신의 재정적 판단력이 최고조에 달해, 복잡한 재무 정보도 명료하게 분석하고 올바른 결론을 도출할 수 있습니다. 중요한 투자 결정을 내리기에 이보다 더 적합한 날은 없습니다. 충분한 분석과 함께 과감한 결정을 내려보세요—직관과 이성 모두가 같은 방향을 가리키고 있습니다.', en: 'Today your financial judgment peaks, allowing you to clearly analyze even complex financial information and draw correct conclusions. There is no better day for making important investment decisions. Make a bold decision backed by thorough analysis—both your intuition and reason are pointing in the same direction.', zh: '今天你的财务判断力达到顶峰，即使是复杂的财务信息也能清晰分析，得出正确结论。没有比今天更适合做出重要投资决策的日子了。在充分分析的基础上做出果断的决定吧——直觉和理性都指向同一个方向。', ja: '今日あなたの財政的な判断力が最高潮に達し、複雑な財務情報も明確に分析して正しい結論を導き出せます。重要な投資決定を下すにはこれ以上適した日はありません。十分な分析とともに大胆な決定を下してみてください。直感と理性の両方が同じ方向を指しています。', es: 'Hoy tu juicio financiero alcanza su punto maximo, permitiendote analizar claramente incluso informacion financiera compleja y sacar conclusiones correctas. No hay mejor dia para tomar decisiones de inversion importantes. Toma una decision audaz respaldada por un analisis exhaustivo—tanto tu intuicion como tu razon apuntan en la misma direccion.' },
      { ko: '오늘 부동산이나 실물 자산과 관련된 구체적인 기회가 찾아올 수 있습니다. 흙의 별자리인 염소자리는 손으로 만질 수 있는 실체적인 자산에서 안정감을 느끼며, 지금은 그 감각이 빛을 발하는 때입니다. 너무 서두르지 말고 충분히 검토한 후 결정을 내리세요.', en: 'Today a concrete opportunity related to real estate or tangible assets may arrive. Capricorn, an earth sign, finds stability in physical, touchable assets, and now is the time for that instinct to shine. Don\'t rush—review thoroughly and then make your decision.', zh: '今天，与房地产或实物资产相关的具体机会可能到来。作为土象星座的摩羯座，在可以用手触摸的实体资产中感到安心，而现在正是那种直觉发光的时候。不要太着急——充分审查后再做决定。', ja: '今日不動産や実物資産に関連した具体的な機会が訪れる可能性があります。大地の星座である摩羯座は手で触れられる実体的な資産に安定感を感じ、今はその感覚が光を放つ時です。急ぎすぎず十分に検討してから決定を下してください。', es: 'Hoy puede llegar una oportunidad concreta relacionada con bienes raices o activos tangibles. Capricornio, un signo de tierra, encuentra estabilidad en activos fisicos y tangibles, y ahora es el momento en que ese instinto brilla. No te apresures—revisa a fondo y luego toma tu decision.' },
      { ko: '매일 조금씩 꾸준히 이어온 저축 습관이 오늘 예상보다 훨씬 큰 자산으로 성장해 있음을 확인하게 됩니다. 이 결과가 복리의 힘과 당신의 규율이 만든 작품임을 잊지 마세요. 이 성공 경험을 바탕으로 더 큰 저축 목표와 투자 계획을 세워보세요.', en: 'Today you confirm that the steady saving habit you have maintained a little each day has grown into an asset far larger than expected. Remember that this result is the creation of compound interest\'s power and your discipline working together. Build larger saving goals and investment plans on the foundation of this success.', zh: '今天你将看到，每天坚持一点点的储蓄习惯，已成长为远超预期的资产。请记住，这个结果是复利的力量与你的规律共同创造的作品。以这次成功的经验为基础，制定更大的储蓄目标和投资计划吧。', ja: '毎日少しずつ着実に続けてきた貯蓄習慣が今日予想よりずっと大きな資産に成長していることを確認することになります。この結果が複利の力とあなたの規律が作り出した作品であることを忘れないでください。この成功体験をもとにより大きな貯蓄目標と投資計画を立ててみてください。', es: 'Hoy confirmas que el habito de ahorro constante que has mantenido un poco cada dia ha crecido hasta convertirse en un activo mucho mayor de lo esperado. Recuerda que este resultado es la creacion del poder del interes compuesto y tu disciplina trabajando juntos. Construye metas de ahorro mas grandes y planes de inversion sobre la base de este exito.' },
      { ko: '오늘 직장이나 사업에서 묵묵히 쌓아온 성과가 금전적인 형태의 보상으로 돌아오기 시작합니다. 이 보상은 당신이 마땅히 받아야 할 것이며, 당당하게 받아들이세요. 이 재정적 성취를 발판 삼아 다음 단계의 경제적 목표를 향해 나아갈 준비를 시작하세요.', en: 'Today the achievements you have quietly built at work or in business begin returning in the form of financial rewards. This reward is what you rightfully deserve—accept it with confidence. Use this financial achievement as a stepping stone to begin preparing for your next economic goal.', zh: '今天，你在职场或事业上默默积累的成果，开始以金钱奖励的形式回报给你。这份报酬是你理所应得的——坦然接受它吧。以这次财务成就为跳板，开始为下一阶段的经济目标做准备吧。', ja: '今日職場やビジネスで黙々と積み上げてきた成果が金銭的な形の報酬として返ってきます。この報酬はあなたが当然受けるべきものであり、堂々と受け取ってください。この財政的な達成を足がかりに次の段階の経済的目標に向けて準備を始めてください。', es: 'Hoy los logros que has construido silenciosamente en el trabajo o los negocios comienzan a regresar en forma de recompensas financieras. Esta recompensa es lo que mereces por derecho—acéptala con confianza. Usa este logro financiero como trampolines para comenzar a prepararte para tu proximo objetivo economico.' },
      { ko: '단기 수익에 현혹되지 않고 장기적 관점으로 꾸준히 유지해 온 재테크 전략이 지금 가장 빛을 발하는 시기입니다. 주변에서 빠른 수익을 자랑하더라도 흔들리지 마세요. 당신의 방식이 느린 것처럼 보여도, 시간이 지나면 당신이 가장 멀리 와 있을 것입니다.', en: 'The long-term investment strategy you have steadily maintained without being tempted by short-term profits is now shining most brightly. Even if others around you boast about quick gains, don\'t waver. Your approach may look slow, but given time, you will have come the furthest of all.', zh: '不被短期收益诱惑、坚持长期视角的理财策略，现在正大放异彩。即使周围有人炫耀快速收益，也不要动摇。你的方式看起来慢，但假以时日，你将走得最远。', ja: '短期的な収益に惑わされず長期的な観点で着実に維持してきた財テク戦略が今最も光を放つ時期です。周囲が早い収益を自慢しても揺らがないでください。あなたのやり方が遅く見えても時間が経てばあなたが最も遠くに来ているでしょう。', es: 'La estrategia de inversion a largo plazo que has mantenido consistentemente sin ser tentado por ganancias a corto plazo ahora brilla con mas intensidad. Incluso si otros a tu alrededor presumen de ganancias rapidas, no vaciles. Tu enfoque puede parecer lento, pero dado el tiempo, seras quien ha llegado mas lejos.' },
      { ko: '오늘 세우는 재정 계획은 구체성과 실행 가능성이 모두 갖춰져 있어 실현될 가능성이 매우 높습니다. 염소자리의 현실적인 계획 능력이 오늘 최대로 발휘되는 날이니, 단순한 소망이 아닌 단계별 실행 계획이 담긴 구체적인 재정 목표를 오늘 작성해 보세요.', en: 'Financial plans made today carry both specificity and feasibility, making them very likely to be realized. Capricorn\'s realistic planning ability is maximally expressed today, so write specific financial goals today that contain not just wishes but step-by-step action plans.', zh: '今天制定的财务计划兼具具体性和可操作性，实现可能性非常高。摩羯座现实的规划能力今天发挥到了极致，所以今天不只是写下愿望，而要写出包含分步骤执行计划的具体财务目标。', ja: '今日立てる財政計画は具体性と実行可能性の両方が揃っており実現される可能性が非常に高いです。摩羯座の現実的な計画能力が今日最大限に発揮される日なので、単なる願いではなくステップごとの実行計画が含まれた具体的な財政目標を今日書いてみてください。', es: 'Los planes financieros elaborados hoy llevan tanto especificidad como viabilidad, haciendolos muy propensos a realizarse. La capacidad de planificacion realista de Capricornio se expresa al maximo hoy, asi que escribe objetivos financieros especificos hoy que contengan no solo deseos sino planes de accion paso a paso.' },
      { ko: '오늘 오랜 신뢰 관계를 바탕으로 한 거래에서 기대 이상의 좋은 조건과 합의를 이끌어낼 수 있습니다. 염소자리가 쌓아온 신뢰 자본이 오늘 실질적인 금전적 이득으로 전환되는 날입니다. 협상에 자신 있게 임하고 당신의 가치를 명확히 제시하세요.', en: 'Today, in dealings built on long-term trust relationships, you can draw out favorable conditions and agreements beyond expectations. Today is the day Capricorn\'s accumulated trust capital converts into real financial gain. Approach negotiations with confidence and clearly present your value.', zh: '今天，在长期信任关系基础上的交易中，你能争取到超出预期的良好条件和共识。摩羯座积累的信任资本今天转化为实质性金融收益。自信地参与谈判，清晰地展示你的价值吧。', ja: '今日長い信頼関係を基盤とした取引で期待以上の良い条件と合意を引き出すことができます。摩羯座が積み上げてきた信頼の資本が今日実質的な金銭的利益に転換する日です。交渉に自信を持って臨み、あなたの価値を明確に提示してください。', es: 'Hoy, en tratos construidos sobre relaciones de confianza de largo plazo, puedes extraer condiciones y acuerdos favorables mas alla de las expectativas. Hoy es el dia en que el capital de confianza acumulado de Capricornio se convierte en ganancia financiera real. Aborda las negociaciones con confianza y presenta claramente tu valor.' },
      { ko: '충동을 다스리고 불필요한 지출을 꾸준히 줄여온 당신의 노력이 오늘 통장 잔고의 숫자로 명확히 증명됩니다. 이 숫자는 단순한 돈이 아니라 당신의 자기 규율과 미래를 위한 헌신의 증거입니다. 이 성과를 충분히 음미하고 다음 재정 목표를 향해 나아가세요.', en: 'The effort you have put into controlling impulses and consistently reducing unnecessary spending is clearly proven today by the number in your bank account. This number is not just money—it is evidence of your self-discipline and dedication to your future. Savor this achievement fully and move toward your next financial goal.', zh: '你控制冲动、持续减少不必要支出的努力，今天通过账户余额的数字清晰地得到了证明。这个数字不只是钱——它是你自我规律和为未来奉献的证明。充分品味这个成就，然后向下一个财务目标迈进吧。', ja: '衝動を抑えて不必要な支出を着実に減らしてきたあなたの努力が今日通帳残高の数字で明確に証明されます。この数字は単なるお金ではなくあなたの自己規律と未来への献身の証拠です。この成果を十分に味わい次の財政目標に向けて進んでください。', es: 'El esfuerzo que has puesto en controlar los impulsos y reducir consistentemente el gasto innecesario se prueba claramente hoy por el numero en tu cuenta bancaria. Este numero no es solo dinero—es evidencia de tu autodisciplina y dedicacion a tu futuro. Saborea plenamente este logro y avanza hacia tu proximo objetivo financiero.' },
      { ko: '오늘 현재 수입원에 더해 또 하나의 안정적인 수입원이 추가될 가능성이 있습니다. 부업, 임대 수익, 배당금, 프리랜서 기회 등 다양한 방면에서 눈을 크게 뜨고 기회를 살피세요. 다수의 수입원을 가지는 것이 진정한 재정적 안정을 만드는 염소자리의 방식입니다.', en: 'Today there is a possibility of an additional stable income source beyond your current one. Keep your eyes wide open and watch for opportunities in various areas—side work, rental income, dividends, or freelance opportunities. Having multiple income sources is the Capricorn way of building true financial stability.', zh: '今天，在现有收入来源之外，还有可能增加一个新的稳定收入来源。在副业、租金收入、股息、自由职业等各个方面睁大眼睛，留意机会。拥有多个收入来源，是摩羯座建立真正财务稳定的方式。', ja: '今日現在の収入源に加えてもう一つの安定した収入源が追加される可能性があります。副業、賃貸収入、配当金、フリーランスの機会などさまざまな方面で目を大きく開いて機会を見極めてください。複数の収入源を持つことが真の財政的安定を作る摩羯座のやり方です。', es: 'Hoy hay una posibilidad de una fuente de ingresos estable adicional mas alla de tu fuente actual. Mantén los ojos bien abiertos y busca oportunidades en varias areas—trabajo paralelo, ingresos de alquiler, dividendos u oportunidades freelance. Tener multiples fuentes de ingresos es la forma de Capricornio de construir verdadera estabilidad financiera.' },
    ],
    medium: [
      { ko: '오늘은 현재의 재정 상태를 꼼꼼하게 점검하고 변화된 환경에 맞게 예산을 재조정하기에 최적의 시기입니다. 숫자를 직접 마주하는 것이 불편하더라도, 현실을 정확히 파악하는 것이 재정 건강의 시작입니다. 오늘 한 시간을 투자해 재정 현황을 정리해보세요.', en: 'Today is the optimal time to carefully examine your current financial status and readjust your budget to match changed circumstances. Even if facing numbers directly is uncomfortable, accurately grasping reality is the beginning of financial health. Invest one hour today to organize your financial situation.', zh: '今天是仔细检查当前财务状况、根据变化调整预算的最佳时机。即使直面数字让你感到不舒服，准确把握现实也是财务健康的起点。今天投入一小时来整理你的财务状况吧。', ja: '今日は現在の財政状態を丁寧に点検し変化した環境に合わせて予算を再調整するのに最適な時期です。数字を直接向き合うことが不快でも現実を正確に把握することが財政的健康の始まりです。今日一時間を投資して財政状況を整理してみてください。', es: 'Hoy es el momento optimo para examinar cuidadosamente tu estado financiero actual y reajustar tu presupuesto para que coincida con las circunstancias cambiadas. Aunque enfrentar numeros directamente puede ser incomodo, captar la realidad con precision es el comienzo de la salud financiera. Invierte una hora hoy para organizar tu situacion financiera.' },
      { ko: '대단한 투자 결정이나 큰 변화 없이도 작은 절약들이 쌓여 만들어내는 차이가 오늘 실감 나게 느껴집니다. 가계부를 기록하는 작은 습관이 지출 패턴을 명확히 보여주고 절약의 기회를 자연스럽게 발견하게 합니다. 오늘부터 가계부를 시작해보는 것은 어떨까요.', en: 'Without any major investment decisions or big changes, the difference that small savings accumulate makes itself felt concretely today. The small habit of keeping a household ledger clearly shows your spending patterns and naturally helps you discover saving opportunities. Why not start keeping a ledger today.', zh: '不需要重大投资决策或大的改变，小节约积累起来的差异今天真实地让你感受到了。记账这个小习惯，能清晰展现你的支出模式，自然而然地帮你发现节约的机会。今天就开始记账怎么样？', ja: '大きな投資決定や大きな変化なしでも小さな節約が積み重なって生み出す違いが今日実感を持って感じられます。家計簿を記録する小さな習慣が支出パターンを明確に示し節約の機会を自然に発見させます。今日から家計簿を始めてみてはどうでしょう。', es: 'Sin ninguna decision de inversion importante ni grandes cambios, la diferencia que acumulan los pequenos ahorros se siente concretamente hoy. El pequeno habito de llevar un libro de gastos del hogar muestra claramente tus patrones de gasto y naturalmente te ayuda a descubrir oportunidades de ahorro. Por que no empezar a llevar un registro hoy.' },
      { ko: '오늘 원하는 것을 사고 싶은 충동이 예상보다 강하게 올라올 수 있습니다. 구매 전 잠깐 멈추고 이것이 진짜 필요한 것인지 단순히 원하는 것인지 자문해보세요. 염소자리의 현실적 분별력이 오늘 지갑을 지키는 가장 강력한 방패가 됩니다.', en: 'Today the urge to buy what you want may arise more strongly than expected. Before purchasing, pause briefly and ask yourself whether this is something you truly need or simply want. Capricorn\'s realistic discernment is the most powerful shield protecting your wallet today.', zh: '今天，想要购买某样东西的冲动可能比预期来得更强烈。在购买之前，暂停一下，问问自己这是真正需要的，还是只是想要的。摩羯座现实的分辨力今天是保护你钱包最有力的盾牌。', ja: '今日欲しいものを買いたい衝動が予想より強く上がってくる可能性があります。購入前に少し立ち止まり、これが本当に必要なものなのか単に欲しいものなのかを自問してみてください。摩羯座の現実的な分別力が今日財布を守る最も強力な盾になります。', es: 'Hoy el impulso de comprar lo que quieres puede surgir con mas fuerza de lo esperado. Antes de comprar, haz una breve pausa y preguntate si esto es algo que realmente necesitas o simplemente deseas. El discernimiento realista de Capricornio es el escudo mas poderoso que protege tu billetera hoy.' },
      { ko: '오늘은 장기적인 저축 계획을 새로 세우거나 기존 계획을 현실에 맞게 보완하기에 좋은 날입니다. 5년, 10년 후의 재정 목표를 구체적으로 그려보고 그것을 위한 월별 저축 금액을 계산해보세요. 작은 숫자도 장기 복리로 커질 수 있음을 기억하세요.', en: 'Today is a good day to establish a new long-term savings plan or supplement your existing plan to match reality. Specifically picture your financial goals 5 or 10 years from now and calculate the monthly savings amount needed to achieve them. Remember that even small amounts can grow large through long-term compounding.', zh: '今天是制定新的长期储蓄计划，或根据实际情况完善现有计划的好日子。具体地描绘5年、10年后的财务目标，并计算为此每月需要储蓄的金额。记住，即使是小数字，通过长期复利也能不断增长。', ja: '今日は長期的な貯蓄計画を新たに立てるか既存の計画を現実に合わせて補完するのに良い日です。5年、10年後の財政目標を具体的に描いてそのための毎月の貯蓄額を計算してみてください。小さな数字も長期複利で大きくなれることを覚えておいてください。', es: 'Hoy es un buen dia para establecer un nuevo plan de ahorro a largo plazo o complementar tu plan existente para que coincida con la realidad. Imagina especificamente tus metas financieras a 5 o 10 anos y calcula el monto de ahorro mensual necesario para lograrlas. Recuerda que incluso cantidades pequenas pueden crecer a traves del interes compuesto a largo plazo.' },
      { ko: '오늘은 새로운 수익 창출보다 현재의 안정적인 수입 흐름을 지속적으로 유지하는 것에 더 집중해야 할 시기입니다. 무리하게 사업을 확장하거나 위험을 감수하기보다는 이미 작동하는 것들을 더욱 견고히 하는 것이 현명합니다. 안정이 다음 성장의 토대가 됩니다.', en: 'Today you should focus more on continuously maintaining your current stable income flow than on generating new revenue. Rather than recklessly expanding your business or taking on risks, it is wiser to solidify what is already working. Stability becomes the foundation for the next growth.', zh: '今天，比起创造新收益，更应该专注于持续维持当前稳定的收入流。与其鲁莽地扩张业务或承担风险，不如巩固已经有效运转的东西更为明智。稳定是下一次增长的基础。', ja: '今日は新たな収益創出より現在の安定した収入の流れを継続的に維持することにより集中すべき時期です。無理に事業を拡張したりリスクを負うよりすでに機能しているものをさらに堅固にすることが賢明です。安定が次の成長の土台になります。', es: 'Hoy debes enfocarte mas en mantener continuamente tu flujo de ingresos estable actual que en generar nuevos ingresos. En lugar de expandir imprudentemente tu negocio o asumir riesgos, es mas sabio solidificar lo que ya funciona. La estabilidad se convierte en la base del siguiente crecimiento.' },
      { ko: '오늘은 보험이나 연금처럼 미래를 위한 재정 상품들을 꼼꼼하게 점검하기 좋은 날입니다. 가입한 상품이 현재 삶의 상황에 여전히 적합한지 확인하고, 변경이나 추가가 필요한지 살펴보세요. 미래를 체계적으로 대비하는 것이 염소자리다운 가장 현명한 재정 전략입니다.', en: 'Today is a good day to carefully review financial products for the future like insurance or pensions. Check whether the products you have joined are still appropriate for your current life situation, and see if any changes or additions are needed. Systematically preparing for the future is the most Capricorn-like and wisest financial strategy.', zh: '今天是仔细检查保险或养老金等未来财务产品的好日子。确认已加入的产品是否仍适合当前生活状况，看看是否需要更改或新增。系统性地为未来做好准备，是最符合摩羯座风格、最明智的财务战略。', ja: '今日は保険や年金のような未来のための金融商品を丁寧に点検するのに良い日です。加入した商品が現在の生活状況にまだ適切かどうか確認し、変更や追加が必要かどうか確認してください。未来を体系的に備えることが摩羯座らしい最も賢明な財政戦略です。', es: 'Hoy es un buen dia para revisar cuidadosamente productos financieros para el futuro como seguros o pensiones. Comprueba si los productos a los que estas suscrito siguen siendo apropiados para tu situacion de vida actual, y mira si se necesitan cambios o adiciones. Prepararse sistematicamente para el futuro es la estrategia financiera mas al estilo Capricornio y mas sabia.' },
      { ko: '단순한 가성비보다 오래 사용할 수 있는 내구성을 기준으로 소비하는 것이 장기적으로 훨씬 더 이득이 된다는 것을 오늘 다시 한번 확인하게 됩니다. 싸게 사서 자주 바꾸는 것보다 한 번 제대로 사서 오래 쓰는 것이 염소자리의 지혜입니다. 오늘 소비 결정에 내구성을 기준으로 적용해보세요.', en: 'Today you are reminded once again that spending based on durability that lasts a long time, rather than simple cost-effectiveness, pays off far more in the long run. Buying properly once and using it for a long time is wiser than buying cheaply and replacing frequently—that is Capricorn wisdom. Apply durability as your criterion for spending decisions today.', zh: '今天你再次意识到，以能长期使用的耐用性而非单纯性价比为标准消费，从长远来看收益更大。买对一次、长期使用，比便宜买、频繁更换更明智——这就是摩羯座的智慧。今天把耐用性作为消费决定的标准来应用吧。', ja: '単なるコスパより長く使える耐久性を基準に消費することが長期的にずっとお得になることを今日改めて確認することになります。安く買って頻繁に替えるよりきちんと一度買って長く使うことが摩羯座の知恵です。今日の消費決定に耐久性を基準として適用してみてください。', es: 'Hoy te recuerdas una vez mas que gastar basado en la durabilidad que dura mucho tiempo, en lugar de la simple relacion calidad-precio, paga mucho mas a largo plazo. Comprar correctamente una vez y usarlo por mucho tiempo es mas sabio que comprar barato y reemplazar con frecuencia—esa es la sabiduria de Capricornio.' },
      { ko: '재테크 공부에 투자하는 시간이 앞으로 당신의 재정 인생을 완전히 다르게 만들 수 있습니다. 책 한 권, 팟캐스트 하나, 온라인 강의 하나에서 얻는 지식이 실제 재정 결정에 활용될 때 수십 배의 가치를 발휘합니다. 오늘 재테크 관련 콘텐츠에 30분을 투자해보세요.', en: 'The time you invest in financial education can completely change your financial life going forward. Knowledge gained from one book, one podcast, or one online lecture delivers value dozens of times over when applied to actual financial decisions. Invest 30 minutes in financial content today.', zh: '投入财务知识学习的时间，可以彻底改变你未来的财务人生。从一本书、一档播客或一堂在线课程中获取的知识，当被运用于实际财务决策时，能发挥数十倍的价值。今天投入30分钟在理财相关内容上吧。', ja: '財テクの勉強に投資する時間がこれからあなたの財政人生を完全に変えることができます。本一冊、ポッドキャスト一つ、オンライン講義一つから得る知識が実際の財政決定に活用される時に数十倍の価値を発揮します。今日財テク関連コンテンツに30分を投資してみてください。', es: 'El tiempo que inviertes en educacion financiera puede cambiar completamente tu vida financiera en adelante. El conocimiento obtenido de un libro, un podcast o una clase en linea ofrece valor decenas de veces mayor cuando se aplica a decisiones financieras reales. Invierte 30 minutos en contenido financiero hoy.' },
      { ko: '지인이나 친구와의 금전적 거래 요청이 있다면 오늘 특히 신중하게 판단하세요. 돈 문제는 아무리 가까운 관계도 흐트러뜨릴 수 있습니다. 관계가 먼저이며, 금전이 관계를 위협할 것 같다면 거절하는 용기도 필요합니다. 명확한 원칙을 세우고 그것을 지키세요.', en: 'If a request for financial dealings from an acquaintance or friend arises, be especially careful in your judgment today. Money matters can disrupt even the closest relationships. Relationships come first, and if money threatens to endanger the relationship, you also need the courage to refuse. Set clear principles and uphold them.', zh: '如果熟人或朋友提出金钱往来的请求，今天要格外慎重地判断。金钱问题可以动摇再亲密的关系。关系第一，如果金钱可能威胁到关系，也需要拒绝的勇气。设立清晰的原则并坚守它。', ja: '知人や友人との金銭的な取引の要請があれば今日特に慎重に判断してください。お金の問題はどんなに親しい関係も崩す可能性があります。関係が先であり金銭が関係を脅かしそうなら断る勇気も必要です。明確な原則を立てそれを守ってください。', es: 'Si surge una solicitud de tratos financieros de un conocido o amigo, se especialmente cuidadoso en tu juicio hoy. Los asuntos de dinero pueden perturbar incluso las relaciones mas cercanas. Las relaciones van primero, y si el dinero amenaza con poner en peligro la relacion, tambien necesitas el valor para negarte.' },
      { ko: '남들과 비교하거나 소셜 미디어의 화려함에 흔들리지 않고, 현재 수입에 맞는 생활 수준을 유지하면 내면의 평온함이 자연스럽게 따라옵니다. 과소비로 인한 재정적 스트레스야말로 행복을 가장 빠르게 갉아먹는 적입니다. 오늘 자신의 수준에 만족하는 연습을 해보세요.', en: 'Without comparing yourself to others or being shaken by the glamour of social media, maintaining a lifestyle that matches your current income naturally brings inner peace. Financial stress from overspending is the enemy that most quickly erodes happiness. Practice being content with your own level today.', zh: '不与他人比较，不被社交媒体的华丽所动摇，维持与当前收入相匹配的生活水平，内心的平静会自然而然地随之而来。过度消费带来的财务压力，是最快侵蚀幸福的敌人。今天练习对自己的现状感到满足吧。', ja: '他人と比較したりソーシャルメディアの華やかさに揺らがず、現在の収入に合った生活水準を維持すれば内面の平和が自然についてきます。過消費による財政的ストレスこそが幸福を最も早く蝕む敵です。今日自分のレベルに満足する練習をしてみてください。', es: 'Sin compararte con otros ni ser sacudido por el glamour de las redes sociales, mantener un estilo de vida que coincida con tus ingresos actuales trae naturalmente paz interior. El estres financiero del gasto excesivo es el enemigo que mas rapidamente erosiona la felicidad. Practica estar contento con tu propio nivel hoy.' },
    ],
    low: [
      { ko: '오늘 예상치 못한 지출이 발생할 가능성이 있습니다. 먼저 비상금이 얼마나 준비되어 있는지 확인하고, 당장 사용하지 않아도 되는 지출은 최대한 미루거나 줄이세요. 예상치 못한 상황을 위한 재정 완충재가 있다는 사실이 당신에게 침착함을 유지하게 해줄 것입니다.', en: 'There is a possibility of unexpected expenses arising today. First check how much emergency fund you have prepared, and as much as possible postpone or reduce spending that does not need to happen immediately. Knowing that you have a financial buffer for unexpected situations will help you maintain composure.', zh: '今天有可能发生意想不到的支出。首先确认应急资金准备了多少，并尽量推迟或减少暂时不需要发生的支出。知道自己有应对意外情况的财务缓冲，将帮助你保持冷静。', ja: '今日予想外の支出が発生する可能性があります。まず非常資金がどれくらい準備されているか確認し、すぐに使わなくてもよい支出はできる限り先延ばしにするか減らしてください。予想外の状況のための財政的緩衝材があるという事実があなたを落ち着いた状態に保ちます。', es: 'Hoy hay una posibilidad de que surjan gastos inesperados. Primero verifica cuanto fondo de emergencia tienes preparado, y tanto como sea posible pospone o reduce el gasto que no necesita ocurrir de inmediato. Saber que tienes un colchon financiero para situaciones inesperadas te ayudara a mantener la compostura.' },
      { ko: '오늘 투자 관련 결정에서 조급함은 절대 금물입니다. 빠른 수익을 쫓다 더 큰 손실을 입는 것이 가장 흔한 투자 실수이며, 오늘은 그 위험이 특히 높은 날입니다. 손실을 최소화하는 보수적인 접근이 수익을 극대화하려는 시도보다 훨씬 현명한 선택입니다.', en: 'Impatience in investment-related decisions today is absolutely forbidden. Chasing quick profits and incurring greater losses is the most common investment mistake, and today is a day when that risk is particularly high. A conservative approach that minimizes losses is a far wiser choice than attempting to maximize gains.', zh: '今天在投资相关决策中，急躁绝对是大忌。追求快速收益而遭受更大损失，是最常见的投资错误，而今天这种风险尤其高。最大限度减少损失的保守做法，远比试图最大化收益的尝试更明智。', ja: '今日投資関連の決定で焦りは絶対禁物です。早い収益を追って大きな損失を被ることが最もよくある投資ミスであり、今日はその危険が特に高い日です。損失を最小限にする保守的なアプローチが収益を最大化しようとする試みよりずっと賢明な選択です。', es: 'La impaciencia en las decisiones relacionadas con la inversion hoy esta absolutamente prohibida. Perseguir ganancias rapidas e incurrir en mayores perdidas es el error de inversion mas comun, y hoy es un dia en que ese riesgo es particularmente alto. Un enfoque conservador que minimiza las perdidas es una eleccion mucho mas sabia que intentar maximizar las ganancias.' },
      { ko: '오늘 보증이나 대출과 관련된 결정이 필요하다면 절대 서두르지 마세요. 단기적 유혹이나 압박에 굴하지 않고 충분한 시간을 갖고 꼼꼼히 검토한 후에만 결정을 내리세요. 염소자리의 신중함이 오늘 당신의 재정을 지키는 가장 중요한 무기입니다.', en: 'If a decision related to guarantees or loans is needed today, absolutely do not rush. Don\'t yield to short-term temptation or pressure—take sufficient time and make a decision only after thorough examination. Capricorn\'s caution is the most important weapon protecting your finances today.', zh: '如果今天需要做出与担保或贷款相关的决定，绝对不要着急。不要屈服于短期诱惑或压力——留出充足时间，仔细审查后再做决定。摩羯座的谨慎，是今天保护你财务的最重要武器。', ja: '今日保証やローンに関連した決定が必要であれば絶対に急がないでください。短期的な誘惑や圧力に屈せず十分な時間を取り十分に検討した後にのみ決定を下してください。摩羯座の慎重さが今日あなたの財政を守る最も重要な武器です。', es: 'Si hoy se necesita una decision relacionada con garantias o prestamos, absolutamente no te apresures. No cedas a la tentacion o presion a corto plazo—toma tiempo suficiente y toma una decision solo despues de un examen exhaustivo. La cautela de Capricornio es el arma mas importante que protege tus finanzas hoy.' },
      { ko: '극단적으로 절약하는 것이 미덕처럼 느껴질 수 있지만, 과도한 절약은 오히려 심리적 스트레스로 이어져 역효과를 낳을 수 있습니다. 재정 규율을 지키면서도 자신에게 적절한 보상을 허용하는 균형이 필요합니다. 지속 가능한 절약이 강요된 절약보다 훨씬 오래갑니다.', en: 'Extreme frugality may feel like a virtue, but excessive saving can actually backfire by leading to psychological stress. You need balance that allows appropriate rewards for yourself while maintaining financial discipline. Sustainable saving lasts far longer than forced saving.', zh: '极端节约可能感觉像美德，但过度节约反而可能导致心理压力，产生反效果。在保持财务规律的同时，也需要允许自己适当奖励的平衡。可持续的节约远比被迫的节约持续更久。', ja: '極端に節約することが美徳に感じられるかもしれませんが、過度な節約はかえって心理的ストレスに繋がり逆効果になる可能性があります。財政規律を守りながらも自分に適切なご褒美を許す均衡が必要です。持続可能な節約が強要された節約よりずっと長続きします。', es: 'La frugalidad extrema puede sentirse como una virtud, pero el ahorro excesivo puede en realidad tener el efecto contrario al provocar estres psicologico. Necesitas equilibrio que permita recompensas apropiadas para ti mismo mientras mantienes la disciplina financiera. El ahorro sostenible dura mucho mas que el ahorro forzado.' },
      { ko: '오늘 부동산이나 큰 규모의 자산 거래를 진행할 계획이 있다면, 시기를 다시 한번 신중하게 살펴보는 것이 현명합니다. 이 결정은 한번 내리면 되돌리기 어려운 종류이므로, 서두르지 말고 더 유리한 조건이나 시점을 기다리는 인내심이 오늘 가장 가치 있는 자산입니다.', en: 'If you have plans to proceed with real estate or large-scale asset transactions today, it is wise to carefully reconsider the timing once more. Since this type of decision is difficult to reverse once made, patience to wait for more favorable conditions or timing without rushing is your most valuable asset today.', zh: '如果今天计划进行房地产或大规模资产交易，最好再谨慎地重新审视一下时机。这类决定一旦做出就很难撤回，因此不急于求成，等待更有利的条件或时机的耐心，是今天最有价值的资产。', ja: '今日不動産や大規模な資産取引を進める計画があれば、時期をもう一度慎重に検討することが賢明です。この決定は一度下すと取り消しにくい種類なので、急がず有利な条件や時点を待つ忍耐心が今日最も価値ある資産です。', es: 'Si tienes planes de proceder con transacciones inmobiliarias o de activos a gran escala hoy, es sabio reconsiderar cuidadosamente el momento una vez mas. Dado que este tipo de decision es dificil de revertir una vez tomada, la paciencia de esperar condiciones o momentos mas favorables sin apresurarse es tu activo mas valioso hoy.' },
      { ko: '오늘 주변에서 달콤하게 들리는 투자 조언이 찾아올 수 있습니다. 아무리 신뢰하는 사람의 말이라도 맹신하지 말고, 반드시 자신만의 기준으로 냉철하게 검증하세요. 염소자리의 독립적인 판단력이 오늘 당신의 재산을 지키는 가장 강력한 방패입니다.', en: 'Tempting investment advice may reach you from those around you today. Even from someone you trust, don\'t believe blindly—be sure to verify it coldly and objectively with your own criteria. Capricorn\'s independent judgment is the most powerful shield protecting your wealth today.', zh: '今天可能会有听起来甜蜜的投资建议找上门来。不管是多么信任的人说的话，也不要盲目相信——一定要用自己的标准冷静地加以验证。摩羯座的独立判断力，是今天保护你财富最有力的盾牌。', ja: '今日周囲からおいしそうに聞こえる投資アドバイスが来る可能性があります。いくら信頼する人の言葉でも盲信せず、必ず自分だけの基準で冷静に検証してください。摩羯座の独立した判断力が今日あなたの財産を守る最も強力な盾です。', es: 'Hoy pueden llegar consejos de inversion tentadores de quienes te rodean. Incluso de alguien en quien confias, no lo creas ciegamente—asegurate de verificarlo fria y objetivamente con tus propios criterios. El juicio independiente de Capricornio es el escudo mas poderoso que protege tu riqueza hoy.' },
      { ko: '금전적 불안감이 크게 느껴지더라도, 그 불안의 대부분은 실제 수치가 아닌 머릿속 걱정에서 비롯되는 경우가 많습니다. 오늘 통장 잔고, 지출 내역, 고정비를 직접 확인해보세요—숫자를 마주하면 불안은 오히려 줄어드는 경우가 대부분입니다. 현실을 직시하는 용기가 염소자리의 가장 강력한 재정 치유제입니다.', en: 'When financial anxiety feels overwhelming, most of it often stems from worries in your head rather than the actual numbers. Today, directly check your account balance, expense records, and fixed costs—facing the numbers actually reduces anxiety in most cases. The courage to look reality in the eye is Capricorn\'s most powerful financial remedy.', zh: '即使金融焦虑感很强烈，其中大部分往往来自脑海中的担忧，而非实际数字。今天，直接查看你的账户余额、支出记录和固定费用——面对数字，焦虑反而通常会减少。直视现实的勇气是摩羯座最强大的财务疗愈剂。', ja: '金銭的な不安感が大きく感じられても、その不安の多くは実際の数字ではなく頭の中の心配から来ることが多いです。今日口座残高、支出記録、固定費を直接確認してみてください—数字を直視すると不安はかえって減ることがほとんどです。現実を直視する勇気が摩羯座の最も強力な財政的治癒薬です。', es: 'Cuando la ansiedad financiera se siente abrumadora, la mayor parte a menudo proviene de preocupaciones en tu cabeza en lugar de los numeros reales. Hoy verifica directamente tu saldo de cuenta, registros de gastos y costos fijos—enfrentar los numeros en realidad reduce la ansiedad en la mayoria de los casos. El valor de mirar la realidad de frente es el remedio financiero mas poderoso de Capricornio.' },
      { ko: '오늘 더 많이, 더 빨리 갖고 싶다는 물질적 욕심이 평소보다 강하게 작동할 수 있으며, 이것이 판단력을 흐리게 만들 위험이 있습니다. 염소자리는 원래 욕심이 아닌 계획으로 부를 쌓는 별자리임을 기억하세요. 오늘은 원점으로 돌아가—지금 당신에게 진짜 필요한 것이 무엇인지 냉정하게 재고해보세요.', en: 'Today the material desire to have more and faster may operate more strongly than usual, putting you at risk of clouding your judgment. Remember that Capricorn is a sign that builds wealth through planning, not greed. Return to the starting point today—reconsider coldly and clearly what you truly need right now.', zh: '今天，想要更多、更快得到的物质欲望可能比平时更强烈，这有模糊判断力的危险。记住，摩羯座本来是靠计划而非贪欲积累财富的星座。今天回到原点——冷静地重新思考你现在真正需要的是什么。', ja: '今日もっと多く、もっと早く持ちたいという物質的な欲求が普段より強く働く可能性があり、これが判断力を曇らせる危険があります。摩羯座はもともと欲ではなく計画で富を築く星座であることを覚えておいてください。今日は原点に戻って—今あなたに本当に必要なものが何かを冷静に再考してみてください。', es: 'Hoy el deseo material de tener mas y mas rapido puede operar con mas fuerza de lo usual, poniendo en riesgo de nublar tu juicio. Recuerda que Capricornio es un signo que construye riqueza a traves de la planificacion, no de la codicia. Vuelve al punto de partida hoy—reconsidera fria y claramente que es lo que realmente necesitas ahora mismo.' },
      { ko: '카드를 자주 사용하면 지출이 눈에 잘 보이지 않아 무감각해지기 쉽고, 오늘은 그 위험이 특히 높은 날입니다. 가능하다면 오늘 하루만이라도 현금이나 계좌 이체를 활용해 지출할 때마다 직접 느끼는 연습을 해보세요. 돈의 흐름을 몸으로 인식하는 것이 가장 강력한 절약 훈련입니다.', en: 'Frequent card usage makes spending harder to see and easy to become numb to, and today is a day when that risk is particularly high. If possible, try using cash or bank transfers for even just today—so you feel each expense directly as it happens. Physically sensing the flow of money is the most powerful frugality training.', zh: '频繁使用信用卡会让支出不那么明显，容易变得麻木，而今天这种风险尤其高。如果可能的话，哪怕只是今天，也尝试使用现金或银行转账，每次消费时都直接感受一下。用身体感知金钱的流动，是最强大的节约训练。', ja: 'カードを頻繁に使うと支出が見えにくくなって無感覚になりやすく、今日はその危険が特に高い日です。できれば今日一日だけでも現金や口座振替を活用して支出するたびに直接感じる練習をしてみてください。お金の流れを体で認識することが最も強力な節約訓練です。', es: 'El uso frecuente de tarjetas hace que el gasto sea mas dificil de ver y facil de insensibilizarse, y hoy es un dia en que ese riesgo es particularmente alto. Si es posible, intenta usar efectivo o transferencias bancarias aunque sea solo hoy—para sentir cada gasto directamente cuando ocurre. Sentir fisicamente el flujo del dinero es el entrenamiento de frugalidad mas poderoso.' },
      { ko: '염소자리는 혼자 해결해야 한다는 강한 자존심 때문에 재정 문제를 스스로 떠안으려 하지만, 그것이 오히려 문제를 더 키울 수 있습니다. 세무사, 재무 상담사, 혹은 신뢰할 수 있는 재정 경험자에게 도움을 구하는 것은 약함이 아니라 문제를 가장 빠르게 해결하는 현명한 전략입니다. 오늘 전문가 상담을 예약하거나 연락하는 첫 걸음을 내디뎌보세요.', en: 'Capricorn\'s strong pride in solving things alone can lead to shouldering financial problems personally, but that can actually make problems grow larger. Seeking help from a tax accountant, financial advisor, or trusted person with financial experience is not weakness—it is the wisest strategy to resolve problems most quickly. Take the first step today by booking or reaching out for expert consultation.', zh: '摩羯座强烈的自尊心驱使其独自承担财务问题，但这反而可能让问题越来越大。向税务师、财务顾问或可信赖的有财务经验的人寻求帮助，不是软弱——而是最快解决问题的明智策略。今天迈出第一步，预约或联系专业咨询吧。', ja: '摩羯座は一人で解決しなければならないという強い自尊心から財政問題を自分で抱え込もうとしますが、それがかえって問題をより大きくする可能性があります。税理士、財務相談士、または信頼できる財政経験者に助けを求めることは弱さではなく問題を最も速く解決する賢明な戦略です。今日専門家への相談を予約したり連絡する最初の一歩を踏み出してみてください。', es: 'El fuerte orgullo de Capricornio en resolver las cosas solo puede llevar a cargar personalmente con problemas financieros, pero eso en realidad puede hacer que los problemas crezcan mas. Buscar ayuda de un contador fiscal, asesor financiero o persona de confianza con experiencia financiera no es debilidad—es la estrategia mas sabia para resolver problemas mas rapidamente. Da el primer paso hoy reservando o contactando para una consulta de expertos.' },
    ],
  },
};
